             class="breadcrumb-link">
            @if (item.icon) { <span [class]="item.icon"></span> }
            {{ item.label }}
          </a>
        } @else if (!item.routerLink && !last) {
          <a href="#"
             (click)="onClick(item, i, $event)"
             class="breadcrumb-link">
            @if (item.icon) { <span [class]="item.icon"></span> }
            {{ item.label }}
          </a>
        } @else {
          <span class="breadcrumb-text">
            @if (item.activeIcon) { <span [class]="item.activeIcon"></span> }
            {{ item.label }}
          </span>
        }

      </li>
    }
  </ol>
</nav>
  `,
  styles: [`
