import { Directive, ElementRef, Input, OnInit, OnDestroy, Renderer2, inject } from '@angular/core';
import { Subscription } from 'rxjs';
import { ApexDynamicActionService } from './dynamic-action.service';

@Directive({
  selector: '[apexDATarget]',
  standalone: true
})
export class ApexDynamicActionTargetDirective implements OnInit, OnDestroy {
  @Input('apexDATarget') targetId!: string;

  private el = inject(ElementRef);
  private renderer = inject(Renderer2);
  private daService = inject(ApexDynamicActionService);
  private sub?: Subscription;

  private originalDisplay = '';

  ngOnInit() {
    this.originalDisplay = this.el.nativeElement.style.display || '';

    this.sub = this.daService.events$.subscribe(event => {
      if (
        event.targetRegionId === this.targetId ||
        event.targetComponentId === this.targetId
      ) {
        this.handleAction(event.action, event.payload);
      }
    });
  }

  ngOnDestroy() {
    this.sub?.unsubscribe();
  }

  private handleAction(action: string, payload?: any) {
    const nativeEl = this.el.nativeElement;

    switch (action) {
      case 'show':
        this.renderer.setStyle(nativeEl, 'display', this.originalDisplay);
        break;
      case 'hide':
        this.renderer.setStyle(nativeEl, 'display', 'none');
        break;
      case 'enable':
        this.renderer.removeAttribute(nativeEl, 'disabled');
        if ('disabled' in nativeEl) {
          nativeEl.disabled = false;
        }
        break;
      case 'disable':
        this.renderer.setAttribute(nativeEl, 'disabled', 'true');
        if ('disabled' in nativeEl) {
          nativeEl.disabled = true;
        }
        break;
      case 'refresh':
        // Dispatch custom refresh event for components to handle custom reload logic
        const refreshEvent = new CustomEvent('apex-refresh', { detail: payload });
        nativeEl.dispatchEvent(refreshEvent);
        break;
    }
  }
}

import { Directive, HostListener, Input, inject } from '@angular/core';
import { ApexDynamicActionService } from './dynamic-action.service';

export interface ApexDynamicActionDefinition {
  event: 'click' | 'change' | 'dblclick' | 'mouseenter' | 'mouseleave';
  action: 'refresh' | 'show' | 'hide' | 'enable' | 'disable' | 'custom' | 'executeCode';
  targetId?: string;
  code?: () => void;
  condition?: () => boolean;
}

@Directive({
  selector: '[apexDA]',
  standalone: true
})
export class ApexDynamicActionDirective {
  /** The dynamic action definition */
  @Input('apexDA') daDef!: ApexDynamicActionDefinition;

  private daService = inject(ApexDynamicActionService);

  @HostListener('click', ['$event'])
  onClick(e: Event) {
    if (this.daDef?.event === 'click') {
      this.executeAction();
    }
  }

  @HostListener('change', ['$event'])
  onChange(e: Event) {
    if (this.daDef?.event === 'change') {
      this.executeAction();
    }
  }

  @HostListener('dblclick', ['$event'])
  onDblClick(e: Event) {
    if (this.daDef?.event === 'dblclick') {
      this.executeAction();
    }
  }

  @HostListener('mouseenter', ['$event'])
  onMouseEnter(e: Event) {
    if (this.daDef?.event === 'mouseenter') {
      this.executeAction();
    }
  }

  @HostListener('mouseleave', ['$event'])
  onMouseLeave(e: Event) {
    if (this.daDef?.event === 'mouseleave') {
      this.executeAction();
    }
  }

  private executeAction(): void {
    // Check Client-Side Condition
    if (this.daDef.condition && !this.daDef.condition()) {
      return; // Condition not met
    }

    if (this.daDef.action === 'executeCode' && this.daDef.code) {
      this.daDef.code();
    } else if (this.daDef.action !== 'executeCode') {
      // Broadcast to standard service
      this.daService.broadcast({
        action: this.daDef.action as any,
        targetRegionId: this.daDef.targetId,
        targetComponentId: this.daDef.targetId
      });
    }
  }
}

import { Injectable } from '@angular/core';
import { Subject, Observable } from 'rxjs';
import { filter } from 'rxjs/operators';

/**
 * Event type for Dynamic Actions.
 * Emulates APEX Refresh, Show, Hide, etc.
 */
export interface ApexDynamicActionEvent {
  action: 'refresh' | 'show' | 'hide' | 'enable' | 'disable' | 'custom';
  targetRegionId?: string;
  targetComponentId?: string;
  payload?: any;
}

@Injectable({
  providedIn: 'root'
})
export class ApexDynamicActionService {
  private _events$ = new Subject<ApexDynamicActionEvent>();

  /**
   * Broadcasts a Dynamic Action event to the application.
   */
  public broadcast(event: ApexDynamicActionEvent): void {
    this._events$.next(event);
  }

  /**
   * Observable to listen for ALL Dynamic Action events.
   */
  public get events$(): Observable<ApexDynamicActionEvent> {
    return this._events$.asObservable();
  }

  /**
   * Listens for a specific action on a specific target.
   * Useful for components to listen to 'refresh' events targeted at them.
   */
  public onAction(action: string, targetId: string): Observable<ApexDynamicActionEvent> {
    return this._events$.pipe(
      filter(e => e.action === action && (e.targetRegionId === targetId || e.targetComponentId === targetId))
    );
  }

  /**
   * Convenience method to trigger a refresh on a specific region.
   */
  public refreshRegion(regionId: string, payload?: any): void {
    this.broadcast({
      action: 'refresh',
      targetRegionId: regionId,
      payload
    });
  }
}

import { Injectable } from '@angular/core';
import * as xlsx from 'xlsx';

@Injectable({
  providedIn: 'root'
})
export class ApexExportService {

  /**
   * Export an array of JSON objects to an Excel (.xlsx) file.
   * Emulates APEX "Download > Excel"
   * 
   * @param data Array of objects to export
   * @param fileName Desired file name without extension
   * @param sheetName Desired sheet name
   */
  public exportToExcel(data: any[], fileName: string = 'export', sheetName: string = 'Data'): void {
    if (!data || data.length === 0) {
      console.warn('No data to export');
      return;
    }

    const worksheet: xlsx.WorkSheet = xlsx.utils.json_to_sheet(data);
    const workbook: xlsx.WorkBook = { 
      Sheets: { [sheetName]: worksheet }, 
      SheetNames: [sheetName] 
    };

    // Write and trigger download
    xlsx.writeFile(workbook, `${fileName}.xlsx`);
  }

  /**
   * Export an array of JSON objects to a CSV (.csv) file.
   * Emulates APEX "Download > CSV"
   * 
   * @param data Array of objects to export
   * @param fileName Desired file name without extension
   */
  public exportToCsv(data: any[], fileName: string = 'export'): void {
    if (!data || data.length === 0) {
      console.warn('No data to export');
      return;
    }

    const worksheet: xlsx.WorkSheet = xlsx.utils.json_to_sheet(data);
    const csv: string = xlsx.utils.sheet_to_csv(worksheet);

    // Create Blob and trigger download manually
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', `${fileName}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }
}

