export class ApexTimelineComponent {
  @Input() value: any[] = [];
  @Input() title?: string;
  @Input() align: 'left' | 'right' | 'alternate' | 'top' | 'bottom' = 'left';
  @Input() layout: 'vertical' | 'horizontal' = 'vertical';
  @Input() showActor = true;
  @Input() showRelativeTime = true;

  @ContentChild('marker') markerTemplate?: TemplateRef<any>;
  @ContentChild('content') contentTemplate?: TemplateRef<any>;

  relativeTime(dateStr: string | Date): string {
    const date = new Date(dateStr);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const rtf = new Intl.RelativeTimeFormat('es-MX', { numeric: 'auto' });
    if (diffMins < 1) return 'ahora';
    if (diffMins < 60) return rtf.format(-diffMins, 'minute');
    const diffHours = Math.floor(diffMins / 60);
    if (diffHours < 24) return rtf.format(-diffHours, 'hour');
    const diffDays = Math.floor(diffHours / 24);
    if (diffDays < 30) return rtf.format(-diffDays, 'day');
    return date.toLocaleDateString('es-MX');
  }

  markerColor(event: any): string {
    switch (event.severity) {
      case 'success': return 'var(--green-500)';
      case 'info':    return 'var(--blue-500)';
      case 'warning': return 'var(--yellow-500)';
      case 'error':
      case 'danger':  return 'var(--red-500)';
      default:        return event.color || 'var(--primary-color)';
    }
  }
}

import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { AbstractControl, AsyncValidatorFn, ValidationErrors } from '@angular/forms';
import { Observable, timer, of } from 'rxjs';
import { map, switchMap, catchError } from 'rxjs/operators';

export interface ServerValidationPayload {
  item_name: string;
  item_value: any;
  validation_context?: string;
}

export interface ServerValidationResponse {
  is_valid: boolean;
  message?: string;
}

@Injectable({
  providedIn: 'root'
})
export class ApexServerValidationService {
  constructor(private http: HttpClient) {}

  /**
   * Equivalent to APEX: Server-Side PL/SQL Validation returning Boolean or Error Text
   * This validator hits a generic endpoint. In a real scenario, the endpoint would run
   * the PL/SQL equivalent Python/SQL logic.
   * 
   * @param endpoint URL of the backend validation endpoint
   * @param itemName Name of the field/item being validated
   * @param context Additional context (e.g. form ID, record ID)
   * @param debounceMs Time to wait after user stops typing before calling server
   */
  public createAsyncValidator(
    endpoint: string, 
    itemName: string, 
    context?: string,
    debounceMs: number = 500
  ): AsyncValidatorFn {
    return (control: AbstractControl): Observable<ValidationErrors | null> => {
      if (!control.value) {
        return of(null);
      }

      return timer(debounceMs).pipe(
        switchMap(() => {
          const payload: ServerValidationPayload = {
            item_name: itemName,
            item_value: control.value,
            validation_context: context
          };

          return this.http.post<ServerValidationResponse>(endpoint, payload).pipe(
            map((response: ServerValidationResponse) => {
              return response.is_valid ? null : { serverValidationFailed: true, message: response.message || 'Server validation failed' };
            }),
            catchError(() => of({ serverError: true, message: 'Could not reach validation server' }))
          );
        })
      );
    };
  }
}

/**
 * Dashboard y Reportes - Utilities para renderizado de datos
 * 
 * Aplicado a: director_dashboard, reportes, monitor_sistema, kardex
 */

export interface DashboardData<T> {
  data: T[];
  total: number;
  periodo?: string;
  actualizado?: Date;
  metadata?: Record<string, any>;
}

export interface ReportMetrics {
  total: number;
  completado: number;
  pendiente: number;
  porcentaje: number;
  estado: 'completo' | 'incompleto' | 'vacío';
}

export class DashboardUtils {

  /**
   * Calcula métricas de completitud
   */
  static calculateMetrics(total: number, completed: number): ReportMetrics {
    const porcentaje = total > 0 ? Math.round((completed / total) * 100) : 0;
    return {
      total,
      completado: completed,
      pendiente: total - completed,
      porcentaje,
      estado: porcentaje === 100 ? 'completo' : porcentaje === 0 ? 'vacío' : 'incompleto'
    };
  }

  /**
   * Valida que datos existan antes de renderizar
   */
  static hasData<T>(data: any): data is T[] {
    return Array.isArray(data) && data.length > 0;
  }

  /**
   * Formatea valores monetarios
   */
  static formatCurrency(value: number): string {
    return new Intl.NumberFormat('es-MX', {
      style: 'currency',
      currency: 'MXN'
    }).format(value);
  }

  /**
   * Formatea porcentajes
   */
  static formatPercentage(value: number): string {
    return Math.round(value) + '%';
  }

  /**
   * Determina severidad de métrica
   */
  static getSeverity(porcentaje: number): 'success' | 'warning' | 'danger' {
    if (porcentaje >= 80) return 'success';
    if (porcentaje >= 50) return 'warning';
    return 'danger';
  }
}

/**
 * FASES 5-6: Form Utilities para UX mejorado
 */
export class FormUtils {
  static cleanInput(value: any): string | null {
    if (!value) return null;
    const trimmed = String(value).trim();
    return trimmed.length === 0 ? null : trimmed;
  }

  static validateLength(value: string, maxLength: number, fieldName: string): string | null {
    if (!value) return null;
    if (value.length > maxLength) {
      return `${fieldName} debe tener máximo ${maxLength} caracteres`;
    }
    return null;
  }
}

/**
 * ContextCatalogService — Catálogos de la cascada plantel→nivel→ciclo→grado→grupo.
 *
 * Fuente ÚNICA de la cascada institucional. Concentra la carga de catálogos (antes
 * embebida en ShellComponent) para que la compartan:
 *   - el topbar (ShellComponent), que es el único selector visible de la cascada;
 *   - los grids (InteractiveGridComponent), mediante el lazo bilateral
 *     contexto ⇄ filtros de columna (ver `contextFilters` / `contextSuggestions` /
 *     `applyGridFilter`).
 *
 * El estado seleccionado vive en ContextService; este servicio solo gestiona las
 * LISTAS de opciones y la lógica de cascada (cargar dependientes / auto-seleccionar).
 */
import { Injectable, inject, signal, computed } from '@angular/core';
import { ContextService } from './context.service';
import { ApiService } from './api.service';
import type { Plantel, CicloEscolar, NivelEducativo, Grado, Grupo } from '../models';
import { grupoLabel } from '../models';

// Sentinelas "Todo el Instituto / Todos…" (admin global) — espejo de ShellComponent.
export const TODO_INSTITUTO: Plantel = { id: '', nombre_plantel: '— Todo el Instituto —', escuela_id: '', is_active: true };
export const TODOS_NIVELES: NivelEducativo = { id: '', nombre_nivel: 'Todos los Niveles' as any, autoridad_educativa: '', tipo_ciclo: '', num_periodos_eval: 0 };
export const TODOS_CICLOS: CicloEscolar = { id: '', nombre_ciclo: '— Todos —', nivel_educativo_id: '', fecha_inicio: '', fecha_fin: '', tipo_ciclo: '', es_vigente: true, _label: '— Todos —' };
export const TODOS_GRADOS: Grado = { id: '', numero_grado: 0, nombre_grado: '— Todos —', nivel_educativo_id: '', plantel_id: '' };
export const TODOS_GRUPOS: Grupo = { id: '', nombre_grupo: '— Todos —', grado_id: '', ciclo_escolar_id: '', capacidad_maxima: 0, turno: '', is_active: true };

const NIVEL_ORDER: Record<string, number> = { PRIMARIA: 0, SECUNDARIA: 1, PREPARATORIA: 2 };
function titleNivel(s: string): string {
  return s ? s.charAt(0).toUpperCase() + s.slice(1).toLowerCase() : s;
}

export type CascadeRole = 'plantel' | 'nivel' | 'grado' | 'grupo';

@Injectable({ providedIn: 'root' })
export class ContextCatalogService {
  private readonly ctx = inject(ContextService);
  private readonly api = inject(ApiService);

  // ── Listas de opciones ────────────────────────────────────────────────────────
  readonly planteles = signal<Plantel[]>([]);
  readonly niveles   = signal<NivelEducativo[]>([]);
  readonly ciclos    = signal<CicloEscolar[]>([]);
  readonly grados    = signal<Grado[]>([]);
  readonly grupos    = signal<Grupo[]>([]);

  // ── Para el lazo bilateral con el grid ──────────────────────────────────────────
  /** Labels seleccionados actualmente — siembran los filtros de columna del grid. */
  readonly contextFilters = computed<Record<CascadeRole, string>>(() => ({
    plantel: this.ctx.plantel()?.nombre_plantel ?? '',
    nivel:   this.ctx.nivel()?.nombre_nivel ?? '',
    grado:   this.ctx.grado()?.nombre_grado ?? '',
    grupo:   this.ctx.grupo()?.nombre_grupo ?? '',
  }));

  /** Catálogo completo de labels por rol — alimenta el LOV del grid (permite ampliar). */
  readonly contextSuggestions = computed<Record<CascadeRole, string[]>>(() => ({
    plantel: this.planteles().filter(p => p.id).map(p => p.nombre_plantel),
    nivel:   this.niveles().filter(n => n.id).map(n => String(n.nombre_nivel)),
    grado:   this.grados().filter(g => g.id).map(g => g.nombre_grado),
    grupo:   this.grupos().filter(g => g.id).map(g => g.nombre_grupo),
  }));

  /**
   * Camino grid → contexto: el usuario filtró una columna de rol cascada.
   * Resuelve el label al objeto del catálogo y dispara el cambio de contexto
   * (con su cascada-clear). Label vacío/null ⇒ ampliar (sentinela "TODOS" si existe).
   */
  applyGridFilter(field: string, label: string | null): void {
    const role = field as CascadeRole;
    if (!['plantel', 'nivel', 'grado', 'grupo'].includes(role)) return;
    const clear = !label || !label.trim();

    switch (role) {
      case 'plantel': {
        const t = clear ? this.planteles().find(p => !p.id)
                        : this.planteles().find(p => p.nombre_plantel === label);
        if (t) this.onPlantelChange(t);
        break;
      }
      case 'nivel': {
        const t = clear ? this.niveles().find(n => !n.id)
                        : this.niveles().find(n => String(n.nombre_nivel) === label);
        if (t) this.onNivelChange(t);
        break;
      }
      case 'grado': {
        const t = clear ? this.grados().find(g => !g.id)
                        : this.grados().find(g => g.nombre_grado === label);
        if (t) this.onGradoChange(t);
        break;
      }
      case 'grupo': {
        const t = clear ? this.grupos().find(g => !g.id)
                        : this.grupos().find(g => g.nombre_grupo === label);
        if (t) this.onGrupoChange(t);
        break;
      }
    }
  }

  // ── Inicialización del topbar ───────────────────────────────────────────────────
  initTopbar(): void {
    const usuario = this.ctx.usuario();
    this.api.get<Plantel[]>('/planteles').subscribe(p => {
      const opciones = this.ctx.esAdminGlobal() ? [TODO_INSTITUTO, ...p] : p;
      this.planteles.set(opciones);

      if (!this.ctx.plantel()) {
        let inicial: Plantel | null;
        if (usuario?.plantel_id) {
          inicial = p.find(x => x.id === usuario.plantel_id) ?? p[0] ?? null;
        } else if (this.ctx.esAdminGlobal()) {
          inicial = TODO_INSTITUTO;
        } else {
          inicial = p[0] ?? null;
        }
        this.ctx.setPlantel(inicial?.id ? inicial : null);
        if (inicial?.id) this.loadNiveles(); else this.loadNivelesTodos();
      } else if (this.ctx.plantel()?.id) {
        this.loadNiveles();
      } else {
        this.loadNivelesTodos();
      }
    });
  }

  // ── Cambios de cascada (topbar y grid pasan por aquí) ───────────────────────────
  onPlantelChange(p: Plantel): void {
    const esGlobal = !p?.id;
    this.ctx.setPlantel(esGlobal ? null : p);
    this.ctx.setNivel(null);
    this.ctx.setCiclo(null);
    this.ctx.setGrado(null);
    this.ctx.setGrupo(null);
    this.ciclos.set([]);
    this.grados.set([]);
    this.grupos.set([]);
    if (esGlobal) this.loadNivelesTodos(); else this.loadNiveles();
  }

  onNivelChange(n: NivelEducativo): void {
    const esGlobal = !n?.id;
    this.ctx.setNivel(esGlobal ? null : n);
    this.ctx.setCiclo(null);
    this.ctx.setGrado(null);
    this.ctx.setGrupo(null);
    this.grados.set([]);
    this.grupos.set([]);
    this.loadCiclos();
  }

  onCicloChange(c: CicloEscolar): void {
    const esGlobal = !c?.id;
    this.ctx.setCiclo(esGlobal ? null : c);
    this.ctx.setGrupo(null);
    this.grupos.set([]);
    this.loadGrados();
  }

  onGradoChange(g: Grado): void {
    const esGlobal = !g?.id;
    this.ctx.setGrado(esGlobal ? null : g);
    this.ctx.setGrupo(null);
    this.grupos.set([]);
    this.loadGrupos();
  }

  onGrupoChange(g: Grupo): void {
    const esGlobal = !g?.id;
    this.ctx.setGrupo(esGlobal ? null : g);
  }

  // ── Carga de catálogos dependientes ─────────────────────────────────────────────
  private sortNiveles(ns: NivelEducativo[]): NivelEducativo[] {
    return [...ns]
      .sort((a, b) => (NIVEL_ORDER[a.nombre_nivel] ?? 99) - (NIVEL_ORDER[b.nombre_nivel] ?? 99))
      .map(n => ({ ...n, nombre_nivel: titleNivel(n.nombre_nivel) as any }));
  }

  private loadNivelesTodos(): void {
    this.api.get<NivelEducativo[]>('/catalogs/niveles').subscribe(ns => {
      this.niveles.set([TODOS_NIVELES, ...this.sortNiveles(ns)]);
      this.ctx.setNivel(null);
      this.loadCiclos();
    });
  }

  private loadNiveles(): void {
    const plantelId = this.ctx.plantel()?.id;
    if (!plantelId) return;

    this.api.get<NivelEducativo[]>(`/planteles/${plantelId}/niveles`).subscribe(ns => {
      const sorted = this.sortNiveles(ns);
      const opciones = this.ctx.esAdminGlobal() ? [TODOS_NIVELES, ...sorted] : sorted;
      this.niveles.set(opciones);

      const usuario = this.ctx.usuario();
      let inicial: NivelEducativo | null = null;
      if (usuario?.nivel_educativo_id) inicial = sorted.find(x => x.id === usuario.nivel_educativo_id) ?? null;
      if (!inicial && this.ctx.nivel()?.id) inicial = sorted.find(x => x.id === this.ctx.nivel()!.id) ?? null;
      if (!inicial && sorted.length) inicial = sorted[0];

      if (inicial) {
        this.ctx.setNivel(inicial);
        this.loadCiclos();
      }
    });
  }

  private loadCiclos(): void {
    const params: Record<string, any> = { solo_vigentes: true };
    if (this.ctx.nivel()?.id) params['nivel_id'] = this.ctx.nivel()!.id;

    this.api.get<CicloEscolar[]>('/catalogs/ciclos', params).subscribe(c => {
      const labeled = c.map(x => ({
        ...x,
        _label: (!this.ctx.nivel()?.id && x.nivel_educativo?.nombre_nivel)
          ? `${x.nombre_ciclo} — ${titleNivel(x.nivel_educativo.nombre_nivel)}`
          : x.nombre_ciclo,
      }));
      const opciones = this.ctx.esAdminGlobal() ? [TODOS_CICLOS, ...labeled] : labeled;
      this.ciclos.set(opciones);

      if (opciones.length) {
        const existente = this.ctx.ciclo() ? opciones.find(x => x.id === this.ctx.ciclo()!.id) : null;
        const elegido = existente ?? opciones[0];
        this.ctx.setCiclo(elegido?.id ? elegido : null);
      }
      this.loadGrados();
    });
  }

  private loadGrados(): void {
    const params: Record<string, any> = {};
    if (this.ctx.nivel()?.id) params['nivel_id'] = this.ctx.nivel()!.id;
    if (this.ctx.plantel()?.id) params['plantel_id'] = this.ctx.plantel()!.id;

    this.api.get<Grado[]>('/catalogs/grados', params).subscribe(gs => {
      const opciones = this.ctx.esAdminGlobal() ? [TODOS_GRADOS, ...gs] : gs;
      this.grados.set(opciones);

      const usuario = this.ctx.usuario();
      let inicial: Grado | null = null;
      if (usuario?.grado_id) inicial = gs.find(x => x.id === usuario.grado_id) ?? null;
      if (!inicial && this.ctx.grado()?.id) inicial = gs.find(x => x.id === this.ctx.grado()!.id) ?? null;
      if (!inicial && opciones.length) inicial = opciones[0];

      this.ctx.setGrado(inicial?.id ? inicial : null);
      this.loadGrupos();
    });
  }

  private loadGrupos(): void {
    const params: Record<string, any> = { solo_activos: true };
    if (this.ctx.plantel()?.id) params['plantel_id'] = this.ctx.plantel()!.id;
    if (this.ctx.grado()?.id) params['grado_id'] = this.ctx.grado()!.id;
    if (this.ctx.ciclo()?.id) params['ciclo_escolar_id'] = this.ctx.ciclo()!.id;

    this.api.get<Grupo[]>('/grupos', params).subscribe(gps => {
      const labeled = gps.map(x => ({ ...x, _label: grupoLabel(x) }));
      const todoGrupo = { ...TODOS_GRUPOS, _label: '— Todos los Grupos —' };
      const opciones = this.ctx.esAdminGlobal() ? [todoGrupo, ...labeled] : labeled;
      this.grupos.set(opciones);

      const usuario = this.ctx.usuario();
      let inicial: Grupo | null = null;
      if (usuario?.grupo_id) inicial = gps.find(x => x.id === usuario.grupo_id) ?? null;
      if (!inicial && this.ctx.grupo()?.id) inicial = gps.find(x => x.id === this.ctx.grupo()!.id) ?? null;
      if (!inicial && opciones.length) inicial = opciones[0];

      this.ctx.setGrupo(inicial?.id ? inicial : null);
    });
  }
}

/**
 * ContextService — Equivale a los Application Items de Oracle APEX.
 * Mantiene el plantel, ciclo y nivel seleccionados por el usuario.
 * Todos los componentes se suscriben a este servicio para filtrar datos.
 */
import { Injectable, signal, computed, effect } from '@angular/core';
import type { AppContext, Plantel, CicloEscolar, NivelEducativo, UsuarioMe, Grado, Grupo } from '../models';
import { esAdminGlobal, esAdminPlantel, tieneScopeNivel, rolLabel } from '../models';

const STORAGE_KEY = 'ades_context';

@Injectable({ providedIn: 'root' })
export class ContextService {
  private readonly _plantel = signal<Plantel | null>(this._restore('plantel'));
  private readonly _ciclo   = signal<CicloEscolar | null>(this._restore('ciclo'));
  private readonly _nivel   = signal<NivelEducativo | null>(this._restore('nivel'));
  private readonly _grado   = signal<Grado | null>(this._restore('grado'));
  private readonly _grupo   = signal<Grupo | null>(this._restore('grupo'));
  private readonly _usuario = signal<UsuarioMe | null>(this._restore('usuario'));

  readonly plantel = this._plantel.asReadonly();
  readonly ciclo   = this._ciclo.asReadonly();
  readonly nivel   = this._nivel.asReadonly();
  readonly grado   = this._grado.asReadonly();
  readonly grupo   = this._grupo.asReadonly();
  readonly usuario = this._usuario.asReadonly();

  readonly context = computed<AppContext>(() => ({
    plantel: this._plantel(),
    ciclo:   this._ciclo(),
    nivel:   this._nivel(),
    grado:   this._grado(),
    grupo:   this._grupo(),
    usuario: this._usuario(),
  }));

  /** true si el contexto mínimo está configurado */
  readonly isReady = computed(() => !!this._plantel() && !!this._ciclo());

  // ── Helpers de rol ───────────────────────────────────────────────────────────
  readonly esAdminGlobal  = computed(() => esAdminGlobal(this._usuario()));
  readonly esAdminPlantel = computed(() => esAdminPlantel(this._usuario()));
  readonly tieneScopeNivel = computed(() => tieneScopeNivel(this._usuario()));
  /** El usuario puede seleccionar plantel libremente (admin global o plantel) */
  readonly puedeSeleccionarPlantel = computed(() =>
    !this.tieneScopeNivel() && this._usuario() != null
  );
  readonly rolLabel = computed(() => rolLabel(this._usuario()));
  readonly nivelAcceso = computed(() => this._usuario()?.nivel_acceso ?? 99);

  constructor() {
    // Persistir cambios en sessionStorage
    effect(() => {
      const ctx = this.context();
      if (ctx.plantel)  sessionStorage.setItem('ades_plantel',  JSON.stringify(ctx.plantel));
      if (ctx.ciclo)    sessionStorage.setItem('ades_ciclo',    JSON.stringify(ctx.ciclo));
      if (ctx.nivel)    sessionStorage.setItem('ades_nivel',    JSON.stringify(ctx.nivel));
      if (ctx.grado)    sessionStorage.setItem('ades_grado',    JSON.stringify(ctx.grado));
      if (ctx.grupo)    sessionStorage.setItem('ades_grupo',    JSON.stringify(ctx.grupo));
      if (ctx.usuario)  sessionStorage.setItem('ades_usuario',  JSON.stringify(ctx.usuario));
    });
  }

  setPlantel(p: Plantel | null): void { this._plantel.set(p); }
  setCiclo(c: CicloEscolar | null): void { this._ciclo.set(c); }
  setNivel(n: NivelEducativo | null): void { this._nivel.set(n); }
  setGrado(g: Grado | null): void { this._grado.set(g); }
  setGrupo(g: Grupo | null): void { this._grupo.set(g); }
  setUsuario(u: UsuarioMe | null): void {
    this._usuario.set(u);
    if (!u) {
      sessionStorage.removeItem('ades_usuario');
      sessionStorage.removeItem('ades_plantel');
      sessionStorage.removeItem('ades_ciclo');
      sessionStorage.removeItem('ades_nivel');
      sessionStorage.removeItem('ades_grado');
      sessionStorage.removeItem('ades_grupo');
    }
  }

  private _restore<T>(key: string): T | null {
    try {
      const raw = sessionStorage.getItem(`ades_${key}`);
      return raw ? (JSON.parse(raw) as T) : null;
    } catch { return null; }
  }
}

/**
 * ExportService — Exportación de tablas al estilo Oracle APEX.
 *
 * Formatos soportados:
 *   - CSV  : sin dependencias externas
 *   - XLSX : SheetJS (xlsx@0.18.5), genera libro real de Excel
 *   - PDF  : descarga desde endpoint backend (WeasyPrint)
 *
 * Uso:
 *   export.toCSV(data, columns, 'alumnos')
 *   export.toXLSX(data, columns, 'Alumnos', 'alumnos')
 *   export.toURL('/api/v1/boletas/{id}', 'boleta.pdf')
 */
import { Injectable } from '@angular/core';

export interface ExportColumn {
  field: string;          // dot-path: 'persona.nombre'
  header: string;         // label en el encabezado
  format?: (val: any) => string;  // transformación opcional
}

@Injectable({ providedIn: 'root' })
export class ExportService {

  // ── CSV ─────────────────────────────────────────────────────────────────────

  toCSV(data: any[], columns: ExportColumn[], filename: string): void {
    const header = columns.map(c => `"${c.header}"`).join(',');
    const rows = data.map(row =>
      columns.map(c => {
        const val = this._getDeep(row, c.field);
        const str = c.format ? c.format(val) : (val ?? '');
        return `"${String(str).replace(/"/g, '""')}"`;
      }).join(',')
    );
    this._download([header, ...rows].join('\n'), `${filename}.csv`, 'text/csv;charset=utf-8;');
  }

  // ── XLSX ────────────────────────────────────────────────────────────────────

  async toXLSX(data: any[], columns: ExportColumn[], sheetName: string, filename: string): Promise<void> {
    const XLSX = await import('xlsx');

    const ws_data = [
      columns.map(c => c.header),
      ...data.map(row =>
        columns.map(c => {
          const val = this._getDeep(row, c.field);
          return c.format ? c.format(val) : (val ?? '');
        })
      ),
    ];

    const ws = XLSX.utils.aoa_to_sheet(ws_data);

    // Ancho automático de columnas
    const colWidths = columns.map((c, i) => {
      const maxLen = Math.max(
        c.header.length,
        ...data.map(row => {
          const v = this._getDeep(row, c.field);
          return String(c.format ? c.format(v) : (v ?? '')).length;
        })
      );
      return { wch: Math.min(maxLen + 2, 50) };
    });
    ws['!cols'] = colWidths;

    // Estilo de encabezado (rojo Nevadi)
    const range = XLSX.utils.decode_range(ws['!ref'] || 'A1');
    for (let C = range.s.c; C <= range.e.c; C++) {
      const cellRef = XLSX.utils.encode_cell({ r: 0, c: C });
      if (ws[cellRef]) {
        ws[cellRef].s = {
          font: { bold: true, color: { rgb: 'FFFFFF' } },
          fill: { fgColor: { rgb: 'D02030' } },
          alignment: { horizontal: 'center' },
        };
      }
    }

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, sheetName);
    XLSX.writeFile(wb, `${filename}.xlsx`);
  }

  // ── PDF desde URL backend ────────────────────────────────────────────────────

  toURL(url: string, filename: string): void {
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.target = '_blank';
    a.click();
  }

  // ── Helpers ──────────────────────────────────────────────────────────────────

  private _getDeep(obj: any, path: string): any {
    return path.split('.').reduce((acc, key) => acc?.[key], obj);
  }

  private _download(content: string, filename: string, mime: string): void {
    const blob = new Blob(['﻿' + content], { type: mime }); // BOM para Excel UTF-8
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }
}

import { Injectable, inject, signal, computed } from '@angular/core';
import { ApiService } from './api.service';
import { tap } from 'rxjs/operators';
import { Observable, of } from 'rxjs';

export interface ModuloPermisos {
  puedeVer: boolean;
  puedeEditar: boolean;
  puedeCrear: boolean;
  puedeEliminar: boolean;
}

const DEFAULT_PERMISOS: ModuloPermisos = {
  puedeVer: true,
  puedeEditar: true,
  puedeCrear: true,
  puedeEliminar: false,
};

const READ_ONLY: ModuloPermisos = {
  puedeVer: true,
  puedeEditar: false,
  puedeCrear: false,
  puedeEliminar: false,
};

@Injectable({ providedIn: 'root' })
export class PermisosService {
  private readonly api = inject(ApiService);

  private readonly _permisos = signal<Record<string, ModuloPermisos>>({});
  private _loaded = false;

  readonly permisos = this._permisos.asReadonly();

  loadPermisos(): Observable<void> {
    if (this._loaded) return of(void 0);
    return this.api.get<Record<string, ModuloPermisos>>('/menus/mis-permisos').pipe(
      tap(data => {
        this._permisos.set(data);
        this._loaded = true;
      }),
    ) as unknown as Observable<void>;
  }

  /** Get permissions for a module clave, falling back to default if not configured */
  get(clave: string): ModuloPermisos {
    return this._permisos()[clave] ?? DEFAULT_PERMISOS;
  }

  puedeVer(clave: string):      boolean { return this.get(clave).puedeVer; }
  puedeEditar(clave: string):   boolean { return this.get(clave).puedeEditar; }
  puedeCrear(clave: string):    boolean { return this.get(clave).puedeCrear; }
  puedeEliminar(clave: string): boolean { return this.get(clave).puedeEliminar; }

  /** Signal that returns true if user can edit the given module */
  puedeEditarSignal(clave: string) {
    return computed(() => (this._permisos()[clave] ?? DEFAULT_PERMISOS).puedeEditar);
  }

  invalidate(): void {
    this._loaded = false;
    this._permisos.set({});
  }
}

/**
 * PushNotificationService — FASE 20 (ntfy).
 *
 * Conecta el navegador al stream SSE de ntfy para recibir notificaciones push
 * en tiempo real, sin necesidad de service worker.
 *
 * Flujo:
 *   1. Al hacer login → init() → GET /push/suscripcion
 *   2. Abre EventSource a ntfy/{topic}/sse
 *   3. Cada mensaje dispara un Subject que el componente de notificaciones observa
 *   4. Muestra notificación nativa del browser si el permiso está concedido
 */
import { Injectable, inject } from '@angular/core';
import { Subject } from 'rxjs';
import { ApiService } from './api.service';

export interface PushEvent {
  id: string;
  event: string;
  topic: string;
  title: string;
  message: string;
  priority: number;
  time: number;
  tags?: string[];
  click?: string;
}

@Injectable({ providedIn: 'root' })
export class PushNotificationService {
  private readonly api = inject(ApiService);

  private _eventSource: EventSource | null = null;
  private _topic = '';

  readonly events$ = new Subject<PushEvent>();
  readonly connected$ = new Subject<boolean>();

  async init(ntfyBaseUrl?: string): Promise<void> {
    try {
      const sub = await this.api.get<{
        topic: string;
        url_sse: string;
        token_requerido: boolean;
      }>('/push/suscripcion').toPromise();

      if (!sub) return;
      this._topic = sub.topic;

      // Solicitar permiso para notificaciones nativas
      if ('Notification' in window && Notification.permission === 'default') {
        await Notification.requestPermission();
      }

      this._conectar(sub.url_sse);
    } catch {
      // ntfy no disponible — modo degradado (solo campanita in-app)
    }
  }

  private _conectar(url: string): void {
    this._desconectar();

    const es = new EventSource(url);
    this._eventSource = es;

    es.onmessage = (ev) => {
      try {
        const data: PushEvent = JSON.parse(ev.data);
        if (data.event === 'keepalive') return;
        this.events$.next(data);
        this._mostrarNativa(data);
      } catch { /* ignorar mensajes malformados */ }
    };

    es.onopen = () => this.connected$.next(true);
    es.onerror = () => {
      this.connected$.next(false);
      // Reconectar automáticamente cada 30s si hay error
      setTimeout(() => {
        if (this._eventSource === es) this._conectar(url);
      }, 30_000);
    };
  }

  private _mostrarNativa(ev: PushEvent): void {
    if (!('Notification' in window) || Notification.permission !== 'granted') return;
    const n = new Notification(ev.title || 'ADES', {
      body: ev.message,
      icon: '/assets/nevadi-images/favicon.ico',
      tag: ev.id,
    });
    if (ev.click) n.onclick = () => { window.open(ev.click, '_blank'); n.close(); };
  }

  private _desconectar(): void {
    if (this._eventSource) {
      this._eventSource.close();
      this._eventSource = null;
      this.connected$.next(false);
    }
  }

  destroy(): void { this._desconectar(); }
}

export async function compressImageIfNeeded(file: File, maxSizeInBytes: number = 2 * 1024 * 1024): Promise<File> {
  if (!file.type.startsWith('image/')) {
    return file; // No es imagen, no se comprime
  }
  if (file.size <= maxSizeInBytes) {
    return file; // Ya es menor de 2 MB
  }

  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = (event: any) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        // Si es muy grande, reducir dimensiones proporcionalmente
        const maxDimension = 2048;
        if (width > maxDimension || height > maxDimension) {
          if (width > height) {
            height = Math.round((height * maxDimension) / width);
            width = maxDimension;
          } else {
            width = Math.round((width * maxDimension) / height);
            height = maxDimension;
          }
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        if (!ctx) {
          resolve(file);
          return;
        }

        ctx.drawImage(img, 0, 0, width, height);

        // Ajustar calidad progresivamente hasta que pese menos del límite
        let quality = 0.85;

        const attemptCompress = () => {
          canvas.toBlob((blob) => {
            if (!blob) {
              resolve(file);
              return;
            }

            if (blob.size <= maxSizeInBytes || quality <= 0.2) {
              const compressedFile = new File([blob], file.name.replace(/\.[^/.]+$/, "") + ".jpg", {
                type: 'image/jpeg', // convertimos a jpeg para máxima compresión
                lastModified: Date.now(),
              });
              resolve(compressedFile);
            } else {
              // Reducir calidad progresivamente
              quality -= 0.15;
              attemptCompress();
            }
          }, 'image/jpeg', quality);
        };

        attemptCompress();
      };
      img.onerror = () => resolve(file);
      img.src = event.target.result;
    };
    reader.onerror = () => resolve(file);
    reader.readAsDataURL(file);
  });
}

