    .dlg-lbl { display: block; font-size: .85rem; margin-bottom: .25rem; color: var(--text-color-secondary); }
    .dlg-note { font-size: .78rem; color: var(--text-color-secondary); margin: 0; }
  `],
})
export class AlumnosComponent implements OnInit {
  private readonly api = inject(ApiService);
  private readonly ctx = inject(ContextService);
  readonly catalog = inject(ContextCatalogService);
  private readonly notify = inject(ApexNotificationService);
  private readonly exp = inject(ExportService);
  private readonly crearAlumnoSubject = new Subject<void>();
  alumnos = signal<Estudiante[]>([]);
  alumnosDatos = signal<any[]>([]);
  totalAlumnos = signal(0);
  busqueda = signal('');

  /** Columnas gobernadas por el contexto global (filtrado server-side + lazo bilateral). */
  readonly cascadeFields = ['plantel', 'nivel', 'grado', 'grupo'];

  readonly alumnosFiltrados = computed(() => {
    const q = this.busqueda().toLowerCase();
    if (!q) return this.alumnosDatos();
    return this.alumnosDatos().filter(a =>
      (a.nombre_completo ?? a.nombre ?? '').toLowerCase().includes(q) ||
      (a.matricula ?? '').toLowerCase().includes(q)
    );
  });

  alumnoSeleccionado = signal<Estudiante | null>(null);
  perfilVisible = signal(false);
  showDialog = signal(false);
  loading = signal(false);
  loadingTabla = signal(false);
  form = { nombre: '', apellido_paterno: '', apellido_materno: '', curp: '' };

  readonly recargar = () => this.cargarAlumnos();

  // Spec: spec/modules/fase-24-interactive-grid/specification.md § Pre-configured Schemas
  columnas: ColumnConfig[] = [
    { field: 'matricula', header: 'Matrícula', sortable: true, filterable: true, width: '120px' },
    { field: 'nombre_completo', header: 'Nombre Completo', sortable: true, filterable: true, width: '200px' },
    { field: 'curp', header: 'CURP', sortable: true, filterable: true, width: '170px' },
    { field: 'nss', header: 'NSS', sortable: false, filterable: false, width: '80px' },
    { field: 'plantel', header: 'Plantel', sortable: true, filterable: true, width: '140px' },
    { field: 'nivel', header: 'Nivel', sortable: true, filterable: true, width: '120px' },
    { field: 'grado', header: 'Grado', sortable: true, filterable: true, width: '80px' },
    { field: 'grupo', header: 'Grupo', sortable: true, filterable: true, width: '80px' },
    { field: 'fecha_ingreso', header: 'Ingreso', sortable: true, filterable: false, width: '110px' },
  ];

  private readonly exportCols = [
    { field: 'matricula', header: 'Matrícula' },
    { field: 'nombre_completo', header: 'Nombre Completo' },
    { field: 'curp', header: 'CURP' },
    { field: 'rfc', header: 'RFC' },
    { field: 'genero', header: 'Género' },
    { field: 'fecha_nacimiento', header: 'Fecha Nacimiento' },
    { field: 'telefono', header: 'Teléfono' },
    { field: 'email_personal', header: 'Email' },
    { field: 'nacionalidad', header: 'Nacionalidad' },
    { field: 'plantel', header: 'Plantel' },
    { field: 'nivel', header: 'Nivel' },
    { field: 'grado', header: 'Grado' },
    { field: 'grupo', header: 'Grupo' },
    { field: 'fecha_ingreso', header: 'Fecha Ingreso' },
    { field: 'nss', header: 'NSS' },
    { field: 'tipo_alumno', header: 'Tipo Alumno' },
    { field: 'escuela_procedencia', header: 'Escuela Procedencia' },
    { field: 'promedio_procedencia', header: 'Promedio Procedencia' },
    { field: 'beca_tipo', header: 'Beca' },
    { field: 'folio_sep', header: 'Folio SEP' },
  ];

  constructor() {
    // Recargar cuando cambia la cascada del contexto global (topbar o lazo del grid).
    effect(() => {
      // Suscripción explícita a las 4 dimensiones de la cascada.
      this.ctx.plantel(); this.ctx.nivel(); this.ctx.grado(); this.ctx.grupo();
      this.cargarAlumnos();
    });
  }

  ngOnInit(): void {
    // Throttle submissions to max one every 500ms to prevent duplicate requests
    this.crearAlumnoSubject.pipe(
      throttleTime(500, undefined, { leading: true, trailing: false })
    ).subscribe(() => {
      this.performCrearAlumno();
    });
  }

  cargarAlumnos(): void {
    const params: Record<string, any> = {
      pagina: 1,
      por_pagina: 500,
    };
    const plantel = this.ctx.plantel(); if (plantel?.id) params['plantel_id'] = plantel.id;
    const nivel = this.ctx.nivel();     if (nivel?.id)   params['nivel_id']   = nivel.id;
    const grado = this.ctx.grado();     if (grado?.id)   params['grado_id']   = grado.id;
    const grupo = this.ctx.grupo();     if (grupo?.id)   params['grupo_id']   = grupo.id;

    this.loadingTabla.set(true);
    this.api.get<{ data: Estudiante[]; total: number }>('/alumnos', params)
      .subscribe({
        next: resp => {
          this.alumnos.set(resp.data);
          this.totalAlumnos.set(resp.total);
          // Transform for grid display
          this.alumnosDatos.set(resp.data.map((a: any) => ({
            id: a.id,
            matricula: a.matricula,
            nombre_completo: `${a.persona?.nombre} ${a.persona?.apellido_paterno} ${a.persona?.apellido_materno || ''}`.trim(),
            curp: a.persona?.curp || '',
            rfc: a.persona?.rfc || '',
            genero: a.persona?.genero || '',
            fecha_nacimiento: a.persona?.fecha_nacimiento || '',
            telefono: a.persona?.telefono || '',
            email_personal: a.persona?.email_personal || '',
            nacionalidad: a.persona?.nacionalidad || '',
            plantel: a.plantel_nombre || '—',
            nss: a.nss || '',
            tipo_alumno: a.tipo_alumno || '',
            escuela_procedencia: a.escuela_procedencia || '',
            promedio_procedencia: a.promedio_procedencia ?? '',
            beca_tipo: a.beca_tipo || '',
            folio_sep: a.folio_sep || '',
            nivel: a.nivel_educativo?.nombre_nivel || '—',
            grado: a.grado?.nombre_grado || '—',
            grupo: a.grupo?.nombre_grupo || '—',
            fecha_ingreso: a.fecha_ingreso,
            _original: a,
          })));
          this.loadingTabla.set(false);
        },
        error: () => {
          this.loadingTabla.set(false);
          this.notify.error('Error', 'No se pudieron cargar los alumnos');
        },
      });
  }
  abrirPerfil(row: any): void {
    const alumno = row._original || this.alumnos().find(a => a.id === row.id);
    if (!alumno) return;
    this.api.get<Estudiante>(`/alumnos/${alumno.id}`).subscribe({
      next: full => {
        this.alumnoSeleccionado.set(full);
        this.perfilVisible.set(true);
      },
      error: () => {
        this.notify.error('Error', 'No se pudo cargar el perfil');
      },
    });
  }

  onPerfilGuardado(): void {
    this.cargarAlumnos();
  }

  openDialog(): void {
    this.showDialog.set(true);
    this.form = { nombre: '', apellido_paterno: '', apellido_materno: '', curp: '' };
  }

  exportCSV(): void  { this.exp.toCSV(this.alumnosDatos(), this.exportCols, 'alumnos'); }
  exportXLSX(): void { this.exp.toXLSX(this.alumnosDatos(), this.exportCols, 'Alumnos', 'alumnos'); }

  crearAlumno(): void {
    // Guard: prevent multiple submissions - check before emitting to subject
    if (this.loading()) {
      return;
    }
    // Emit to throttled subject — max one per 500ms
    this.crearAlumnoSubject.next();
  }

  private performCrearAlumno(): void {
    // Set loading IMMEDIATELY to block any subsequent calls from crearAlumno()
    // This must happen synchronously before any async operations
    this.loading.set(true);

    if (!this.form.nombre || !this.form.apellido_paterno || !this.form.curp) {
      this.loading.set(false);
      this.notify.warning('Campos requeridos', 'Nombre, apellido paterno y CURP son obligatorios');
      return;
    }
    if (this.form.curp.length !== 18) {
      this.loading.set(false);
      this.notify.warning('CURP inválida', 'La CURP debe tener exactamente 18 caracteres');
      return;
    }
    const payload = {
      persona: {
        nombre: this.form.nombre,
        apellido_paterno: this.form.apellido_paterno,
        apellido_materno: this.form.apellido_materno || '',
        curp: this.form.curp.toUpperCase(),
      },
      plantel_id: this.ctx.plantel()?.id,
    };
    this.api.post<Estudiante>('/alumnos', payload).subscribe({
      next: (newAlumno) => {
        this.showDialog.set(false);
        this.loading.set(false);
        this.notify.success('Creado', `Matrícula: ${newAlumno.matricula}`);
        this.cargarAlumnos();
        this.abrirPerfil({ _original: newAlumno });
      },
      error: (e) => {
        this.loading.set(false);
        const detail = e.error?.detail ?? e.error?.message;
        const status = e.status;
        const msg = Array.isArray(detail) ? detail.map((d: any) => d.msg || d).join('; ')
                  : typeof detail === 'string' ? detail
                  : status === 409 ? 'Ya existe un alumno con esa CURP'
                  : status === 422 ? (e.error?.error || 'Datos inválidos')
                  : 'Error al crear alumno';
        this.notify.error('Error', msg);
      },
    });
  }
}

import { Component, OnInit, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/services/api.service';
import { ButtonModule } from 'primeng/button';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { ToastModule } from 'primeng/toast';
import { DatePickerModule } from 'primeng/datepicker';
import { CheckboxModule } from 'primeng/checkbox';
import { InputNumberModule } from 'primeng/inputnumber';
import { CardModule } from 'primeng/card';
import { AutoCompleteModule } from 'primeng/autocomplete';
import { MessageService } from 'primeng/api';
import { ApexNotificationService } from 'apex-component-library';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';

interface AsistenciaPersonal {
  id: string;
  persona_id: string;
  nombre_completo?: string;
  fecha: string;
  hora_entrada: string | null;
  hora_salida: string | null;
  tipo_jornada: string;
  es_retardo: boolean;
  minutos_retardo: number;
  justificado: boolean;
  justificacion: string | null;
  observaciones: string | null;
  row_version: number;
}

interface ReportePersonal {
  persona_id: string;
  mes: number;
  anio: number;
  total_dias: number;
  dias_asistio: number;
  dias_falta: number;
  dias_incapacidad: number;
  dias_vacaciones: number;
  dias_permiso: number;
  total_retardos: number;
  porcentaje_asistencia: number;
}

/**
 * Registro y seguimiento de asistencia del personal administrativo y docente.
 * Permite registrar hora de entrada/salida, retardos y justificaciones por
 * trabajador. Genera resúmenes mensuales con porcentaje de asistencia.
 * Usa optimistic locking (`row_version`) en actualizaciones. Requiere
 * nivelAcceso ≥ 4 (AdminPlantel) para acceder a registros de otros usuarios.
 */
@Component({
  selector: 'app-asistencia-personal',
  standalone: true,
  imports: [
    CommonModule, FormsModule, ButtonModule,
    DialogModule, InputTextModule, SelectModule,
    ToastModule, DatePickerModule, CheckboxModule, InputNumberModule, CardModule,
    AutoCompleteModule, InteractiveGridComponent,
  ],
  providers: [MessageService],
  template: `
    <p-toast />
    <div class="apex-page">
      <div class="apex-toolbar">
        <h2 class="apex-title">Control de Asistencia del Personal</h2>
        <div class="apex-toolbar-actions">
          <input pInputText [(ngModel)]="filtroNombre" (input)="onFiltroNombre()"
            placeholder="Buscar por nombre…" style="width:220px" />
          <p-datepicker [(ngModel)]="filtroFechaInicio" dateFormat="yy-mm-dd" placeholder="Desde" [showIcon]="true" style="width:150px" />
          <p-datepicker [(ngModel)]="filtroFechaFin"    dateFormat="yy-mm-dd" placeholder="Hasta" [showIcon]="true" style="width:150px" />
          <p-button label="Registrar" icon="pi pi-plus" size="small" (onClick)="abrirNuevo()" />
          <p-button label="Reporte" icon="pi pi-chart-bar" size="small" severity="secondary" (onClick)="verReporte()" />
        </div>
      </div>

      <!-- Reporte mensual -->
      @if (reporte()) {
        <div class="reporte-bar">
          <div class="rep-item"><span class="rep-num text-green-600">{{ reporte()!.dias_asistio }}</span><span class="rep-lbl">Asistió</span></div>
          <div class="rep-item"><span class="rep-num text-red-600">{{ reporte()!.dias_falta }}</span><span class="rep-lbl">Faltas</span></div>
          <div class="rep-item"><span class="rep-num text-orange-500">{{ reporte()!.total_retardos }}</span><span class="rep-lbl">Retardos</span></div>
          <div class="rep-item"><span class="rep-num">{{ reporte()!.dias_incapacidad }}</span><span class="rep-lbl">Incapacidad</span></div>
          <div class="rep-item"><span class="rep-num">{{ reporte()!.dias_vacaciones }}</span><span class="rep-lbl">Vacaciones</span></div>
          <div class="rep-item">
            <span class="rep-num" [class.text-green-600]="reporte()!.porcentaje_asistencia>=90"
              [class.text-red-600]="reporte()!.porcentaje_asistencia<80">
              {{ reporte()!.porcentaje_asistencia }}%
            </span>
            <span class="rep-lbl">Asistencia</span>
          </div>
          <p-button icon="pi pi-times" [text]="true" size="small" ariaLabel="Cerrar reporte" (onClick)="reporte.set(null)" class="ml-auto" />
        </div>
      }

      <app-interactive-grid
        [data]="registrosFlat()"
        [columns]="registrosColumns"
        [loading]="cargando()"
        (rowSelected)="editar($event)"
      />
    </div>

    <!-- Dialog: Registro -->
    <p-dialog [header]="editandoId ? 'Editar Registro' : 'Registrar Asistencia'"
      [(visible)]="dialogForm" [modal]="true" [style]="{width:'540px'}" [draggable]="false">
      <div class="grid grid-cols-2 gap-3 p-2">
        @if (!editandoId) {
          <div class="col-span-2 flex flex-col gap-1">
            <label class="text-sm font-medium">Personal <span class="text-red-500">*</span></label>
            <p-autocomplete
              [(ngModel)]="personaSeleccionada"
              [suggestions]="personaSugerencias()"
              (completeMethod)="buscarPersona($event)"
              optionLabel="label"
              [forceSelection]="true"
              [delay]="300"
              placeholder="Escriba nombre del empleado…"
              style="width:100%"
            />
          </div>
          <div class="flex flex-col gap-1">
            <label class="text-sm font-medium">Fecha <span class="text-red-500">*</span></label>
            <p-datepicker [(ngModel)]="form.fecha" dateFormat="yy-mm-dd" [showIcon]="true" />
          </div>
        }
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Tipo Jornada</label>
          <p-select [options]="jornadaOpts" [(ngModel)]="form.tipo_jornada" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Hora Entrada</label>
          <input pInputText [(ngModel)]="form.hora_entrada" placeholder="08:00" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Hora Salida</label>
          <input pInputText [(ngModel)]="form.hora_salida" placeholder="14:30" />
        </div>
        <div class="flex items-center gap-2 mt-4">
          <p-checkbox [(ngModel)]="form.es_retardo" [binary]="true" inputId="retardo" />
          <label for="retardo" class="text-sm">Retardo</label>
        </div>
        @if (form.es_retardo) {
          <div class="flex flex-col gap-1">
            <label class="text-sm font-medium">Minutos de retardo</label>
            <p-inputNumber [(ngModel)]="form.minutos_retardo" [min]="1" />
          </div>
        }
        <div class="flex items-center gap-2">
          <p-checkbox [(ngModel)]="form.justificado" [binary]="true" inputId="justif" />
          <label for="justif" class="text-sm">Justificado</label>
        </div>
        @if (form.justificado) {
          <div class="col-span-2 flex flex-col gap-1">
            <label class="text-sm font-medium">Justificación</label>
            <input pInputText [(ngModel)]="form.justificacion" placeholder="Motivo de la falta justificada…" />
          </div>
        }
        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Observaciones</label>
          <input pInputText [(ngModel)]="form.observaciones" />
        </div>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="dialogForm=false" />
        <p-button [label]="editandoId ? 'Guardar' : 'Registrar'" icon="pi pi-save"
          [loading]="guardando()" (onClick)="guardar()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog: Reporte mensual -->
    <p-dialog header="Generar Reporte Mensual" [(visible)]="dialogReporte"
      [modal]="true" [style]="{width:'400px'}" [draggable]="false">
      <div class="flex flex-col gap-3 p-2">
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Personal <span class="text-red-500">*</span></label>
          <p-autocomplete
            [(ngModel)]="personaReporteSelec"
            [suggestions]="personaReporteSug()"
            (completeMethod)="buscarPersonaReporte($event)"
            optionLabel="label"
            [forceSelection]="true"
            [delay]="300"
            placeholder="Buscar empleado…"
            style="width:100%"
          />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Mes</label>
          <p-select [options]="mesOpts" [(ngModel)]="reporteMes" />
