/**
 * CalificacionesComponent — Libreta de calificaciones.
 *
 * Patrón Oracle APEX: Editable Interactive Report
 *   - Tabla con filtro por columna en header (filterDisplay="row")
 *   - Edición inline por celda (p-cellEditor) — igual que APEX Editable IR
 *   - Cambios se acumulan localmente
 *   - Un solo botón "Guardar cambios" envía el PATCH bulk
 *   - Exportar a CSV con un click
 */
import { Component, OnInit, inject, signal, computed, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
// PrimeNG
import { TableModule } from 'primeng/table';
import { ButtonModule } from 'primeng/button';
import { SelectModule } from 'primeng/select';
import { InputNumberModule } from 'primeng/inputnumber';
import { TagModule } from 'primeng/tag';
import { TooltipModule } from 'primeng/tooltip';
import { ToolbarModule } from 'primeng/toolbar';
import { Table } from 'primeng/table';

import { ContextService } from '../../core/services/context.service';
import { ApiService } from '../../core/services/api.service';
import type { Materia, LibretaGrupo, RegistroLibreta, Grupo, PeriodoSimple } from '../../core/models';
import { grupoLabel } from '../../core/models';

type GrupoConLabel = Grupo & { _label: string };
import { HelpButtonComponent } from '../../shared/components/help-button/help-button.component';
import { ApexNotificationService } from 'apex-component-library';

@Component({
  selector: 'app-calificaciones',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    TableModule, ButtonModule, SelectModule, InputNumberModule,
    TagModule, TooltipModule, ToolbarModule,
    HelpButtonComponent,
  ],
  template: `

    <div class="page-header">
      <div>
        <h2>Calificaciones</h2>
        <p class="subtitle">
          Libreta de calificaciones — edición inline
          @if (ctx.ciclo()?.sistema_educativo) {
            <p-tag [value]="ctx.ciclo()!.sistema_educativo"
                   [severity]="ctx.ciclo()!.sistema_educativo === 'SEP' ? 'info' : 'success'"
                   [style]="{'margin-left': '1rem'}"></p-tag>
          }
        </p>
      </div>
      <app-help-button modulo="calificaciones" />
    </div>

    <!-- Filtro de dominio: Materia (la cascada plantel→nivel→grado→grupo vive en el topbar) -->
    <div class="filter-bar">
      <p-select
        [options]="materias()"
        [(ngModel)]="selectedMateria"
        optionLabel="nombre_materia"
        placeholder="Seleccionar materia"
        (onChange)="loadLibreta()"
        [showClear]="true"
        [disabled]="!selectedGrupo"
        [filter]="true" filterPlaceholder="Buscar..."/>
    </div>

    <!-- ── Libreta — Editable Interactive Report ── -->
    @if (libreta()) {
      @if (esCualitativa()) {
        <div class="cual-badge">
          <i class="pi pi-star-fill"></i>
          Evaluación cualitativa NEM — Grado {{ selectedGrupo?.numero_grado }}° Primaria
          <span class="cual-desc-legend">
            @for (d of cualDescriptores(); track d.nivel) {
              <span class="cual-chip" [style.background]="d.color" [pTooltip]="d.descripcion">
                {{ d.nivel }} – {{ d.label }}
              </span>
            }
          </span>
        </div>
      }
      <p-toolbar styleClass="libreta-toolbar">
        <ng-template pTemplate="start">
          <span class="changes-badge" [class.has-changes]="pendingChanges() > 0">
            {{ pendingChanges() }} cambio(s) sin guardar
          </span>
        </ng-template>
        <ng-template pTemplate="end">
          <p-button
            label="Guardar cambios"
            icon="pi pi-save"
            [disabled]="pendingChanges() === 0"
            [loading]="saving()"
            (onClick)="guardarCambios()"
          />
          <p-button
            label="Exportar CSV"
            icon="pi pi-download"
            severity="secondary"
            [text]="true"
            (onClick)="exportarCSV()"
            styleClass="ml-2"
          />
        </ng-template>
      </p-toolbar>

      <p-table
        #dt
        [value]="libreta()!.registros"
        [columns]="columnas()"
        filterDisplay="row"
        [paginator]="true"
        [rows]="30"
        [rowsPerPageOptions]="[15, 30, 50]"
        [showCurrentPageReport]="true"
        currentPageReportTemplate="{first}-{last} de {totalRecords} alumnos"
        styleClass="p-datatable-sm p-datatable-gridlines libreta-table"
        [editMode]="'cell'"
      >
        <ng-template pTemplate="caption">
          <div class="table-caption">
            <input
              pInputText
              type="text"
              placeholder="Buscar alumno..."
              (input)="dt.filterGlobal($any($event.target).value, 'contains')"
              class="search-input"
            />
          </div>
        </ng-template>

        <ng-template pTemplate="header" let-columns>
          <tr>
            <th pSortableColumn="matricula" style="width:110px">
              Matrícula <p-sortIcon field="matricula" />
            </th>
            <th pSortableColumn="nombre_completo">
              Alumno <p-sortIcon field="nombre_completo" />
            </th>
            @for (col of columns; track col) {
              <th style="width:110px; text-align:center">{{ col }}</th>
            }
            <th style="width:90px; text-align:center; font-weight:700">Promedio</th>
            <th style="width:70px; text-align:center">Acredita</th>
          </tr>
          <tr>
            <th><p-columnFilter field="matricula" type="text" matchMode="contains" /></th>
            <th><p-columnFilter field="nombre_completo" type="text" matchMode="contains" /></th>
            @for (col of columns; track col) { <th></th> }
            <th></th><th></th>
          </tr>
        </ng-template>

        <ng-template pTemplate="body" let-row let-columns="columns">
          <tr>
            <td>{{ row.matricula }}</td>
            <td>{{ row.nombre_completo }}</td>
            @for (col of columns; track col) {
              <td
                [pEditableColumn]="esCualitativa() ? (row.niveles_logro?.[col] ?? null) : row.calificaciones[col]"
                pEditableColumnField="col"
                style="text-align:center; padding:0.2rem"
                [class.edited]="isEdited(row.estudiante_id, col)"
              >
                @if (esCualitativa()) {
                  <p-cellEditor>
                    <ng-template pTemplate="input">
                      <p-select
                        [options]="cualDescriptoresOpts()"
                        [(ngModel)]="row.niveles_logro[col]"
                        placeholder="—"
                        [style]="{width:'110px'}"
                        (onChange)="onLogrolChange(row, col, $event.value)"
                      />
                    </ng-template>
                    <ng-template pTemplate="output">
                      @if (row.niveles_logro?.[col]) {
                        <span class="cual-cell"
                          [style.background]="nivelColor(row.niveles_logro[col])">
                          {{ row.niveles_logro[col] }}
                          @if (cualMostrarEquiv()) {
                            <span class="cual-equiv">({{ row.calificaciones[col] | number:'1.1-1' }})</span>
                          }
                        </span>
                      } @else { <span style="color:var(--text-muted)">—</span> }
                    </ng-template>
                  </p-cellEditor>
                } @else {
                  <p-cellEditor>
                    <ng-template pTemplate="input">
                      <p-inputNumber
                        [(ngModel)]="row.calificaciones[col]"
                        [min]="0" [max]="10" [maxFractionDigits]="1"
                        [inputStyle]="{width:'60px', textAlign:'center'}"
                        (onBlur)="onCalificacionChange(row, col)"
                      />
                    </ng-template>
                    <ng-template pTemplate="output">
                      {{ row.calificaciones[col] | number:'1.1-1' }}
                    </ng-template>
                  </p-cellEditor>
                }
              </td>
            }
            <td style="text-align:center; font-weight:600">
              @if (esCualitativa()) {
                @if (nivelPromedio(row); as np) {
                  <span class="cual-cell" [style.background]="nivelColor(np)">{{ np }}</span>
                } @else { — }
              } @else {
                {{ row.promedio | number:'1.1-1' }}
              }
            </td>
            <td style="text-align:center">
              @if (row.promedio !== null) {
                <p-tag
                  [value]="row.promedio! >= 6 ? 'Sí' : 'No'"
                  [severity]="row.promedio! >= 6 ? 'success' : 'danger'"
                />
              }
            </td>
          </tr>
        </ng-template>

        <ng-template pTemplate="emptymessage">
          <tr><td [colSpan]="3 + columnas().length">No hay registros para esta materia.</td></tr>
        </ng-template>
      </p-table>
    } @else {
      <div class="empty-state">
        <i class="pi pi-info-circle" style="font-size:2rem; color:var(--text-muted)"></i>
        <p>Selecciona un grupo y una materia para ver la libreta.</p>
      </div>
    }
  `,
  styles: [`
    .page-header { margin-bottom: 1rem; }
    .filter-bar { display: flex; gap: 1rem; margin-bottom: 1rem; flex-wrap: wrap; }
    .libreta-toolbar { margin-bottom: 0.5rem; }
    .changes-badge { font-size: 0.85rem; color: var(--text-secondary); }
    .changes-badge.has-changes { color: var(--color-warning); font-weight: 600; }
    .table-caption { display: flex; justify-content: flex-end; }
    .search-input { padding: 0.4rem 0.6rem; border: 1px solid var(--surface-border); border-radius: 4px; }
    td.edited { background-color: #fef9c3 !important; }
    .empty-state { display: flex; flex-direction: column; align-items: center; gap: 0.5rem; padding: 4rem; color: var(--text-muted); }
    :host ::ng-deep .libreta-table .p-datatable-tbody > tr > td { padding: 0.3rem 0.5rem; }
    /* Evaluación cualitativa */
    .cual-badge { display:flex; align-items:center; gap:.5rem; flex-wrap:wrap;
      background:#eff6ff; border:1px solid #bfdbfe; border-radius:6px;
      padding:.5rem .75rem; margin-bottom:.75rem; font-size:.85rem; color:#1e40af; font-weight:500; }
    .cual-desc-legend { display:flex; gap:.4rem; flex-wrap:wrap; margin-left:.5rem; }
    .cual-chip { color:#fff; font-size:.75rem; font-weight:600; padding:.15rem .5rem;
      border-radius:4px; cursor:help; }
    .cual-cell { display:inline-flex; align-items:center; gap:.25rem; color:#fff;
      font-weight:700; font-size:.82rem; padding:.15rem .45rem; border-radius:4px; }
    .cual-equiv { font-weight:400; opacity:.85; font-size:.75rem; }
  `],
})
export class CalificacionesComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);
  private readonly notify = inject(ApexNotificationService);

  materias      = signal<Materia[]>([]);
  libreta       = signal<LibretaGrupo | null>(null);
  saving        = signal(false);

  /** Grupo derivado del contexto global (topbar). Expone nombre_nivel y numero_grado para esCualitativa. */
  get selectedGrupo(): GrupoConLabel | null {
    const g = this.ctx.grupo();
    if (!g?.id) return null;
    return { ...g, _label: grupoLabel(g) } as GrupoConLabel;
  }
  selectedMateria:   Materia | null = null;

  private editadas = new Set<string>();

  // ── Evaluación Cualitativa NEM ───────────────────────────────────────────
  cualConfig    = signal<{ config: any; escala: any } | null>(null);
  cualGrados    = computed<number[]>(() => {
    const v = this.cualConfig()?.config?.['EVAL_CUAL_GRADOS_PRIMARIA'];
    return Array.isArray(v) ? v : [];
  });
  cualDescriptores = computed<any[]>(() => {
    return this.cualConfig()?.escala?.valores_json ?? [];
  });
  cualDescriptoresOpts = computed(() =>
    this.cualDescriptores().map(d => ({ label: `${d.nivel} – ${d.label}`, value: d.nivel }))
  );
  cualMostrarEquiv = computed<boolean>(() =>
    !!this.cualConfig()?.config?.['EVAL_CUAL_MOSTRAR_EQUIVALENCIA']
  );

  /** true cuando el grupo seleccionado es de primaria y su grado está en la lista cualitativa */
  esCualitativa = computed(() => {
    const grupo = this.selectedGrupo;
    if (!grupo) return false;
    const nivel = (grupo as any).nombre_nivel ?? (grupo as any).nivel ?? '';
    if (!nivel.toLowerCase().includes('primaria')) return false;
    const grado = (grupo as any).numero_grado ?? (grupo as any).numero ?? 0;
    return this.cualGrados().includes(Number(grado));
  });

  /** Calcula el nivel de logro dominante (el más frecuente) para una fila */
  nivelPromedio(row: any): string | null {
    if (!row.niveles_logro) return null;
    const counts: Record<string, number> = {};
    const orden = ['D', 'C', 'B', 'A'];
    for (const v of Object.values(row.niveles_logro)) {
      if (v) counts[v as string] = (counts[v as string] ?? 0) + 1;
    }
    if (!Object.keys(counts).length) return null;
    let best: string | null = null;
    for (const n of orden) {
      if (counts[n]) { best = n; break; }
    }
    return best;
  }

  nivelColor(nivel: string | null): string {
    const d = this.cualDescriptores().find((x: any) => x.nivel === nivel);
    return d?.color ?? '#94a3b8';
  }

  columnas       = computed(() => this.libreta()?.periodos ?? []);
  pendingChanges = computed(() => this.editadas.size);

  constructor() {
    // Recargar materias cuando cambia el grupo en el contexto global.
    effect(() => {
      const grupo = this.ctx.grupo();
      this.selectedMateria = null;
      this.libreta.set(null);
      this.editadas.clear();
      if (!grupo?.id) {
        this.materias.set([]);
        return;
      }
      this.onGrupoChange();
    });
  }

  ngOnInit(): void {
    // ngOnInit no necesita cargar planteles — la cascada vive en el topbar.
  }

  onGrupoChange(): void {
    this.selectedMateria = null;
    this.libreta.set(null);
    this.editadas.clear();
    if (!this.selectedGrupo) return;

    // Cargar config cualitativa si aún no está cargada
    if (!this.cualConfig()) {
      this.api.get<any>('/calificaciones/config-cualitativa', { nivel: 'PRIMARIA' }).subscribe({
        next: cfg => this.cualConfig.set(cfg),
        error: () => {},
      });
    }

    const gradoId = this.selectedGrupo.grado_id;
    const cicloId = this.ctx.ciclo()?.id;
    const planParams: Record<string, any> = { grado_id: gradoId };
    if (cicloId) planParams['ciclo_id'] = cicloId;

    // Cargar planes del grado para obtener las materia_ids vigentes
    this.api.get<any[]>('/planes-estudio', planParams).subscribe({
      next: planes => {
        const materiaIds = new Set(planes.map((p: any) => p.materia_id).filter(Boolean));
        // Cargar todas las materias y filtrar por las que están en el plan del grado
        this.api.get<Materia[]>('/materias').subscribe({
          next: all => {
            const filtradas = materiaIds.size > 0
              ? all.filter(m => materiaIds.has(m.id))
              : all;
            this.materias.set(filtradas.sort((a, b) => a.nombre_materia.localeCompare(b.nombre_materia)));
          },
          error: () => this.materias.set([]),
        });
      },
      error: () => {
        // Fallback: cargar materias por nivel del grupo
        const nivelNombre = this.selectedGrupo?.nombre_nivel;
        const params: Record<string, any> = {};
        if (nivelNombre) params['nivel'] = nivelNombre;
        this.api.get<Materia[]>('/materias', params).subscribe({
          next: all => this.materias.set(all.sort((a, b) => a.nombre_materia.localeCompare(b.nombre_materia))),
          error: () => this.materias.set([]),
        });
      },
    });
  }

  loadLibreta(): void {
    if (!this.selectedGrupo || !this.selectedMateria) return;
    this.editadas.clear();
    this.api.get<LibretaGrupo>(
      `/calificaciones/grupo/${this.selectedGrupo.id}/libreta`,
      { materia_id: this.selectedMateria.id },
    ).subscribe(l => this.libreta.set(l));
  }

  isEdited(estudianteId: string, periodo: string): boolean {
    return this.editadas.has(`${estudianteId}|${periodo}`);
  }

  onCalificacionChange(row: RegistroLibreta, periodo: string): void {
    this.editadas.add(`${row.estudiante_id}|${periodo}`);
    const vals = Object.values(row.calificaciones).filter((v): v is number => v !== null);
    row.promedio = vals.length ? parseFloat((vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(1)) : null;
  }

  onLogrolChange(row: any, periodo: string, nivel: string): void {
    this.editadas.add(`${row.estudiante_id}|${periodo}`);
    // Actualizar calificacion_final con equiv_num del descriptor
    const d = this.cualDescriptores().find((x: any) => x.nivel === nivel);
    if (d && d.equiv_num !== undefined) {
      if (!row.calificaciones) row.calificaciones = {};
      row.calificaciones[periodo] = d.equiv_num;
      // Recalcular promedio local
      const vals = Object.values(row.calificaciones as Record<string, number>).filter(v => v !== null);
      row.promedio = vals.length ? parseFloat((vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(1)) : null;
    }
  }

  guardarCambios(): void {
    if (!this.libreta() || !this.selectedMateria || !this.selectedGrupo) return;
    this.saving.set(true);

    const libreta = this.libreta()!;
    const periodoMap = new Map<string, string>(
      libreta.periodos_detalle.map((p: PeriodoSimple) => [p.nombre_periodo, p.id]),
    );
    const esCual = this.esCualitativa();

    const requests = [...this.editadas].map(key => {
      const [estudianteId, periodoNombre] = key.split('|');
      const row = libreta.registros.find((r: any) => r.estudiante_id === estudianteId);
      const periodoId = periodoMap.get(periodoNombre);
      if (!row || !periodoId) return null;

      if (esCual) {
        const nivelLogro = (row as any).niveles_logro?.[periodoNombre];
        if (!nivelLogro) return null;
        return {
          _endpoint: '/calificaciones/cualitativa',
          estudianteId, grupoId: this.selectedGrupo!.id,
          materiaId: this.selectedMateria!.id,
          periodoEvaluacionId: periodoId,
          nivelLogro,
        };
      } else {
        const valor = row?.calificaciones[periodoNombre];
        if (valor === null || valor === undefined) return null;
        return {
          _endpoint: '/calificaciones/manual',
          estudiante_id: estudianteId,
          grupo_id: this.selectedGrupo!.id,
          materia_id: this.selectedMateria!.id,
          periodo_id: periodoId,
          calificacion_final: valor,
        };
      }
    }).filter(Boolean);

    if (requests.length === 0) {
      this.saving.set(false);
      this.editadas.clear();
      return;
    }

    let completed = 0;
    let hasError = false;
    requests.forEach((payload: any) => {
      const endpoint = payload._endpoint;
      const { _endpoint, ...body } = payload;
      this.api.post(endpoint, body).subscribe({
        next: () => {
          completed++;
          if (completed === requests.length && !hasError) {
            this.saving.set(false);
            this.editadas.clear();
            this.notify.success('Guardado', `${completed} calificación(es) guardadas`);
          }
        },
        error: (e) => {
          hasError = true;
          this.saving.set(false);
          this.notify.error('Error', e.error?.detail || e.error?.message || 'Error al guardar');
        },
      });
    });
  }

  exportarCSV(): void {
    // Construir CSV manualmente
    const libreta = this.libreta();
    if (!libreta) return;
    const header = ['Matrícula', 'Alumno', ...libreta.periodos, 'Promedio'].join(',');
    const rows = libreta.registros.map(r => [
      r.matricula,
      r.nombre_completo,
      ...libreta.periodos.map(p => r.calificaciones[p] ?? ''),
      r.promedio ?? '',
    ].join(','));
    const csv = [header, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `calificaciones_${this.selectedGrupo?.nombre_grupo ?? 'grupo'}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }
}

import { Component, OnInit, signal, inject, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/services/api.service';
import { ButtonModule } from 'primeng/button';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { TextareaModule } from 'primeng/textarea';
import { TagModule } from 'primeng/tag';
import { ToastModule } from 'primeng/toast';
import { DatePickerModule } from 'primeng/datepicker';
import { InputNumberModule } from 'primeng/inputnumber';
import { CardModule } from 'primeng/card';
import { AutoCompleteModule } from 'primeng/autocomplete';
import { MessageService } from 'primeng/api';
import { ApexNotificationService } from 'apex-component-library';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';

interface Capacitacion {
  id: string;
  docente_id: string;
  nombre_docente?: string;
  nombre: string;
  descripcion: string | null;
  institucion: string;
  tipo_certificacion: string;
  modalidad: string;
  fecha_inicio: string;
  fecha_fin: string;
  duracion_hrs: number;
  area_formacion: string | null;
  certificado_url: string | null;
  folio_certificado: string | null;
  validado_rh: boolean;
  fecha_validacion: string | null;
  row_version: number;
  fecha_creacion: string;
}

interface ResumenCapacitaciones {
  docente_id: string;
  total_hrs: number;
  total_eventos: number;
  por_tipo: Record<string, number>;
  por_modalidad: Record<string, number>;
  validadas: number;
}

interface CapacitacionForm {
  nombre: string;
  descripcion: string;
  institucion: string;
  tipo_certificacion: string;
  modalidad: string;
  fecha_inicio: Date | null;
  fecha_fin: Date | null;
  duracion_hrs: number;
  area_formacion: string;
  folio_certificado: string;
  certificado_url: string;
}

/**
 * Registro y seguimiento de capacitaciones y certificaciones del personal docente.
 * Captura tipo, modalidad, institución, duración en horas y folio de certificado.
 * Genera resúmenes por docente con totales y distribución por área de formación.
 * El área de RRHH puede validar registros (campo `validado_rh`). Usa optimistic
 * locking (`row_version`) en actualizaciones. Requiere nivelAcceso ≥ 3.
 */
@Component({
  selector: 'app-capacitaciones',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    ButtonModule, DialogModule,
    InputTextModule, SelectModule, TextareaModule,
    TagModule, ToastModule, DatePickerModule,
    InputNumberModule, CardModule, AutoCompleteModule,
    InteractiveGridComponent,
  ],
  providers: [MessageService],
  template: `
    <p-toast />

    <div class="apex-page">
      <!-- Toolbar -->
      <div class="apex-toolbar">
        <h2 class="apex-title">Capacitaciones y Certificaciones Docentes</h2>
        <div class="apex-toolbar-actions">
          <input pInputText [(ngModel)]="filtroNombre" (input)="onFiltroNombre()"
            placeholder="Buscar por docente…" style="min-width:200px" />
          <p-select [options]="tipoOpts" [(ngModel)]="filtroTipo" placeholder="Todos los tipos"
            [showClear]="true" (onChange)="cargar()" style="min-width:150px" />
          <p-select [options]="modalidadOpts" [(ngModel)]="filtroModalidad" placeholder="Modalidad"
            [showClear]="true" (onChange)="cargar()" style="min-width:130px" />
          <p-select [options]="validadoOpts" [(ngModel)]="filtroValidado" placeholder="Validación"
            [showClear]="true" (onChange)="cargar()" style="min-width:120px" />
          <p-button label="Registrar Capacitación" icon="pi pi-plus" size="small" (onClick)="abrirNueva()" />
        </div>
      </div>

      <!-- Resumen stats (si hay filtro por docente) -->
      @if (resumen()) {
        <div class="resumen-bar">
          <div class="resumen-item">
            <span class="resumen-num">{{ resumen()!.total_hrs }}</span>
            <span class="resumen-lbl">Horas totales</span>
          </div>
          <div class="resumen-item">
            <span class="resumen-num">{{ resumen()!.total_eventos }}</span>
            <span class="resumen-lbl">Eventos</span>
          </div>
          <div class="resumen-item">
            <span class="resumen-num text-green-600">{{ resumen()!.validadas }}</span>
            <span class="resumen-lbl">Validadas</span>
          </div>
        </div>
      }

      <!-- Grid -->
      <app-interactive-grid
        [data]="capacitacionesFlat()"
        [columns]="capacitacionColumns"
        [loading]="cargando()"
        [showDelete]="true"
        (rowSelected)="verDetalle($event)"
        (rowDeleted)="eliminar($event)"
      />
    </div>

    <!-- Dialog: Nueva Capacitación -->
    <p-dialog
      header="Registrar Capacitación / Certificación"
      [(visible)]="dialogNueva"
      [modal]="true"
      [style]="{width:'640px'}"
      [draggable]="false">

      <div class="grid grid-cols-2 gap-3 p-2">
        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Docente <span class="text-red-500">*</span></label>
          <p-autocomplete
            [(ngModel)]="docenteSeleccionado"
            [suggestions]="docenteSugerencias()"
            (completeMethod)="buscarDocente($event)"
            optionLabel="label"
            [forceSelection]="true"
            [delay]="300"
            placeholder="Escriba nombre del docente…"
            style="width:100%"
          />
        </div>

        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Nombre del evento <span class="text-red-500">*</span></label>
          <input pInputText [(ngModel)]="form.nombre" placeholder="Ej: Taller de Evaluación Formativa" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Institución <span class="text-red-500">*</span></label>
          <input pInputText [(ngModel)]="form.institucion" placeholder="Ej: SEP, UAEMEX…" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Tipo <span class="text-red-500">*</span></label>
          <p-select [options]="tipoOpts" [(ngModel)]="form.tipo_certificacion" placeholder="Selecciona…" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Modalidad <span class="text-red-500">*</span></label>
          <p-select [options]="modalidadOpts" [(ngModel)]="form.modalidad" placeholder="Selecciona…" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Área de Formación</label>
          <p-select [options]="areaOpts" [(ngModel)]="form.area_formacion" placeholder="Ninguna" [showClear]="true" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Fecha Inicio <span class="text-red-500">*</span></label>
          <p-datepicker [(ngModel)]="form.fecha_inicio" dateFormat="yy-mm-dd" [showIcon]="true" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Fecha Fin <span class="text-red-500">*</span></label>
          <p-datepicker [(ngModel)]="form.fecha_fin" dateFormat="yy-mm-dd" [showIcon]="true" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Duración (hrs) <span class="text-red-500">*</span></label>
          <p-inputNumber [(ngModel)]="form.duracion_hrs" [min]="0.5" [step]="0.5" [maxFractionDigits]="1" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Folio Certificado</label>
          <input pInputText [(ngModel)]="form.folio_certificado" placeholder="Número de folio…" />
        </div>

        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">URL Certificado (MinIO)</label>
          <input pInputText [(ngModel)]="form.certificado_url" placeholder="https://…" />
        </div>

        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Descripción</label>
          <textarea pTextarea [(ngModel)]="form.descripcion" rows="2" placeholder="Descripción breve…"></textarea>
        </div>
      </div>

      <ng-template pTemplate="footer">
        <p-button label="Cancelar" icon="pi pi-times" [text]="true" (onClick)="dialogNueva=false" />
        <p-button label="Guardar" icon="pi pi-save" [loading]="guardando()" (onClick)="guardar()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog: Detalle -->
    <p-dialog
      header="Detalle de Capacitación"
      [(visible)]="dialogDetalle"
      [modal]="true"
      [style]="{width:'560px'}"
      [draggable]="false">
      @if (seleccionada()) {
        <div class="grid grid-cols-2 gap-y-3 gap-x-4 p-2 text-sm">
          <div class="col-span-2"><span class="font-medium">Nombre:</span> {{ seleccionada()!.nombre }}</div>
          <div><span class="font-medium">Institución:</span> {{ seleccionada()!.institucion }}</div>
          <div><span class="font-medium">Tipo:</span> {{ tipoLabel(seleccionada()!.tipo_certificacion) }}</div>
          <div><span class="font-medium">Modalidad:</span> {{ seleccionada()!.modalidad }}</div>
          <div><span class="font-medium">Área:</span> {{ seleccionada()!.area_formacion ?? '—' }}</div>
          <div><span class="font-medium">Inicio:</span> {{ seleccionada()!.fecha_inicio }}</div>
          <div><span class="font-medium">Fin:</span> {{ seleccionada()!.fecha_fin }}</div>
          <div><span class="font-medium">Horas:</span> {{ seleccionada()!.duracion_hrs }}</div>
          <div><span class="font-medium">Validado RH:</span>
            <p-tag [value]="seleccionada()!.validado_rh ? 'Sí' : 'No'"
              [severity]="seleccionada()!.validado_rh ? 'success' : 'warn'" class="ml-1" />
          </div>
          @if (seleccionada()!.folio_certificado) {
            <div class="col-span-2"><span class="font-medium">Folio:</span> {{ seleccionada()!.folio_certificado }}</div>
          }
          @if (seleccionada()!.descripcion) {
            <div class="col-span-2"><span class="font-medium">Descripción:</span> {{ seleccionada()!.descripcion }}</div>
          }
          <div class="col-span-2 text-gray-400 text-xs">Versión {{ seleccionada()!.row_version }} — {{ seleccionada()!.fecha_creacion }}</div>
        </div>
      }
    </p-dialog>
  `,
  styles: [`
    .apex-page { padding: 1rem; }
    .apex-toolbar {
      display: flex; align-items: center; justify-content: space-between;
      margin-bottom: 1rem; flex-wrap: wrap; gap: 0.5rem;
    }
    .apex-title { margin: 0; font-size: 1.25rem; font-weight: 600; }
    .apex-toolbar-actions { display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; }
    .resumen-bar {
      display: flex; gap: 2rem; padding: 0.75rem 1rem; background: var(--surface-100);
      border-radius: 8px; margin-bottom: 1rem; border: 1px solid var(--surface-200);
    }
    .resumen-item { display: flex; flex-direction: column; align-items: center; }
    .resumen-num { font-size: 1.5rem; font-weight: 700; color: var(--primary-color); }
    .resumen-lbl { font-size: 0.75rem; color: var(--text-color-secondary); }
  `],
})
export class CapacitacionesComponent implements OnInit {
  private api = inject(ApiService);
  private notify = inject(ApexNotificationService);

  capacitaciones = signal<Capacitacion[]>([]);

  readonly capacitacionColumns: ColumnConfig[] = [
    { field: 'nombre_docente', header: 'Docente',      sortable: true, filterable: true,  width: '180px' },
    { field: 'nombreConFolio', header: 'Nombre',       sortable: true, filterable: true },
    { field: 'institucion',    header: 'Institución',  sortable: true, filterable: true,  width: '160px' },
    { field: 'tipoLabel',      header: 'Tipo',         sortable: true, filterable: true,  width: '110px' },
    { field: 'modalidad',      header: 'Modalidad',    sortable: true, filterable: true,  width: '100px' },
    { field: 'fecha_inicio',   header: 'Inicio',       sortable: true, filterable: false, width: '100px' },
    { field: 'duracion_hrs',   header: 'Hrs',          sortable: true, filterable: false, width: '70px' },
    { field: 'validadoLabel',  header: 'Validado',     sortable: true, filterable: true,  width: '90px' },
  ];

  readonly capacitacionesFlat = computed(() =>
    this.capacitaciones().map(cap => ({
      ...cap,
      nombreConFolio: cap.folio_certificado ? `${cap.nombre} (${cap.folio_certificado})` : cap.nombre,
      tipoLabel: this.tipoOpts.find(o => o.value === cap.tipo_certificacion)?.label ?? cap.tipo_certificacion,
      areaFormacion: cap.area_formacion ?? '—',
      validadoLabel: cap.validado_rh ? 'Validado' : 'Pendiente',
    }))
  );
  cargando       = signal(false);
  guardando      = signal(false);
  seleccionada   = signal<Capacitacion | null>(null);
  resumen        = signal<ResumenCapacitaciones | null>(null);
  docenteSugerencias = signal<{ label: string; value: string }[]>([]);
  docenteSeleccionado: { label: string; value: string } | null = null;

  dialogNueva   = false;
  dialogDetalle = false;

  filtroTipo     = '';
  filtroModalidad = '';
  filtroValidado: boolean | null = null;
  filtroNombre   = '';

  private filtroTimer: ReturnType<typeof setTimeout> | null = null;

  form: CapacitacionForm = this.resetForm();

  tipoOpts = [
    { label: 'Curso',          value: 'CURSO' },
    { label: 'Taller',         value: 'TALLER' },
    { label: 'Diplomado',      value: 'DIPLOMADO' },
    { label: 'Posgrado',       value: 'POSGRADO' },
    { label: 'Certificación',  value: 'CERTIFICACION' },
    { label: 'Congreso',       value: 'CONGRESO' },
    { label: 'Otro',           value: 'OTRO' },
  ];

  modalidadOpts = [
    { label: 'Presencial', value: 'PRESENCIAL' },
    { label: 'En línea',   value: 'EN_LINEA' },
    { label: 'Híbrida',    value: 'HIBRIDA' },
  ];

  areaOpts = [
    { label: 'Pedagogía',    value: 'PEDAGOGIA' },
    { label: 'TIC',          value: 'TIC' },
    { label: 'Disciplinar',  value: 'DISCIPLINAR' },
    { label: 'Idiomas',      value: 'IDIOMAS' },
    { label: 'Liderazgo',    value: 'LIDERAZGO' },
    { label: 'Otro',         value: 'OTRO' },
  ];

  validadoOpts = [
    { label: 'Validadas',    value: true },
    { label: 'No validadas', value: false },
  ];

  ngOnInit() { this.cargar(); }

  onFiltroNombre() {
    if (this.filtroTimer) clearTimeout(this.filtroTimer);
    this.filtroTimer = setTimeout(() => this.cargar(), 400);
  }

  cargar() {
    this.cargando.set(true);
    const params: Record<string, string> = {};
    if (this.filtroTipo)               params['tipo']     = this.filtroTipo;
    if (this.filtroModalidad)          params['modalidad'] = this.filtroModalidad;
    if (this.filtroValidado !== null)  params['validado'] = String(this.filtroValidado);
    if (this.filtroNombre)             params['q']        = this.filtroNombre;

    this.api.get<Capacitacion[]>('/capacitaciones', params).subscribe({
      next: data => { this.capacitaciones.set(data); this.cargando.set(false); },
      error: () => { this.cargando.set(false); this.notify.error('Error al cargar capacitaciones'); },
    });
  }

  buscarDocente(event: { query: string }) {
    if (!event.query || event.query.length < 2) { this.docenteSugerencias.set([]); return; }
    this.api.get<any>('/profesores', { buscar: event.query }).subscribe({
      next: res => {
        const data = res?.data ?? res ?? [];
        this.docenteSugerencias.set(data.map((p: any) => ({
          label: [p.nombre ?? p.persona?.nombre, p.apellido_paterno ?? p.persona?.apellido_paterno, p.apellido_materno ?? p.persona?.apellido_materno].filter(Boolean).join(' '),
          value: p.id,
        })));
      },
      error: () => this.docenteSugerencias.set([]),
    });
  }

  abrirNueva() {
    this.form = this.resetForm();
    this.docenteSeleccionado = null;
    this.dialogNueva = true;
  }

  guardar() {
    if (!this.docenteSeleccionado?.value || !this.form.nombre || !this.form.institucion
        || !this.form.tipo_certificacion || !this.form.modalidad
        || !this.form.fecha_inicio || !this.form.fecha_fin || !this.form.duracion_hrs) {
      this.notify.warning('Complete los campos obligatorios');
      return;
    }
    this.guardando.set(true);
    const payload = {
      docente_id:         this.docenteSeleccionado.value,
      nombre:             this.form.nombre,
      descripcion:        this.form.descripcion || null,
      institucion:        this.form.institucion,
      tipo_certificacion: this.form.tipo_certificacion,
      modalidad:          this.form.modalidad,
      fecha_inicio:       this.toDateStr(this.form.fecha_inicio),
      fecha_fin:          this.toDateStr(this.form.fecha_fin),
      duracion_hrs:       this.form.duracion_hrs,
      area_formacion:     this.form.area_formacion || null,
      folio_certificado:  this.form.folio_certificado || null,
      certificado_url:    this.form.certificado_url || null,
    };
    this.api.post<Capacitacion>('/capacitaciones', payload).subscribe({
      next: () => {
        this.guardando.set(false);
        this.dialogNueva = false;
        this.notify.success('Capacitación registrada');
        this.cargar();
      },
      error: (e: any) => { this.guardando.set(false); this.notify.error(e.error?.detail ?? 'Error al guardar'); },
    });
  }

  verDetalle(cap: Capacitacion) {
    this.seleccionada.set(cap);
    this.dialogDetalle = true;
  }

  validar(cap: Capacitacion) {
    this.api.post<Capacitacion>(`/capacitaciones/${cap.id}/validar`, null).subscribe({
      next: () => { this.notify.success('Capacitación validada'); this.cargar(); },
      error: (e: any) => this.notify.error(e.error?.detail ?? 'Error al validar'),
    });
  }

  eliminar(cap: Capacitacion) {
    this.api.delete(`/capacitaciones/${cap.id}`).subscribe({
      next: () => { this.notify.success('Capacitación eliminada'); this.cargar(); },
      error: (e: any) => this.notify.error(e.error?.detail ?? 'Error al eliminar'),
    });
  }

  verPdf(url: string) { window.open(url, '_blank'); }

  modalidadSeverity(modalidad: string): 'info' | 'success' | 'warn' {
    const map: Record<string, 'info' | 'success' | 'warn'> = {
      PRESENCIAL: 'info', EN_LINEA: 'success', HIBRIDA: 'warn',
    };
    return map[modalidad] ?? 'info';
  }

  tipoLabel(tipo: string): string {
    return this.tipoOpts.find(o => o.value === tipo)?.label ?? tipo;
  }

  private resetForm(): CapacitacionForm {
    return {
      nombre: '', descripcion: '', institucion: '',
      tipo_certificacion: 'CURSO', modalidad: 'PRESENCIAL',
      fecha_inicio: null, fecha_fin: null, duracion_hrs: 0,
      area_formacion: '', folio_certificado: '', certificado_url: '',
    };
  }

  private toDateStr(d: Date | null): string {
    if (!d) return '';
    return d.toISOString().split('T')[0];
  }
}

import { Component, inject, signal, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { TableModule } from 'primeng/table';
import { ButtonModule } from 'primeng/button';
import { TagModule } from 'primeng/tag';
import { DialogModule } from 'primeng/dialog';
import { SelectModule } from 'primeng/select';
import { InputTextModule } from 'primeng/inputtext';
import { AutoCompleteModule } from 'primeng/autocomplete';
import { TooltipModule } from 'primeng/tooltip';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { ApexNotificationService, ApexDynamicActionTargetDirective, ApexDynamicActionService } from 'apex-component-library';
import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';

interface Certificado {
  id: string;
  folio: string;
  tipo_certificado: string;
  nivel_educativo: string;
  grado_completado: string | null;
  promedio_final: number | null;
  fecha_emision: string;
  vigente: boolean;
  estado_firma: 'PENDIENTE' | 'FIRMADO' | 'REVOCADO';
  fecha_firma: string | null;
  verificable_url: string | null;
  nombre_alumno: string;
  nombre_ciclo: string;
  blockchain_tx: string | null;
  blockchain_status: 'PENDIENTE' | 'ANCLADO' | 'FALLIDO' | null;
  fecha_anclaje: string | null;
  blockchain_network: string | null;
}

interface AlumnoOpt { id: string; label: string; }

/**
 * Emisión y verificación de certificados digitales con firma Ed25519.
 * Gestiona el ciclo PENDIENTE → FIRMADO → REVOCADO y el anclaje opcional
 * en blockchain para certificados de término de nivel. Los certificados
 * son verificables públicamente vía `/verificar/:folio`. Integra
 * `ApexDynamicActionService` para acciones contextuales. Requiere nivelAcceso ≥ 4.
 */
@Component({
  selector: 'app-certificados',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    TableModule, ButtonModule, TagModule, DialogModule,
    SelectModule, InputTextModule, AutoCompleteModule, TooltipModule,
    ProgressSpinnerModule, ApexDynamicActionTargetDirective,
  ],
  template: `
    <div class="page-header">
      <div>
        <h2>Certificados Digitales</h2>
        <p class="subtitle">Emisión y verificación Ed25519 · Instituto Nevadi</p>
      </div>
      @if (esAdmin()) {
        <div style="display:flex;gap:.5rem">
          <p-button label="Emitir certificado" icon="pi pi-plus-circle"
            (onClick)="abrirEmitir()" />
          <p-button label="Gestión de llaves" icon="pi pi-key"
            severity="secondary" [outlined]="true"
            (onClick)="showLlaves.set(true)" />
        </div>
      }
    </div>

    <!-- ── KPI strip ── -->
    <div class="kpi-strip">
      <div class="kpi-card">
        <span class="kpi-val">{{ total() }}</span>
        <span class="kpi-lbl">Total emitidos</span>
      </div>
      <div class="kpi-card kpi-verde">
        <span class="kpi-val">{{ firmados() }}</span>
        <span class="kpi-lbl">Firmados Ed25519</span>
      </div>
      <div class="kpi-card kpi-amber">
        <span class="kpi-val">{{ pendientes() }}</span>
        <span class="kpi-lbl">Pendientes firma</span>
      </div>
    </div>

    <!-- ── Tabla ── -->
    <p-table
      [value]="certificados()"
      [loading]="cargando()"
      [paginator]="true" [rows]="20" [rowsPerPageOptions]="[10,20,50]"
      [sortMode]="'single'"
      styleClass="p-datatable-sm p-datatable-striped apex-grid">
      <ng-template pTemplate="header">
        <tr>
          <th pSortableColumn="folio">Folio <p-sortIcon field="folio" /></th>
          <th pSortableColumn="nombre_alumno">Alumno <p-sortIcon field="nombre_alumno" /></th>
          <th pSortableColumn="tipo_certificado">Tipo <p-sortIcon field="tipo_certificado" /></th>
          <th>Nivel / Grado</th>
          <th>Ciclo</th>
          <th>Promedio</th>
          <th pSortableColumn="fecha_emision">Fecha <p-sortIcon field="fecha_emision" /></th>
          <th>Estado Firma</th>
          <th>Anclaje Blockchain</th>
          <th class="col-acciones">Acciones</th>
        </tr>
      </ng-template>
      <ng-template pTemplate="body" let-c>
        <tr>
          <td><code style="font-size:.8rem">{{ c.folio }}</code></td>
          <td>{{ c.nombre_alumno }}</td>
          <td>{{ tipoLabel(c.tipo_certificado) }}</td>
          <td>{{ c.nivel_educativo }}{{ c.grado_completado ? ' · ' + c.grado_completado : '' }}</td>
          <td>{{ c.nombre_ciclo }}</td>
          <td>{{ c.promedio_final ? c.promedio_final : '—' }}</td>
          <td>{{ c.fecha_emision | date:'dd/MM/yyyy' }}</td>
          <td>
            <p-tag
              [value]="estadoLabel(c.estado_firma)"
              [severity]="estadoSeverity(c.estado_firma)"
              [pTooltip]="c.fecha_firma ? 'Firmado: ' + (c.fecha_firma | date:'dd/MM/yyyy HH:mm') : ''"
            />
          </td>
          <td>
            @if (c.blockchain_status === 'ANCLADO') {
              <a [href]="blockchainLink(c.blockchain_tx, c.blockchain_network)" target="_blank" style="text-decoration:none">
                <p-tag value="ANCLADO" severity="success" icon="pi pi-link" pTooltip="Ver transacción en explorador" />
              </a>
            } @else if (c.blockchain_status === 'PENDIENTE') {
              <p-tag value="PENDIENTE" severity="warn" icon="pi pi-spin pi-spinner" pTooltip="Procesando anclaje en segundo plano" />
            } @else if (c.blockchain_status === 'FALLIDO') {
              <p-tag value="FALLIDO" severity="danger" icon="pi pi-exclamation-triangle" pTooltip="Error al anclar en blockchain" />
            } @else {
              <span class="text-muted">—</span>
            }
          </td>
          <td class="acciones-cell">
            <p-button icon="pi pi-file-pdf" [text]="true" severity="secondary" size="small"
              pTooltip="Descargar PDF"
              data-testid="btn-descargar-pdf"
              [loading]="descargando() === c.id"
              (onClick)="descargarPdf(c)" />
            @if (c.verificable_url) {
              <p-button icon="pi pi-external-link" [text]="true" severity="info" size="small"
                pTooltip="Verificar en línea" (onClick)="abrirVerificar(c.folio)" />
            }
            @if (esAdmin() && c.estado_firma === 'PENDIENTE') {
              <p-button icon="pi pi-sign-in" [text]="true" severity="success" size="small"
                pTooltip="Firmar ahora"
                [loading]="firmando() === c.id"
                (onClick)="firmarCertificado(c)" />
            }
          </td>
        </tr>
      </ng-template>
      <ng-template pTemplate="emptymessage">
        <tr><td colspan="10" style="text-align:center;padding:2rem;color:var(--text-color-secondary)">
          Sin certificados emitidos
        </td></tr>
      </ng-template>
    </p-table>

    <!-- ── Dialog emitir ── -->
    <p-dialog
      [visible]="showEmitir()" (visibleChange)="showEmitir.set($event)"
      header="Emitir Certificado Digital"
      [modal]="true" [style]="{width:'480px'}">
      <div class="form-grid">
        <div class="form-row">
          <label>Alumno *</label>
          <p-autoComplete
            [(ngModel)]="alumnoQuery"
            [suggestions]="alumnoOpts()"
            (completeMethod)="buscarAlumnos($event.query)"
            (onSelect)="onAlumnoSelect($event.value)"
            field="label" [minLength]="2"
            placeholder="Nombre o matrícula..."
            styleClass="w-full" />
        </div>
        <div class="form-row">
          <label>Tipo *</label>
          <p-select [(ngModel)]="emitirForm.tipo_certificado"
            [options]="tiposOpts" optionLabel="label" optionValue="value"
            (onChange)="onTipoChange()"
            styleClass="w-full" />
        </div>
        <div class="form-row" [apexDATarget]="'grado-row'">
          <label>Grado completado</label>
          <input pInputText [(ngModel)]="emitirForm.grado_completado"
            placeholder="ej. 6° Primaria" class="w-full" />
        </div>
        <div class="form-row" [apexDATarget]="'promedio-row'">
          <label>Promedio final</label>
          <input pInputText type="number" [(ngModel)]="emitirForm.promedio_final"
            placeholder="ej. 9.2" class="w-full" />
        </div>
      </div>
      <div class="form-note">
        <i class="pi pi-info-circle"></i>
        El certificado se firma automáticamente con Ed25519 si la llave está configurada.
        Se genera PDF con QR de verificación.
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true"
          (onClick)="showEmitir.set(false)" />
        <p-button label="Emitir y descargar PDF" icon="pi pi-file-pdf"
          [loading]="emitiendo()"
          (onClick)="emitirCertificado()" />
      </ng-template>
    </p-dialog>

    <!-- ── Dialog gestión llaves ── -->
    <p-dialog
      [visible]="showLlaves()" (visibleChange)="showLlaves.set($event)"
      header="Gestión de Llaves de Firma Ed25519"
      [modal]="true" [style]="{width:'560px'}">
      <div class="llave-info">
        @if (llaveActiva()) {
          <div class="llave-card llave-activa">
            <div class="llave-header">
              <i class="pi pi-key" style="color:var(--green-500)"></i>
              <strong>{{ llaveActiva()!.nombre }}</strong>
              <span class="llave-badge">ACTIVA</span>
            </div>
            <div class="llave-pub">
              <span class="llave-pub-label">Clave pública (base64):</span>
              <code class="llave-pub-val">{{ llaveActiva()!.clave_publica_b64 }}</code>
            </div>
            <div class="llave-meta">
              Activada: {{ llaveActiva()!.fecha_activacion | date:'dd/MM/yyyy' }}
            </div>
            @if (!llaveActiva()!.configurada_en_env) {
              <div class="llave-warn">
                <i class="pi pi-exclamation-triangle"></i>
                La llave privada NO está en .env — los certificados no se podrán firmar.
              </div>
            }
          </div>
        } @else {
          <div class="llave-empty">
            <i class="pi pi-exclamation-circle" style="font-size:2rem;color:var(--yellow-500)"></i>
            <p>No hay llave de firma registrada.</p>
            <p class="llave-hint">Genera un par Ed25519 y registra la llave pública.</p>
          </div>
        }
      </div>

      <div class="llave-actions">
        <p-button label="Generar nuevo par de llaves" icon="pi pi-refresh"
          severity="warn" [outlined]="true"
          [loading]="generandoLlave()"
          (onClick)="generarLlave()" />
        @if (nuevaLlave()) {
          <div class="nueva-llave-box">
            <div class="nueva-llave-aviso">
              <i class="pi pi-shield" style="color:var(--red-500)"></i>
              <strong>Copia la llave privada AHORA. No se mostrará de nuevo.</strong>
            </div>
            <div class="nueva-llave-item">
              <label>FIRMA_CLAVE_PRIVADA_HEX (para .env):</label>
              <code>{{ nuevaLlave()!.privada_hex }}</code>
            </div>
            <div class="nueva-llave-item">
              <label>Clave pública (base64):</label>
              <code>{{ nuevaLlave()!.publica_b64 }}</code>
            </div>
            <p-button label="Registrar esta llave pública" icon="pi pi-save"
              (onClick)="registrarLlave()" />
          </div>
        }
      </div>

      <ng-template pTemplate="footer">
        <p-button label="Cerrar" severity="secondary" [text]="true"
          (onClick)="showLlaves.set(false)" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .page-header { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:1.5rem; }
    .page-header h2 { margin:0; font-size:1.4rem; }
    .subtitle { color:var(--text-color-secondary); font-size:.85rem; margin-top:.2rem; }

    .kpi-strip { display:flex; gap:1rem; margin-bottom:1.5rem; flex-wrap:wrap; }
    .kpi-card { background:var(--surface-0); border:1px solid var(--surface-200); border-radius:8px;
      padding:.75rem 1.5rem; min-width:130px; text-align:center; }
