import { Component, inject, OnInit, signal, computed, effect } from '@angular/core';
import { CommonModule, DatePipe } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { TagModule } from 'primeng/tag';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';
import { DialogModule } from 'primeng/dialog';
import { SelectModule } from 'primeng/select';
import { InputTextModule } from 'primeng/inputtext';
import { TextareaModule } from 'primeng/textarea';
import { TooltipModule } from 'primeng/tooltip';
import { CheckboxModule } from 'primeng/checkbox';
import { MessageModule } from 'primeng/message';

import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';
import { ExportService, ExportColumn } from '../../core/services/export.service';

type TagSeverity = 'success' | 'info' | 'warn' | 'danger' | 'secondary' | 'contrast' | undefined;

interface Comunicado {
  id: string;
  titulo: string;
  contenido: string;
  tipo_comunicado: string;
  plantel_id: string | null;
  requiere_acuse: boolean;
  fecha_publicacion: string;
  fecha_vencimiento: string | null;
  total_acuses: number;
  acusado_por_mi: boolean;
  creado_por_nombre: string;
}

const TIPO_SEV: Record<string, TagSeverity> = {
  GENERAL: 'info',
  URGENTE: 'danger',
  ACADEMICO: 'success',
  ADMINISTRATIVO: 'secondary',
  SALUD: 'warn',
};

const TIPOS = [
  { label: 'General',        value: 'GENERAL' },
  { label: 'Urgente',        value: 'URGENTE' },
  { label: 'Académico',      value: 'ACADEMICO' },
  { label: 'Administrativo', value: 'ADMINISTRATIVO' },
  { label: 'Salud',          value: 'SALUD' },
];

/**
 * Sistema de comunicados institucionales con acuse de recibo.
 * Soporta tipos GENERAL, URGENTE, ACADÉMICO, ADMINISTRATIVO y SALUD con
 * severidades visuales diferenciadas. Los comunicados con `requiere_acuse`
 * registran quién confirmó lectura y cuándo. Permite publicar a toda la
 * institución o a un plantel específico. Requiere nivelAcceso ≥ 4 para crear;
 * nivelAcceso ≥ 3 puede leer y acusar recibo.
 */
@Component({
  selector: 'app-comunicados',
  standalone: true,
  imports: [
    CommonModule, DatePipe, FormsModule,
    ButtonModule, TagModule, DialogModule,
    SelectModule, InputTextModule, TextareaModule,
    TooltipModule, CheckboxModule, MessageModule,
    InteractiveGridComponent,
  ],
  template: `
    <div class="page-header">
      <div>
        <h2 class="page-title">Comunicados y Circulares</h2>
        <p class="page-subtitle">Mensajes institucionales del plantel</p>
      </div>
      <div class="page-actions">
        <p-button icon="pi pi-download" label="CSV"   severity="secondary" [text]="true" (onClick)="exportCSV()" />
        <p-button icon="pi pi-file-excel" label="Excel" severity="secondary" [text]="true" (onClick)="exportXLSX()" />
        <p-button icon="pi pi-plus" label="Nuevo comunicado" (onClick)="abrirNuevo()" />
      </div>
    </div>

    <!-- Filtro rápido tipo -->
    <div class="filter-bar" style="margin-bottom:1rem; display:flex; gap:.5rem; flex-wrap:wrap;">
      @for (t of tiposConTodos; track t.value) {
        <p-button
          [label]="t.label"
          [outlined]="filtroTipo !== t.value"
          size="small"
          severity="secondary"
          (onClick)="filtroTipo = t.value; cargar()"
        />
      }
    </div>

    <app-interactive-grid
      [data]="comunicadosFlat()"
      [columns]="comunicadoColumns"
      [loading]="loading()"
      [showDelete]="false"
      (rowSelected)="onComunicadoSelected($event)"
    />

    <!-- Detalle del comunicado seleccionado -->
    @if (comunicadoSeleccionado()) {
      <div class="comunicado-body" style="margin-top:1rem; border:1px solid var(--surface-200); border-radius:8px;">
        <div style="display:flex; justify-content:space-between; align-items:center; padding:.5rem .75rem; border-bottom:1px solid var(--surface-200);">
          <strong>{{ comunicadoSeleccionado()!.titulo }}</strong>
          <div style="display:flex; gap:.4rem; align-items:center;">
            @if (!comunicadoSeleccionado()!.acusado_por_mi && comunicadoSeleccionado()!.requiere_acuse) {
              <p-button icon="pi pi-check" label="Acusar recibo" size="small" severity="success"
                (onClick)="acusarRecibo(comunicadoSeleccionado()!)" />
            }
            <p-button icon="pi pi-times" [text]="true" size="small" severity="secondary"
              ariaLabel="Cerrar comunicado" (onClick)="comunicadoSeleccionado.set(null)" />
          </div>
        </div>
        <pre class="comunicado-contenido">{{ comunicadoSeleccionado()!.contenido }}</pre>
        <div class="comunicado-meta">
          <span>Publicado por: <strong>{{ comunicadoSeleccionado()!.creado_por_nombre }}</strong></span>
          @if (comunicadoSeleccionado()!.fecha_vencimiento) {
            <span>Vigente hasta: <strong>{{ comunicadoSeleccionado()!.fecha_vencimiento | date:'dd/MM/yyyy' }}</strong></span>
          }
          @if (comunicadoSeleccionado()!.acusado_por_mi) {
            <p-tag value="Ya acusé recibo" severity="success" icon="pi pi-check" />
          }
        </div>
      </div>
    }

    <!-- Dialog nuevo comunicado -->
    <p-dialog
      header="Nuevo comunicado"
      [visible]="showDialog()" (visibleChange)="showDialog.set($event)"
      [modal]="true"
      [style]="{width:'600px'}"
      [closable]="true"
    >
      <div class="form-grid">
        <div class="form-field full">
          <label>Título *</label>
          <input pInputText [(ngModel)]="form.titulo" placeholder="Título del comunicado" style="width:100%"
            [class.p-invalid]="cIntento() && !form.titulo.trim()" />
          @if (cIntento() && !form.titulo.trim()) {
            <small class="field-error">El título es obligatorio</small>
          }
        </div>
        <div class="form-field">
          <label>Tipo</label>
          <p-select [options]="tipos" [(ngModel)]="form.tipo_comunicado"
                    optionLabel="label" optionValue="value" styleClass="w-full" 
 [filter]="true" filterPlaceholder="Buscar..."/>
        </div>
        <div class="form-field">
          <label>Fecha vencimiento</label>
          <input pInputText type="date" [(ngModel)]="form.fecha_vencimiento" style="width:100%" />
        </div>
        <div class="form-field full">
          <label>Contenido *</label>
          <textarea pTextarea [(ngModel)]="form.contenido"
                    rows="6" style="width:100%; resize:vertical"
                    placeholder="Texto del comunicado..."
                    [class.p-invalid]="cIntento() && !form.contenido.trim()"></textarea>
          @if (cIntento() && !form.contenido.trim()) {
            <small class="field-error">El contenido es obligatorio</small>
          }
        </div>
        <div class="form-field full" style="display:flex; align-items:center; gap:.5rem;">
          <p-checkbox [(ngModel)]="form.requiere_acuse" [binary]="true" inputId="acuse" />
          <label for="acuse">Requiere acuse de recibo</label>
        </div>
      </div>

      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true" (onClick)="showDialog.set(false)" />
        <p-button label="Publicar" icon="pi pi-send" (onClick)="publicar()" [loading]="saving()" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .page-header    { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:1.25rem; }
    .page-title     { font-size:1.25rem; font-weight:700; margin:0 0 .2rem; }
    .page-subtitle  { color:var(--text-color-secondary); font-size:.82rem; margin:0; }
    .page-actions   { display:flex; gap:.5rem; align-items:center; flex-wrap:wrap; }

    .acuse-badge {
      display:inline-flex; align-items:center; justify-content:center;
      background:var(--surface-200); border-radius:12px;
      font-size:.75rem; padding:0 .5rem; min-width:1.5rem; height:1.4rem;
    }

    .comunicado-leido td { opacity: 0.7; }

    .row-expansion td { background: var(--surface-50); }

    .comunicado-body {
      padding: .75rem 1rem;
    }
    .comunicado-contenido {
      font-family: inherit; white-space: pre-wrap; word-break: break-word;
      background: var(--surface-100); border-radius: 6px; padding: .75rem;
      font-size: .875rem; margin: 0 0 .75rem; max-height: 200px; overflow-y: auto;
    }
    .comunicado-meta {
      display: flex; gap: 1.5rem; align-items: center; font-size: .8rem;
      color: var(--text-color-secondary);
    }

    .form-grid   { display:grid; grid-template-columns:1fr 1fr; gap:.85rem; }
    .form-field  { display:flex; flex-direction:column; gap:.3rem; font-size:.875rem; }
    .form-field.full { grid-column: 1 / -1; }
    label { font-weight:500; font-size:.82rem; }
    .field-error { color: var(--red-600, #dc2626); font-size: .78rem; }
  `],
})
export class ComunicadosComponent implements OnInit {
  private readonly api    = inject(ApiService);
  readonly ctx            = inject(ContextService);
  private readonly exporter = inject(ExportService);

  comunicados = signal<Comunicado[]>([]);
  loading     = signal(false);
  saving      = signal(false);
  showDialog  = signal(false);
  cIntento    = signal(false);
  comunicadoSeleccionado = signal<Comunicado | null>(null);
  // expandedRows kept for potential future use but not used with interactive grid
  expandedRows: Record<string, boolean> = {};
  filtroTipo  = '';

  readonly comunicadoColumns: ColumnConfig[] = [
    { field: 'tipo_comunicado',   header: 'Tipo',   sortable: true, filterable: true, width: '130px' },
    { field: 'tituloDisplay',     header: 'Título', sortable: true, filterable: true },
    { field: 'plantelDisplay',    header: 'Plantel',sortable: true, filterable: true, width: '80px' },
    { field: 'fechaPublicacion',  header: 'Fecha',  sortable: true, filterable: false, width: '100px' },
    { field: 'total_acuses',      header: 'Acuses', sortable: true, filterable: false, width: '80px' },
    { field: 'acusadoLabel',      header: 'Acuse',  sortable: true, filterable: true,  width: '80px' },
  ];

  readonly comunicadosFlat = computed(() =>
    this.comunicados().map(c => ({
      ...c,
      tituloDisplay: c.titulo + (c.requiere_acuse && !c.acusado_por_mi ? ' ⚠' : ''),
      plantelDisplay: c.plantel_id ? 'Plantel' : 'Todos',
      fechaPublicacion: c.fecha_publicacion ? new Date(c.fecha_publicacion).toLocaleDateString('es-MX') : '',
      acusadoLabel: c.acusado_por_mi ? 'Sí' : (c.requiere_acuse ? 'Pendiente' : '—'),
    }))
  );

  onComunicadoSelected(row: any): void {
    // Find the original Comunicado with full data
    const original = this.comunicados().find(c => c.id === row.id) ?? null;
    this.comunicadoSeleccionado.set(original);
  }

  tipos = TIPOS;
  tiposConTodos = [{ label: 'Todos', value: '' }, ...TIPOS];

  form = this.emptyForm();

  private readonly exportCols: ExportColumn[] = [
    { field: 'tipo_comunicado', header: 'Tipo' },
    { field: 'titulo',          header: 'Título' },
    { field: 'fecha_publicacion', header: 'Fecha publicación', format: (v: string) => v ? new Date(v).toLocaleDateString('es-MX') : '' },
    { field: 'total_acuses',    header: 'Acuses' },
    { field: 'creado_por_nombre', header: 'Publicado por' },
    { field: 'requiere_acuse',  header: 'Requiere acuse', format: (v: boolean) => v ? 'Sí' : 'No' },
  ];

  constructor() {
    // Recargar cuando cambia el plantel en el contexto global.
    effect(() => {
      this.ctx.plantel();
      this.cargar();
    });
  }

  ngOnInit(): void {
    // Carga reactiva via effect en constructor.
  }

  cargar(): void {
    this.loading.set(true);
    const params: Record<string, string | boolean> = { solo_vigentes: false };
    const plantel = this.ctx.plantel();
    if (plantel) params['plantel_id'] = plantel.id;
    if (this.filtroTipo) params['tipo'] = this.filtroTipo;

    this.api.get<Comunicado[]>('/comunicados', params).subscribe({
      next: (r) => { this.comunicados.set(r); this.loading.set(false); },
      error: () => this.loading.set(false),
    });
  }

  tipoSev(tipo: string): TagSeverity { return TIPO_SEV[tipo] ?? 'info'; }

  toggleExpand(id: string): void {
    this.expandedRows = this.expandedRows[id] ? {} : { [id]: true };
  }

  acusarRecibo(c: Comunicado): void {
    this.api.put<{ ok: boolean }>(`/comunicados/${c.id}/acusar`, {}).subscribe(() => {
      this.comunicados.update(list => list.map(x => x.id === c.id ? { ...x, acusado_por_mi: true } : x));
    });
  }

  abrirNuevo(): void { this.form = this.emptyForm(); this.cIntento.set(false); this.showDialog.set(true); }

  publicar(): void {
    this.cIntento.set(true);
    if (!this.form.titulo.trim() || !this.form.contenido.trim()) return;
    this.saving.set(true);
    const plantel = this.ctx.plantel();
    const payload = {
      ...this.form,
      plantel_id: plantel?.id ?? null,
      fecha_vencimiento: this.form.fecha_vencimiento || null,
    };
    this.api.post('/comunicados', payload).subscribe({
      next: () => { this.showDialog.set(false); this.saving.set(false); this.cargar(); },
      error: () => this.saving.set(false),
    });
  }

  exportCSV(): void  { this.exporter.toCSV(this.comunicados(), this.exportCols, 'comunicados'); }
  exportXLSX(): void { this.exporter.toXLSX(this.comunicados(), this.exportCols, 'Comunicados', 'comunicados'); }

  private emptyForm() {
    return { titulo: '', contenido: '', tipo_comunicado: 'GENERAL', requiere_acuse: false, fecha_vencimiento: '' };
  }
}

import { Component, OnInit, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/services/api.service';
import { ButtonModule } from 'primeng/button';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { ToastModule } from 'primeng/toast';
import { CheckboxModule } from 'primeng/checkbox';
import { TooltipModule } from 'primeng/tooltip';
import { MessageService } from 'primeng/api';
import { ApexNotificationService } from 'apex-component-library';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';

interface Condicion {
  id: string;
  alumno_id: string;
  numero_control: string;
  alumno_nombre: string;
  tipo_condicion: string;
  descripcion: string;
  medicacion_nombre: string | null;
  dosis: string | null;
  frecuencia: string | null;
  alergias: string | null;
  medico_responsable: string | null;
  telefono_medico: string | null;
  activa: boolean;
  fecha_creacion: string;
}

type TagSev = 'success' | 'info' | 'warn' | 'danger' | 'secondary' | 'contrast';

interface AlertaEmergencia {
  tipo_condicion: string;
  descripcion: string;
  medicacion_nombre: string | null;
  dosis: string | null;
  frecuencia: string | null;
  alergias: string | null;
  medico_responsable: string | null;
  telefono_medico: string | null;
  alumno_nombre: string;
  contacto_emergencia: string | null;
  tel_emergencia: string | null;
}

const TIPOS = [
  { label: 'Epilepsia',             value: 'EPILEPSIA' },
  { label: 'Diabetes',              value: 'DIABETES' },
  { label: 'Asma',                  value: 'ASMA' },
  { label: 'Alergia',               value: 'ALERGIA' },
  { label: 'Cardiaca',              value: 'CARDIACA' },
  { label: 'Hipertensión',          value: 'HIPERTENSION' },
  { label: 'Discapacidad Visual',   value: 'DISCAPACIDAD_VISUAL' },
  { label: 'Discapacidad Auditiva', value: 'DISCAPACIDAD_AUDITIVA' },
  { label: 'Otra',                  value: 'OTRA' },
];

/**
 * Registro de condiciones crónicas de salud de alumnos (PII sensible bajo LFPDPPP).
 * Almacena diagnósticos, medicación, alergias y datos del médico responsable.
 * Expone una vista de alerta de emergencia para uso inmediato por personal escolar.
 * El acceso está restringido a nivelAcceso ≥ 4; los datos se transmiten solo por
 * HTTPS y se acceden únicamente en contexto del plantel propio (anti-IDOR).
 */
@Component({
  selector: 'app-condiciones-cronicas',
  standalone: true,
  imports: [
    CommonModule, FormsModule, ButtonModule, DialogModule,
    InputTextModule, SelectModule, ToastModule, CheckboxModule, TooltipModule,
    InteractiveGridComponent,
  ],
  providers: [MessageService],
  template: `
    <p-toast />
    <div class="apex-page">
      <div class="apex-toolbar">
        <h2 class="apex-title">Condiciones Crónicas de Alumnos</h2>
        <div class="apex-toolbar-actions">
          <input pInputText [(ngModel)]="busquedaAlumnoId" placeholder="UUID del alumno…" style="width:260px"
            (keyup.enter)="cargar()" />
          <p-button label="Buscar" icon="pi pi-search" size="small" (onClick)="cargar()" />
          <p-button label="Ver alerta" icon="pi pi-bell" size="small" severity="warn"
            (onClick)="verAlerta()" [disabled]="!busquedaAlumnoId" pTooltip="Pantalla de emergencia" />
          <p-button label="Nueva condición" icon="pi pi-plus" size="small" (onClick)="abrirNueva()" />
        </div>
      </div>

      <app-interactive-grid
        [data]="condicionesFlat()"
        [columns]="condicionesColumns"
        [loading]="cargando()"
        [showDelete]="true"
        (rowSelected)="abrirEdicion($event)"
        (rowDeleted)="eliminar($event)"
      />
    </div>

    <!-- Dialog: Crear/Editar -->
    <p-dialog [header]="editandoId ? 'Editar Condición' : 'Nueva Condición Crónica'"
      [(visible)]="dialogForm" [modal]="true" [style]="{width:'580px'}" [draggable]="false">
      <div class="grid grid-cols-2 gap-3 p-3">
        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">UUID del Alumno *</label>
          <input pInputText [(ngModel)]="form.alumno_id" [disabled]="!!editandoId"
            placeholder="uuid del alumno" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Tipo de Condición *</label>
          <p-select [options]="tipos" optionLabel="label" optionValue="value"
            [(ngModel)]="form.tipo_condicion" placeholder="Seleccionar…" />
        </div>
        <div class="flex flex-col gap-1 items-center justify-end">
          <label class="text-sm font-medium">¿Activa?</label>
          <p-checkbox [(ngModel)]="form.activa" [binary]="true" />
        </div>
        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Descripción *</label>
          <input pInputText [(ngModel)]="form.descripcion" placeholder="Descripción clínica…" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Medicación</label>
          <input pInputText [(ngModel)]="form.medicacion_nombre" placeholder="Nombre del medicamento" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Dosis</label>
          <input pInputText [(ngModel)]="form.dosis" placeholder="Ej: 10mg" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Frecuencia</label>
          <input pInputText [(ngModel)]="form.frecuencia" placeholder="Ej: Cada 8 horas" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Alergias</label>
          <input pInputText [(ngModel)]="form.alergias" placeholder="Alergias conocidas" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Médico Responsable</label>
          <input pInputText [(ngModel)]="form.medico_responsable" placeholder="Dr. Nombre Apellido" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Teléfono Médico</label>
          <input pInputText [(ngModel)]="form.telefono_medico" placeholder="722-000-0000" />
        </div>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="dialogForm=false" />
        <p-button [label]="editandoId ? 'Guardar cambios' : 'Registrar condición'"
          icon="pi pi-save" [loading]="guardando()" (onClick)="guardar()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog: Alerta de emergencia (SB-007) -->
    <p-dialog header="⚠ ALERTA MÉDICA — EMERGENCIA" [(visible)]="dialogAlerta"
      [modal]="true" [style]="{width:'680px'}" [draggable]="false">
      @for (alerta of alertas(); track alerta.tipo_condicion) {
        <div class="alerta-card">
          <div class="alerta-tipo">{{ alerta.tipo_condicion }}</div>
          <div class="alerta-desc">{{ alerta.descripcion }}</div>
          @if (alerta.medicacion_nombre) {
            <div class="alerta-med">
              <strong>Medicación:</strong> {{ alerta.medicacion_nombre }} — {{ alerta.dosis }}
              ({{ alerta.frecuencia }})
            </div>
          }
          @if (alerta.alergias) {
            <div class="alerta-alergia"><strong>⚠ Alergias:</strong> {{ alerta.alergias }}</div>
          }
          @if (alerta.medico_responsable) {
            <div class="alerta-medico">
              <strong>Médico:</strong> {{ alerta.medico_responsable }} — {{ alerta.telefono_medico }}
            </div>
          }
          @if (alerta.contacto_emergencia) {
            <div class="alerta-contacto">
              <strong>Contacto emergencia:</strong> {{ alerta.contacto_emergencia }} —
              <a [href]="'tel:' + alerta.tel_emergencia" class="text-primary-600 font-bold">
                {{ alerta.tel_emergencia }}
              </a>
            </div>
          }
        </div>
      }
      @if (alertas().length === 0) {
        <p class="text-center text-gray-500 py-4">Sin condiciones activas para este alumno.</p>
      }
      <ng-template pTemplate="footer">
        <p-button label="Cerrar" (onClick)="dialogAlerta=false" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .apex-page { padding: 1rem; }
    .apex-toolbar { display:flex; align-items:center; justify-content:space-between; margin-bottom:1rem; flex-wrap:wrap; gap:.5rem; }
    .apex-title { margin:0; font-size:1.25rem; font-weight:600; }
    .apex-toolbar-actions { display:flex; gap:.5rem; align-items:center; flex-wrap:wrap; }
    .alerta-card { background:var(--red-50); border:2px solid var(--red-400); border-radius:8px; padding:1rem; margin-bottom:.75rem; }
    .alerta-tipo { font-size:1.1rem; font-weight:700; color:var(--red-700); margin-bottom:.5rem; }
    .alerta-desc { color:var(--text-color); margin-bottom:.5rem; }
    .alerta-med, .alerta-medico, .alerta-contacto { font-size:.9rem; margin-bottom:.25rem; }
    .alerta-alergia { background:var(--yellow-100); padding:.25rem .5rem; border-radius:4px; color:var(--yellow-800); font-size:.9rem; margin-bottom:.25rem; }
  `],
})
export class CondicionesCronicasComponent implements OnInit {
  private api = inject(ApiService);
  private notify = inject(ApexNotificationService);

  readonly condicionesColumns: ColumnConfig[] = [
    { field: 'alumno_str',   header: 'Alumno' },
    { field: 'tipo_condicion', header: 'Tipo',       width: '130px' },
    { field: 'descripcion_str', header: 'Descripción' },
    { field: 'medicacion_str', header: 'Medicación',  width: '160px' },
    { field: 'medico_str',   header: 'Médico',       width: '160px' },
    { field: 'estado_str',   header: 'Estado',       width: '90px' },
  ];

  readonly condicionesFlat = computed(() =>
    this.condiciones().map(c => ({
      ...c,
      alumno_str:      `${c.alumno_nombre} (${c.numero_control})`,
      descripcion_str: c.descripcion.length > 80 ? c.descripcion.slice(0, 80) + '…' : c.descripcion,
      medicacion_str:  c.medicacion_nombre ? `${c.medicacion_nombre} — ${c.dosis ?? ''} ${c.frecuencia ?? ''}`.trim() : '—',
      medico_str:      c.medico_responsable ? `${c.medico_responsable}${c.telefono_medico ? ' · ' + c.telefono_medico : ''}` : '—',
      estado_str:      c.activa ? 'Activa' : 'Inactiva',
    }))
  );

  condiciones = signal<Condicion[]>([]);
  alertas     = signal<AlertaEmergencia[]>([]);
  cargando    = signal(false);
  guardando   = signal(false);

  dialogForm   = false;
  dialogAlerta = false;
  busquedaAlumnoId = '';
  editandoId: string | null = null;
  tipos = TIPOS;

  form = {
    alumno_id: '', tipo_condicion: '', descripcion: '',
    medicacion_nombre: '', dosis: '', frecuencia: '',
    alergias: '', medico_responsable: '', telefono_medico: '',
    activa: true,
  };

  ngOnInit() { this.cargar(); }

  cargar() {
    this.cargando.set(true);
    const params: any = {};
    if (this.busquedaAlumnoId) params.alumno_id = this.busquedaAlumnoId;
    this.api.get<Condicion[]>('/condiciones-cronicas', params).subscribe({
      next: d => { this.condiciones.set(d); this.cargando.set(false); },
      error: () => { this.cargando.set(false); this.notify.error('Error al cargar condiciones'); },
    });
  }

  abrirNueva() {
    this.editandoId = null;
    this.form = { alumno_id: this.busquedaAlumnoId || '', tipo_condicion: '', descripcion: '',
      medicacion_nombre: '', dosis: '', frecuencia: '', alergias: '', medico_responsable: '',
      telefono_medico: '', activa: true };
    this.dialogForm = true;
  }

  abrirEdicion(c: Condicion) {
    this.editandoId = c.id;
    this.form = {
      alumno_id: c.alumno_id, tipo_condicion: c.tipo_condicion,
      descripcion: c.descripcion, medicacion_nombre: c.medicacion_nombre ?? '',
      dosis: c.dosis ?? '', frecuencia: c.frecuencia ?? '',
      alergias: c.alergias ?? '', medico_responsable: c.medico_responsable ?? '',
      telefono_medico: c.telefono_medico ?? '', activa: c.activa,
    };
    this.dialogForm = true;
  }

  guardar() {
    if (!this.form.alumno_id || !this.form.tipo_condicion || !this.form.descripcion) {
      this.notify.warning('Alumno, tipo y descripción son obligatorios');
      return;
    }
    this.guardando.set(true);
    const req$ = this.editandoId
      ? this.api.patch(`/condiciones-cronicas/${this.editandoId}`, this.form)
      : this.api.post('/condiciones-cronicas', this.form);
    req$.subscribe({
      next: () => { this.guardando.set(false); this.dialogForm = false; this.notify.success('Condición guardada'); this.cargar(); },
      error: e => { this.guardando.set(false); this.notify.error(e.error?.detail ?? 'Error al guardar'); },
    });
  }

  eliminar(c: Condicion) {
    if (!confirm(`¿Eliminar la condición ${c.tipo_condicion} de ${c.alumno_nombre}?`)) return;
    this.api.delete(`/condiciones-cronicas/${c.id}`).subscribe({
      next: () => { this.notify.success('Condición eliminada'); this.cargar(); },
      error: e => this.notify.error(e.error?.detail ?? 'Error'),
    });
  }

  verAlerta() {
    if (!this.busquedaAlumnoId) return;
    this.api.get<AlertaEmergencia[]>(`/condiciones-cronicas/alumno/${this.busquedaAlumnoId}/alerta`).subscribe({
      next: d => { this.alertas.set(d); this.dialogAlerta = true; },
      error: () => this.notify.error('Error al cargar alerta de emergencia'),
    });
  }

  tipoSev(tipo: string): TagSev {
    const map: Record<string, TagSev> = {
      EPILEPSIA: 'danger', DIABETES: 'warn', CARDIACA: 'danger',
      ASMA: 'warn', ALERGIA: 'warn', HIPERTENSION: 'warn',
      DISCAPACIDAD_VISUAL: 'info', DISCAPACIDAD_AUDITIVA: 'info', OTRA: 'secondary',
    };
    return map[tipo] ?? 'secondary';
  }
}

import { Component, inject, signal, computed, effect } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { CardModule } from 'primeng/card';
import { SkeletonModule } from 'primeng/skeleton';
import { ButtonModule } from 'primeng/button';
import { DividerModule } from 'primeng/divider';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { TooltipModule } from 'primeng/tooltip';
import { TagModule } from 'primeng/tag';
import { CheckboxModule } from 'primeng/checkbox';
import { MessageModule } from 'primeng/message';

import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';
import type { ResumenPlantel, Plantel } from '../../core/models';
import { ApexNotificationService, ApexChartComponent } from 'apex-component-library';

interface NivelStats {
  nivel_educativo_id: string;
  nombre_nivel: string;
  grupos_activos: number;
  grados: number;
}

interface PlantelStats {
  id: string;
  nombre_plantel: string;
  clave_ct: string | null;
  total_alumnos: number;
  total_profesores: number;
  total_grupos: number;
  niveles: NivelStats[];
}

interface DistribucionNivel {
  nombre_nivel: string;
  total_alumnos: number;
  total_grupos: number;
}

interface DashboardWidgets {
  welcome: boolean;
  kpi: boolean;
  miPlantel: boolean;
  planteles: boolean;
  chart: boolean;
  quickLinks: boolean;
}

const DEFAULT_WIDGETS: DashboardWidgets = {
  welcome: true,
  kpi: true,
  miPlantel: true,
  planteles: true,
  chart: true,
  quickLinks: true
};

const NIVEL_COLOR: Record<string, string> = {
  PRIMARIA: '#22c55e', SECUNDARIA: '#3b82f6', PREPARATORIA: '#a855f7',
};
const NIVEL_ICON: Record<string, string> = {
  PRIMARIA: 'pi-star', SECUNDARIA: 'pi-book', PREPARATORIA: 'pi-graduation-cap',
};

/**
 * Dashboard principal de ADES con KPIs institucionales y accesos rápidos.
 * Muestra estadísticas por plantel (alumnos, docentes, grupos, niveles) y
 * gráfica de distribución. Los widgets son configurables y persisten en
 * localStorage. Para AdminSistema (nivelAcceso 5) muestra todos los planteles;
 * para AdminPlantel (4) muestra solo su plantel vía `ContextService`.
