  <!-- PASO 3: Resumen final antes de confirmar -->
  @if (paso() === 3) {
    <div class="wizard-step">
      <div class="step-header">
        <i class="pi pi-file-check text-orange-500" style="font-size:2rem"></i>
        <div>
