  imports: [
    CommonModule, FormsModule, DatePipe,
    TableModule, ButtonModule, DialogModule, InputTextModule,
    SelectModule, TagModule, TextareaModule, TooltipModule,
    CardModule, TabsModule, ProgressBarModule,
  ],
  template: `
<div class="apex-page">
