            <input type="checkbox" id="fijadoCheck" [(ngModel)]="form.fijado" />
            <label for="fijadoCheck" style="font-size:0.8rem; cursor:pointer">
              Fijar este bloque (El motor automático no lo moverá)
            </label>
          </div>
        </div>
      </div>

      <ng-template pTemplate="footer">
        @if (editEntry) {
          <p-button label="Eliminar" icon="pi pi-trash" severity="danger" [text]="true"
            (onClick)="eliminar()" [loading]="guardando()" />
        }
        <p-button label="Cancelar" severity="secondary" [text]="true"
          (onClick)="showDialog.set(false)" />
        <p-button [label]="editEntry ? 'Guardar cambios' : 'Agregar al horario'"
          icon="pi pi-check" (onClick)="guardar()" [loading]="guardando()" />
      </ng-template>
    </p-dialog>


    <!-- ── Diálogo Asistente IA de Reglas ── -->
    <p-dialog
      [visible]="mostrarReglasIA()"
      (visibleChange)="mostrarReglasIA.set($event)"
      header="Asistente IA para Reglas de Horario"
      [modal]="true" [style]="{width:'600px'}" [draggable]="false">
      <div style="display:flex; flex-direction:column; gap: 1rem; margin-top: 1rem;">
        <p>Escribe la regla en lenguaje natural y la IA se encargará de traducirla.</p>
        <textarea pTextarea [(ngModel)]="reglaFraseIA" rows="3" placeholder="Ej: Educación Física no se imparte los viernes para el grupo 2B" style="width:100%"></textarea>
        <div style="display:flex; justify-content:flex-end;">
          <p-button label="Interpretar regla" icon="pi pi-sparkles" (onClick)="parsearReglaIA()" [loading]="parseandoRegla()" [disabled]="!reglaFraseIA()"></p-button>
        </div>

        @if (reglaInterpretada()) {
          <div style="background: var(--surface-ground); padding: 1rem; border-radius: 6px; border: 1px solid var(--surface-border);">
            <strong style="display:block; margin-bottom: 0.5rem; color: var(--primary-color);">Previsualización de regla:</strong>
            <pre style="margin:0; white-space: pre-wrap; font-size: 0.9rem;">{{ reglaInterpretada() | json }}</pre>
          </div>
        }
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true" (onClick)="mostrarReglasIA.set(false)" />
        <p-button label="Guardar Regla" icon="pi pi-check" (onClick)="guardarReglaIA()" [loading]="guardandoRegla()" [disabled]="!reglaInterpretada()" />
      </ng-template>
    </p-dialog>

    <div class="page-header">
      <div>
        <h2>Horarios</h2>
        <p class="subtitle">Vista semanal — {{ modoLabel() }}</p>
      </div>
      <div style="display:flex;gap:.5rem;align-items:center">
        <p-button
          label="Exportar XML aSc"
          icon="pi pi-download"
          severity="secondary"
          [text]="true"
          (onClick)="exportarASC()"
          [loading]="exportandoAsc()"
          [disabled]="!ctx.ciclo()"
          pTooltip="Exportar horarios al formato XML de aSc TimeTables"
        />
        @if (ctx.nivelAcceso() <= 3) {
          <label class="asc-reemplazar" pTooltip="Si está activo, reemplaza los horarios vigentes del ciclo antes de importar">
            <input type="checkbox" [(ngModel)]="reemplazarAsc" />
            <span>Reemplazar al importar</span>
          </label>
          <p-button
            label="Importar XML aSc"
            icon="pi pi-upload"
            severity="secondary"
            [text]="true"
            (onClick)="ascInput.click()"
            [loading]="importandoAsc()"
            [disabled]="!ctx.ciclo()"
            pTooltip="Importar la solución resuelta desde aSc TimeTables"
          />
          <input #ascInput type="file" accept=".xml" style="display:none"
                 (change)="onArchivoAscSeleccionado($event)" />
        }
        @if (selectedGrupo || selectedProfesor) {
          <p-button
            label="Nueva entrada"
            icon="pi pi-plus"
            (onClick)="abrirNuevo()"
          />
        }
      </div>
    </div>

    <div class="solver-panel">
      <div class="solver-head">
        <div>
          <h3>Timefold Solver</h3>
          <p>
            Corridas del optimizador para el plantel y ciclo actual. Desde aquí puedes lanzar una corrida,
            ver corridas recientes y revisar score, análisis y horarios generados.
          </p>
        </div>
        <div class="solver-actions">
          <p-button
            label="Refrescar corridas"
            icon="pi pi-refresh"
            severity="secondary"
            [text]="true"
            (onClick)="cargarCorridas()"
            [loading]="cargandoCorridas()"
            [disabled]="!puedeUsarSolver()"
          />
          <p-button
            label="Reglas IA"
            icon="pi pi-sparkles"
            severity="info"
            (onClick)="mostrarReglasIA.set(true)"
          />
          <p-button
            label="Ejecutar solver"
            icon="pi pi-play"
            (onClick)="iniciarSolver()"
            [loading]="ejecutandoSolver()"
            [disabled]="!puedeUsarSolver() || !ctx.plantel() || !ctx.ciclo()"
          />
        </div>
      </div>

      @if (!puedeUsarSolver()) {
        <div class="solver-empty">Selecciona un contexto con permisos de coordinación para ejecutar el solver.</div>
      } @else {
        <div class="solver-grid">
          <section class="solver-card">
            <div class="solver-card-head">
              <strong>Corridas recientes</strong>
              <span>{{ corridasSolver().length }}</span>
            </div>
            @if (corridasSolver().length === 0) {
              <div class="solver-empty small">No hay corridas registradas para este plantel.</div>
            } @else {
              <div class="solver-list">
                @for (corrida of corridasSolver(); track corrida.id) {
                  <button class="solver-list-item" type="button" (click)="seleccionarCorrida(corrida.id)">
                    <div>
                      <strong>{{ corrida.estado || 'SIN ESTADO' }}</strong>
                      <span>{{ corrida.score_text || 'sin score' }}</span>
                    </div>
                    <small>{{ corrida.fecha_creacion | slice:0:19 }}</small>
                  </button>
                }
              </div>
            }
          </section>

          <section class="solver-card solver-detail">
            <div class="solver-card-head">
              <strong>Detalle de corrida</strong>
              <div style="display:flex;gap:.5rem;align-items:center;flex-wrap:wrap;justify-content:flex-end">
                @if (esCorridaActiva(corridaDetalle())) {
                  <p-tag severity="warning" value="En vivo"></p-tag>
                }
                <span>{{ corridaDetalle()?.estado || 'sin selección' }}</span>
                <p-button
                  label="Abrir Excel"
                  icon="pi pi-external-link"
                  severity="secondary"
                  [text]="true"
                  [disabled]="!resultadoExcelDisponible()"
                  (onClick)="abrirResultadoExcel()"
                />
                <p-button
                  label="Fijar selección"
                  icon="pi pi-lock"
                  severity="secondary"
                  [text]="true"
                  [loading]="mutandoCorrida()"
                  [disabled]="horariosSeleccionados.size === 0 || !corridaDetalle()"
                  (onClick)="fijarSeleccionados()"
                />
                <p-button
                  label="Regenerar no fijados"
                  icon="pi pi-refresh"
                  [text]="true"
                  [loading]="mutandoCorrida()"
                  [disabled]="!corridaDetalle()"
                  (onClick)="regenerarSeleccionados()"
                />
              </div>
            </div>
            @if (!corridaDetalle()) {
              <div class="solver-empty small">Selecciona una corrida para ver score, análisis y horarios generados.</div>
            } @else {
              <div class="solver-summary">
                <div><label>Score</label><strong>{{ corridaDetalle()?.score_text || 'N/D' }}</strong></div>
                <div><label>Tiempo</label><strong>{{ corridaDetalle()?.tiempo_solving_ms ?? 'N/D' }} ms</strong></div>
                <div><label>Generados</label><strong>{{ corridaDetalle()?.horarios_generados ?? 0 }}</strong></div>
                <div><label>Versión</label><strong>{{ corridaDetalle()?.version || 'N/D' }}</strong></div>
              </div>

              <div class="solver-json-block">
                <label>Análisis de Restricciones</label>
                @if (corridaAnalysis()) {
                  <div class="reporte-checks" style="margin-top: 0.5rem">
                    @for (constraint of corridaAnalysis()?.constraints || []; track constraint.name) {
                      @if (constraint.score !== '0hard/0soft') {
                        <div class="reporte-check">
                          <div>
                            <strong>{{ constraint.name }}</strong>
                            <p>Penalización: {{ constraint.score }}</p>
                          </div>
                          <span [class.ok]="!constraint.score.includes('-')">
                            {{ constraint.score.includes('-') ? '❌' : '⚠️' }}
                          </span>
                        </div>
                      }
                    }
                    @if ((corridaAnalysis()?.constraints?.length || 0) === 0) {
                      <div class="solver-empty small">No hay violaciones de restricciones.</div>
                    }
                  </div>
                } @else {
                  <textarea pTextarea rows="8" readonly [ngModel]="corridaAnalysisText()"></textarea>
                }
              </div>

              @if ((corridaDetalle()?.horarios?.length ?? 0) > 0) {
                <div class="solver-table-wrap">
                  <table class="solver-table">
                    <thead>
                      <tr>
                        <th>Fijar</th>
                        <th>Día</th>
                        <th>Hora</th>
                        <th>Grupo</th>
                        <th>Materia</th>
                        <th>Docente</th>
                        <th>Aula</th>
                      </tr>
                    </thead>
                    <tbody>
                      @for (row of corridaDetalle()?.horarios || []; track row.id) {
                        <tr>
                          <td>
                            <input
                              type="checkbox"
                              [checked]="esHorarioSeleccionado(row.id) || !!row.fijado"
                              [disabled]="!!row.fijado"
                              (change)="alternarHorarioSeleccionado(row.id, $any($event.target).checked)"
                            />
                          </td>
                          <td>{{ labelDia(row.dia_semana) }}</td>
                          <td>{{ row.hora_inicio | slice:0:5 }}–{{ row.hora_fin | slice:0:5 }}</td>
                          <td>{{ row.nombre_grupo }}</td>
                          <td>{{ row.nombre_materia }}</td>
                          <td>{{ row.nombre_profesor }}</td>
                          <td>{{ row.nombre_aula }}</td>
                        </tr>
                      }
                    </tbody>
                  </table>
                </div>
              }
            }
          </section>
        </div>
      }
    </div>

    <div class="solver-panel">
      <div class="solver-head">
        <div>
          <h3>Análisis del Motor (Timefold)</h3>
          <p>
            Calcula las infracciones a las reglas del motor basándose en el horario actualmente activo.
          </p>
        </div>
        <div class="solver-actions">
          <p-button
            label="Verificar Reglas"
            icon="pi pi-shield"
            (onClick)="verificarHorarioBackend()"
            [loading]="cargandoReporte()"
            [disabled]="!ctx.plantel() || !ctx.ciclo()"
          />
        </div>
      </div>

      @if (!reporteVerificacion()) {
        <div class="solver-empty">Pulsa "Verificar Reglas" para analizar el horario actual con Timefold.</div>
      } @else {
        <div class="reporte-grid">
          <section class="solver-card" style="grid-column: 1 / -1">
            <div class="solver-card-head"><strong>Desglose de Restricciones</strong></div>
            <div class="reporte-table-wrap">
              <table class="solver-table">
                <thead>
                  <tr>
                    <th>Regla (Constraint)</th>
                    <th>Penalización Parcial</th>
                    <th>Incidencias (Matches)</th>
                  </tr>
                </thead>
                <tbody>
                  @for (c of reporteVerificacion()?.constraints; track c.name) {
                    <tr>
                      <td>{{ c.name }}</td>
                      <td style="color: var(--pink-500); font-weight:600">{{ c.score }}</td>
                      <td>{{ c.matchesCount }}</td>
                    </tr>
                  }
                  @if (!reporteVerificacion()?.constraints?.length) {
                    <tr>
                      <td colspan="3" style="text-align:center; padding:2rem; color:var(--text-secondary)">
                        No hay penalizaciones. ¡El horario es 100% óptimo!
                      </td>
                    </tr>
                  }
                </tbody>
              </table>
            </div>
          </section>
        </div>
      }
    </div>

    <!-- Controles — la cascada plantel→nivel→grado→grupo vive en el topbar -->
    <div class="filter-bar">
      <p-selectButton
        [options]="modoOpts"
        [(ngModel)]="modo"
        optionLabel="label"
        optionValue="value"
        (onChange)="onModoChange()"
      />

      @if (modo === 'profesor') {
        <p-select
          [options]="profesores()"
          [(ngModel)]="selectedProfesor"
          optionLabel="_label"
          placeholder="Seleccionar docente..."
          (onChange)="cargar()"
          [showClear]="true"
          [filter]="true" filterPlaceholder="Buscar..."/>
      }
    </div>

    <!-- ── Grid semanal ── -->
    @if ((modo === 'grupo' && !selectedGrupoId) || (modo === 'profesor' && !selectedProfesor)) {
      <div class="empty-state">
        <i class="pi pi-calendar" style="font-size:2.5rem;color:#CBD5E1"></i>
        <p>Selecciona un {{ modo === 'grupo' ? 'grupo' : 'docente' }} para ver el horario.</p>
      </div>
    } @else if (entradas().length === 0) {
      <div class="empty-state">
        <i class="pi pi-calendar-plus" style="font-size:2.5rem;color:#CBD5E1"></i>
        <p>No hay entradas de horario. Usa "Nueva entrada" para comenzar.</p>
      </div>
      <app-horario-grid
        [dias]="dias"
        [franjas]="franjas()"
        [entradas]="entradas()"
        [modo]="modo"
        (claseDrop)="onClaseDrop($event)"
        (claseClick)="abrirEditar($event)">
      </app-horario-grid>
    }
  `,
  styles: [`
    .filter-bar { display: flex; gap: 0.75rem; align-items: center; margin-bottom: 1.25rem; flex-wrap: wrap; }
    .page-header { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:1.25rem; }
    .page-header h2 { margin:0; }
    .subtitle { margin:0; font-size:.82rem; color:var(--p-text-color-secondary); }
    .empty-state { display: flex; flex-direction: column; align-items: center; gap: 0.75rem; padding: 4rem; color: #94A3B8; }

    /* Diálogo */
    .dlg-grid { display:flex; flex-direction:column; gap:.75rem; padding:.5rem 0; }
    .dlg-row  { display:grid; grid-template-columns:1fr 1fr; gap:.75rem; }
    .dlg-lbl  { display:block; font-size:.8rem; font-weight:600; margin-bottom:.3rem; color:var(--p-text-color); }
    .asc-reemplazar { display:flex; align-items:center; gap:.35rem; font-size:.8rem; color:var(--p-text-muted-color); cursor:pointer; user-select:none; }
    .asc-reemplazar input { cursor:pointer; }

    .solver-panel { margin-bottom: 1.5rem; padding: 1rem; border: 1px solid var(--surface-border); border-radius: 12px; background: linear-gradient(180deg, var(--surface-card), var(--surface-50)); }
    .solver-head { display:flex; justify-content:space-between; gap:1rem; align-items:flex-start; margin-bottom:1rem; }
    .solver-head h3 { margin:0 0 .25rem 0; font-family: var(--font-display); }
    .solver-head p { margin:0; color: var(--p-text-color-secondary); font-size:.85rem; max-width: 70ch; }
    .solver-actions { display:flex; gap:.5rem; flex-wrap:wrap; justify-content:flex-end; }
    .solver-grid { display:grid; grid-template-columns: 320px 1fr; gap:1rem; }
    .solver-card { background: var(--surface-card); border: 1px solid var(--surface-border); border-radius: 10px; padding: .9rem; min-height: 180px; }
    .solver-card-head { display:flex; justify-content:space-between; align-items:center; margin-bottom:.75rem; }
    .solver-card-head span { color: var(--p-text-color-secondary); font-size:.82rem; }
    .solver-empty { color: var(--p-text-color-secondary); padding:.75rem; border: 1px dashed var(--surface-border); border-radius: 8px; background: var(--surface-hover); }
    .solver-empty.small { padding:.5rem; font-size:.82rem; }
    .solver-list { display:flex; flex-direction:column; gap:.5rem; }
    .solver-list-item { width:100%; border:1px solid var(--surface-border); background:var(--surface-overlay); border-radius:8px; padding:.7rem .75rem; display:flex; justify-content:space-between; align-items:center; cursor:pointer; text-align:left; }
    .solver-list-item:hover { border-color: var(--nevadi-red); }
    .solver-list-item strong { display:block; }
    .solver-list-item span, .solver-list-item small { display:block; color: var(--p-text-color-secondary); font-size:.78rem; }
    .solver-summary { display:grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap:.75rem; margin-bottom: .9rem; }
    .solver-summary label { display:block; font-size:.72rem; color: var(--p-text-color-secondary); margin-bottom:.15rem; }
    .solver-summary strong { font-size:.92rem; }
    .solver-json-block { display:flex; flex-direction:column; gap:.35rem; margin-bottom:.9rem; }
    .solver-json-block label { font-size:.8rem; font-weight:600; color: var(--p-text-color); }
    .solver-json-block textarea { width:100%; min-height:160px; resize:vertical; }
    .solver-table-wrap { overflow:auto; border:1px solid var(--surface-border); border-radius:8px; }
    .solver-table { width:100%; border-collapse:collapse; font-size:.82rem; }
    .solver-table th, .solver-table td { padding:.55rem .6rem; border-bottom:1px solid var(--surface-border); text-align:left; vertical-align:top; }
    .solver-table th { position:sticky; top:0; background: var(--surface-100); z-index:1; }
    .reporte-summary {
      display:grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap:.75rem;
      margin-bottom: 1rem;
    }
    .reporte-summary div { background: var(--surface-card); border:1px solid var(--surface-border); border-radius:8px; padding:.7rem .8rem; }
    .reporte-summary label { display:block; font-size:.72rem; color: var(--p-text-color-secondary); margin-bottom:.2rem; }
    .reporte-summary strong { font-size:.92rem; }
    .reporte-grid { display:grid; grid-template-columns: 1.4fr .9fr; gap:1rem; }
    .reporte-table-wrap { overflow:auto; border:1px solid var(--surface-border); border-radius:8px; }
    .reporte-checks, .reporte-conflicts { display:flex; flex-direction:column; gap:.6rem; }
    .reporte-check, .reporte-conflict {
      display:flex;
      justify-content:space-between;
      gap:1rem;
      padding:.7rem .8rem;
      border:1px solid var(--surface-border);
      border-radius:8px;
      background:var(--surface-card);
      align-items:flex-start;
    }
    .reporte-check strong, .reporte-conflict strong { display:block; margin-bottom:.2rem; }
    .reporte-check p, .reporte-conflict p { margin:0; color: var(--p-text-color-secondary); font-size:.8rem; }
    .reporte-check span.ok { font-size:1rem; font-weight:700; color:#166534; }
    .reporte-check span:not(.ok) { font-size:1rem; font-weight:700; color:#b91c1c; }
    @media (max-width: 1100px) {
      .solver-grid { grid-template-columns: 1fr; }
      .solver-summary { grid-template-columns: repeat(2, minmax(0, 1fr)); }
      .reporte-summary { grid-template-columns: 1fr; }
      .reporte-grid { grid-template-columns: 1fr; }
      .solver-head { flex-direction:column; }
    }
  `],
})
export class HorariosComponent implements OnInit, OnDestroy {
  private readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);
  private readonly notify = inject(ApexNotificationService);

  readonly dias = DIAS.slice(1).map((label, i) => ({ num: i + 1, label }));
  readonly diasOpts = DIAS.slice(1).map((label, i) => ({ label, value: i + 1 }));
  readonly horasOpts = HORAS_INICIO;
  readonly duracionOpts = DURACIONES;

  readonly modoOpts = [
    { label: 'Por grupo', value: 'grupo' },
    { label: 'Por docente', value: 'profesor' },
  ];

  modo: 'grupo' | 'profesor' = 'grupo';
  selectedProfesor: any | null = null;
  /** ID del grupo activo; en modo=grupo viene del contexto global (topbar). */
  selectedGrupoId: string | null = null;

  gruposOpts = signal<GrupoConLabel[]>([]);
  profesores = signal<any[]>([]);
  materias = signal<MateriaOpt[]>([]);
  aulas = signal<AulaOpt[]>([]);
  entradas = signal<HorarioEntry[]>([]);
  corridasSolver = signal<SolverCorrida[]>([]);
  corridaDetalle = signal<SolverDetail | null>(null);
  cargandoCorridas = signal(false);
  ejecutandoSolver = signal(false);
  mutandoCorrida = signal(false);
  reporteVerificacion = signal<any>(null);
  cargandoReporte = signal(false);
  mostrarReglasIA = signal(false);
  reglaFraseIA = signal('');
  reglaInterpretada = signal<any>(null);
  parseandoRegla = signal(false);
  guardandoRegla = signal(false);
  private corridasPollHandle: ReturnType<typeof setInterval> | null = null;
  private horariosSeleccionados = new Set<string>();

  /** Grupo activo leído del contexto global (para modo=grupo). */
  get selectedGrupo(): GrupoConLabel | null {
    const g = this.ctx.grupo();
    if (!g?.id) return null;
    return { ...g, _label: grupoLabel(g) } as GrupoConLabel;
  }

  showDialog = signal(false);
  guardando = signal(false);
  editEntry: HorarioEntry | null = null;

  // aSc TimeTables
  exportandoAsc = signal(false);
  importandoAsc = signal(false);
  reemplazarAsc = false;

  form: {
    dia_semana: number | null;
    hora_inicio: string;
    duracion: number;
    materia_id: string | null;
    profesor_id: string | null;
    grupo_id: string | null;
    aula_id: string | null;
    fijado: boolean;
  } = this.resetForm();

  modoLabel = computed(() => this.modo === 'grupo' ? 'Grupo' : 'Docente');

  readonly franjas = computed(() => {
    const horas = [...new Set(this.entradas().map(e => e.hora_inicio))];
    return horas.sort();
  });

  readonly profeLabel = (p: any) => `${p.nombre ?? ''} ${p.apellido_paterno ?? ''}`.trim() || p.numero_empleado;
  readonly aulaLabel = (a: AulaOpt) => a.codigo ? `${a.codigo} — ${a.nombre}` : a.nombre;

  constructor() {
    // Recargar catálogos cuando cambia el plantel en el contexto global.
    effect(() => {
      const plantel = this.ctx.plantel();
      if (plantel?.id) {
        this.api.get<any[]>('/profesores', { plantel_id: plantel.id })
          .subscribe(p => this.profesores.set(
            p.map((x: any) => ({ ...x, _label: `${x.nombre ?? ''} ${x.apellido_paterno ?? ''}`.trim() || x.numero_empleado }))
          ));
        this.api.get<AulaOpt[]>('/aulas', { plantel_id: plantel.id })
          .subscribe(a => this.aulas.set(
            a.map(x => ({ ...x, _label: x.codigo ? `${x.codigo} — ${x.nombre}` : x.nombre }))
          ));
      } else {
        this.profesores.set([]);
        this.aulas.set([]);
      }
    });

    // Recargar horario cuando cambia el grupo en el contexto global (modo=grupo).
    effect(() => {
      const grupo = this.ctx.grupo();
      this.selectedGrupoId = grupo?.id ?? null;
      this.entradas.set([]);
      this.materias.set([]);
      if (this.modo === 'grupo' && grupo?.id) {
        this.onGrupoChange();
      }
    });
  }

  ngOnInit(): void {
    // Catálogos cargados reactivamente desde effects.
    this.cargarCorridas();
  }

  ngOnDestroy(): void {
    this.detenerPollingCorrida();
  }

  onModoChange(): void {
    this.selectedGrupoId = null;
    this.selectedProfesor = null;
    this.entradas.set([]);
  }

  onGrupoChange(): void {
    this.entradas.set([]);
    this.materias.set([]);
    if (!this.selectedGrupoId) return;
    this.cargar();

    const grupo = this.selectedGrupo;
    if (!grupo) return;
    const gId = grupo.grado_id;
    this.api.get<any[]>('/planes-estudio', { grado_id: gId })
      .subscribe(p => this.materias.set(p.map((x: any) => x.materia).filter(Boolean)));
  }

  puedeUsarSolver(): boolean {
    return Boolean(this.ctx.plantel()?.id && this.ctx.ciclo()?.id && this.ctx.nivelAcceso() <= 3);
  }

  labelDia(dia: number | null | undefined): string {
    return dia ? (this.dias.find(x => x.num === dia)?.label ?? `Día ${dia}`) : 'N/D';
  }

  corridaAnalysisText(): string {
    const detalle = this.corridaDetalle();
    if (!detalle?.score_analysis_json) return 'Sin análisis disponible.';
    try {
      const parsed = JSON.parse(detalle.score_analysis_json);
      return JSON.stringify(parsed, null, 2);
    } catch {
      return detalle.score_analysis_json;
    }
  }

  corridaAnalysis(): any {
    const detalle = this.corridaDetalle();
    if (!detalle?.score_analysis_json) return null;
    try {
      return JSON.parse(detalle.score_analysis_json);
    } catch {
      return null;
    }
  }

  resultadoExcelDisponible(): boolean {
    return Boolean(this.corridaDetalle()?.resultado_excel_url);
  }

  abrirResultadoExcel(): void {
    const url = this.corridaDetalle()?.resultado_excel_url;
    if (!url) return;
    window.open(url, '_blank', 'noopener');
  }

  esCorridaActiva(corrida: SolverCorrida | SolverDetail | null | undefined): boolean {
    const estado = String(corrida?.estado ?? '').toUpperCase();
    return estado.includes('RUNNING') || estado.includes('EN_PROCESO') || estado.includes('PROCESS') || estado.includes('PENDING');
  }

  iniciarPollingCorrida(corridaId: string): void {
    this.detenerPollingCorrida();
    this.corridasPollHandle = setInterval(() => {
      this.api.get<SolverDetail>(`/horarios/solver/corridas/${corridaId}`).subscribe({
        next: corrida => {
          this.corridaDetalle.set(corrida);
          this.sincronizarSeleccionDesdeDetalle(corrida);
          this.corridasSolver.update(corridas => corridas.map(c => c.id === corrida.id ? { ...c, ...corrida } : c));
          if (!this.esCorridaActiva(corrida)) {
            this.detenerPollingCorrida();
          }
        },
        error: () => {
          this.detenerPollingCorrida();
        },
      });
    }, 8000);
  }

  detenerPollingCorrida(): void {
    if (this.corridasPollHandle) {
      clearInterval(this.corridasPollHandle);
      this.corridasPollHandle = null;
    }
  }

  cargarCorridas(): void {
    if (!this.puedeUsarSolver()) {
      this.corridasSolver.set([]);
      this.corridaDetalle.set(null);
      return;
    }
    const plantelId = this.ctx.plantel()?.id;
    const cicloId = this.ctx.ciclo()?.id;
    if (!plantelId || !cicloId) {
      this.corridasSolver.set([]);
      this.corridaDetalle.set(null);
      return;
    }
    this.cargandoCorridas.set(true);
    this.api.get<SolverCorrida[]>('/horarios/solver/corridas', { plantel_id: plantelId, ciclo_id: cicloId }).subscribe({
      next: corridas => {
        this.corridasSolver.set(corridas);
        this.cargandoCorridas.set(false);
        if (!this.corridaDetalle() && corridas.length > 0) {
          this.seleccionarCorrida(corridas[0].id);
        }
      },
      error: () => {
        this.corridasSolver.set([]);
        this.corridaDetalle.set(null);
        this.cargandoCorridas.set(false);
        this.notify.error('Solver', 'No se pudieron cargar las corridas del plantel.');
      },
    });
  }

  verificarHorarioBackend(): void {
    const plantelId = this.ctx.plantel()?.id;
    const cicloId = this.ctx.ciclo()?.id;
    if (!plantelId || !cicloId) {
      this.notify.warning('Contexto requerido', 'Selecciona plantel y ciclo escolar para verificar el horario.');
      return;
    }
    this.cargandoReporte.set(true);
    this.api.get<any[]>('/horarios', { plantel_id: plantelId, ciclo_id: cicloId }).subscribe({
      next: horarios => {
        const payload = this.construirPayloadSolver(horarios ?? [], plantelId, cicloId);
        this.api.post<any>('/horarios/solver/verificar', payload).subscribe({
          next: analysis => {
            this.reporteVerificacion.set(analysis);
            this.cargandoReporte.set(false);
          },
          error: (err) => {
            this.cargandoReporte.set(false);
            this.notify.error('Verificación', err?.error?.detail || 'No se pudo verificar el horario con Timefold.');
          }
        });
      },
      error: () => {
        this.cargandoReporte.set(false);
        this.notify.error('Verificación', 'No se pudo cargar el horario del plantel para verificarlo.');
      },
    });
  }
  seleccionarCorrida(id: string): void {
    this.api.get<SolverDetail>(`/horarios/solver/corridas/${id}`).subscribe({
      next: corrida => {
        this.corridaDetalle.set(corrida);
        this.sincronizarSeleccionDesdeDetalle(corrida);
        if (this.esCorridaActiva(corrida)) {
          this.iniciarPollingCorrida(corrida.id);
        } else {
          this.detenerPollingCorrida();
        }
      },
      error: () => this.notify.error('Solver', 'No se pudo cargar el detalle de la corrida.'),
    });
  }


  parsearReglaIA(): void {
    const frase = this.reglaFraseIA();
    if (!frase) return;
    this.parseandoRegla.set(true);
    this.api.post<any>('/ai/horarios/reglas/parse', { frase }).subscribe({
      next: (res) => {
        this.parseandoRegla.set(false);
        this.reglaInterpretada.set(res.parsed);
        this.notify.success('IA', 'Regla interpretada correctamente.');
      },
      error: (err) => {
        this.parseandoRegla.set(false);
        this.notify.error('IA Error', err?.error?.detail ?? 'No se pudo interpretar la regla.');
      }
    });
  }

  guardarReglaIA(): void {
    const parsed = this.reglaInterpretada();
    const plantelId = this.ctx.plantel()?.id;
    const cicloId = this.ctx.ciclo()?.id;
    if (!parsed || !plantelId || !cicloId) return;

    const payload = {
      plantelId,
      cicloEscolarId: cicloId,
      tipo: parsed.tipo,
      params: parsed.params,
      peso: parsed.peso === 'HARD' ? 100 : 10,
      dura: parsed.peso === 'HARD',
      activa: true
    };

    this.guardandoRegla.set(true);
    // Nota: Llama al API de Spring Boot (/api/v1/horarios/reglas)
    this.api.post<any>('/horarios/reglas', payload).subscribe({
      next: () => {
        this.guardandoRegla.set(false);
        this.mostrarReglasIA.set(false);
        this.reglaFraseIA.set('');
        this.reglaInterpretada.set(null);
        this.notify.success('Reglas', 'Regla guardada en la base de datos.');
      },
      error: () => {
        this.guardandoRegla.set(false);
        this.notify.error('Error', 'No se pudo guardar la regla.');
      }
    });
  }

  iniciarSolver(): void {
    const plantelId = this.ctx.plantel()?.id;
    const cicloId = this.ctx.ciclo()?.id;
    if (!plantelId || !cicloId) {
      this.notify.warning('Contexto requerido', 'Selecciona plantel y ciclo escolar antes de ejecutar el solver.');
      return;
    }
    this.ejecutandoSolver.set(true);
    this.api.get<any[]>('/horarios', { plantel_id: plantelId, ciclo_id: cicloId }).subscribe({
      next: horarios => {
        const payload = this.construirPayloadSolver(horarios ?? [], plantelId, cicloId);
        this.api.post<SolverCorrida>('/horarios/solver/corridas', payload).subscribe({
          next: corrida => {
            this.ejecutandoSolver.set(false);
            this.notify.success('Solver', `Corrida ${corrida.id} creada con estado ${corrida.estado ?? 'N/D'}.`);
            this.cargarCorridas();
            this.seleccionarCorrida(corrida.id);
            if (this.esCorridaActiva(corrida)) {
              this.iniciarPollingCorrida(corrida.id);
            }
          },
          error: (err: any) => {
            this.ejecutandoSolver.set(false);
            this.notify.error('Solver', err?.error?.detail ?? 'No se pudo iniciar la corrida.');
          },
        });
      },
      error: () => {
        this.ejecutandoSolver.set(false);
        this.notify.error('Solver', 'No se pudieron leer los horarios vigentes del plantel.');
      },
    });
  }

  esHorarioSeleccionado(id: string): boolean {
    return this.horariosSeleccionados.has(id);
  }

  alternarHorarioSeleccionado(id: string, seleccionado: boolean): void {
    if (seleccionado) {
      this.horariosSeleccionados.add(id);
    } else {
      this.horariosSeleccionados.delete(id);
    }
  }

  sincronizarSeleccionDesdeDetalle(corrida: SolverDetail | null): void {
    this.horariosSeleccionados.clear();
    for (const horario of corrida?.horarios ?? []) {
      if (horario.fijado) {
        this.horariosSeleccionados.add(horario.id);
      }
    }
  }

  fijarSeleccionados(): void {
    const corridaId = this.corridaDetalle()?.id;
    if (!corridaId || this.horariosSeleccionados.size === 0) return;
    this.mutandoCorrida.set(true);
    this.api.post<SolverDetail>(`/horarios/solver/corridas/${corridaId}/lock`, { horarioIds: Array.from(this.horariosSeleccionados) }).subscribe({
      next: corrida => {
        this.mutandoCorrida.set(false);
        this.notify.success('Solver', 'Horarios fijados correctamente.');
        this.corridaDetalle.set(corrida);
        this.sincronizarSeleccionDesdeDetalle(corrida);
        this.cargarCorridas();
      },
      error: (err: any) => {
        this.mutandoCorrida.set(false);
        this.notify.error('Solver', err?.error?.detail ?? 'No se pudieron fijar los horarios seleccionados.');
      },
    });
  }

  regenerarSeleccionados(): void {
    const corridaId = this.corridaDetalle()?.id;
    if (!corridaId) return;
    this.mutandoCorrida.set(true);
    this.api.post<SolverCorrida>(`/horarios/solver/corridas/${corridaId}/regenerar`, { horarioIds: Array.from(this.horariosSeleccionados) }).subscribe({
      next: corrida => {
        this.mutandoCorrida.set(false);
        this.notify.success('Solver', `Nueva corrida ${corrida.id} generada.`);
        this.cargarCorridas();
        this.seleccionarCorrida(corrida.id);
      },
      error: (err: any) => {
        this.mutandoCorrida.set(false);
        this.notify.error('Solver', err?.error?.detail ?? 'No se pudo regenerar la corrida.');
      },
    });
  }

  private construirPayloadSolver(horarios: any[], plantelId: string, cicloId: string): Record<string, any> {
    const leccionesMap = new Map<string, Record<string, any>>();
    for (const row of horarios) {
      const diaSemana = Number(row.dia_semana);
      const horaInicio = String(row.hora_inicio ?? '').slice(0, 5);
      const horaFin = String(row.hora_fin ?? '').slice(0, 5);

      const leccionKey = String(row.id ?? `${row.grupo_id}|${row.materia_id}|${row.profesor_id}|${row.aula_id}`);
      if (!leccionesMap.has(leccionKey)) {
        leccionesMap.set(leccionKey, {
          id: row.id ?? null,
          grupo_id: row.grupo_id,
          materia_id: row.materia_id,
          profesor_id: row.profesor_id,
          aula_id: row.aula_id ?? null,
          ciclo_escolar_id: row.ciclo_escolar_id ?? cicloId,
          fijado: Boolean(row.fijado),
          timeslot: {
            dia_semana: diaSemana,
            hora_inicio: horaInicio,
            hora_fin: horaFin,
            turno: row.turno ?? null,
          },
        });
      }
    }

    return {
      plantel_id: plantelId,
      ciclo_escolar_id: cicloId,
      lecciones: Array.from(leccionesMap.values()),
    };
  }

  cargar(): void {
    const cicloId = this.ctx.ciclo()?.id;
    if (this.modo === 'grupo' && this.selectedGrupoId) {
      this.api.get<any>(`/horarios/grupo/${this.selectedGrupoId}`, cicloId ? { ciclo_id: cicloId } : undefined)
        .subscribe(r => this.entradas.set(r.entradas || r || []));
    } else if (this.modo === 'profesor' && this.selectedProfesor) {
      this.api.get<any>(`/horarios/profesor/${this.selectedProfesor.id}`, cicloId ? { ciclo_id: cicloId } : undefined)
        .subscribe(r => this.entradas.set(r.entradas || r || []));
    }
  }

  entradasPor(dia: number, hora: string): HorarioEntry[] {
    return this.entradas().filter(e => e.dia_semana === dia && e.hora_inicio === hora);
  }

  colorMateria(nombre: string | null): string {
    if (!nombre) return 'var(--surface-hover)';
    const colorHash = nombre.split('').reduce((acc, char) => char.charCodeAt(0) + ((acc << 5) - acc), 0);
    const h = Math.abs(colorHash) % 360;
    return `hsl(${h}, 60%, 90%)`;
  }

  onClaseDrop(event: CdkDragDrop<any>) {
    if (event.previousContainer === event.container) {
      // Movimiento dentro de la misma celda, no hacer nada o reordenar si aplica
      return;
    }
    const item: HorarioEntry = event.item.data;
    const destino = event.container.data as {dia: number, franja: string};

    // Si la clase está fijada, no permitir moverla (validación extra)
    if (item.fijado) {
      this.notify.error('No se puede mover', 'La clase está fijada por el motor.');
      return;
    }

    // Aquí implementaremos la actualización en la API
    // Por ahora, actualicemos el estado localmente para feedback inmediato
    const oldDia = item.dia_semana;
    const oldHora = item.hora_inicio;

    item.dia_semana = destino.dia;
    item.hora_inicio = destino.franja;
    // Calcular hora de fin basado en la duración original
    const oldIni = new Date(`1970-01-01T${oldHora}`);
    const oldFin = new Date(`1970-01-01T${item.hora_fin}`);
    const diffMs = oldFin.getTime() - oldIni.getTime();

    const newIni = new Date(`1970-01-01T${destino.franja}:00`);
    const newFin = new Date(newIni.getTime() + diffMs);
    item.hora_fin = newFin.toTimeString().slice(0, 5) + ':00';

    // Si la actualización en BD falla, revertiríamos esto.
    // Lógica para enviar a la API
    const payload = {
      dia_semana: item.dia_semana,
      hora_inicio: item.hora_inicio,
      hora_fin: item.hora_fin
    };

    this.api.put(`/horarios/${item.id}`, payload).subscribe({
      next: () => {
        this.notify.success('Clase movida', 'El horario ha sido actualizado.');
        // Trigger de regeneración del signal
        this.entradas.set([...this.entradas()]); 
      },
      error: (err) => {
        this.notify.error('Error al mover', err?.error?.message || 'Hubo un problema de validación de traslape');
        // Revertir
        item.dia_semana = oldDia;
        item.hora_inicio = oldHora;
        item.hora_fin = oldFin.toTimeString().slice(0, 5) + ':00';
        this.entradas.set([...this.entradas()]);
      }
    });
  }

  abrirNuevo(): void {
    this.editEntry = null;
    this.form = {
      ...this.resetForm(),
      grupo_id: this.modo === 'grupo' ? (this.selectedGrupo as any)?.id ?? null : null,
      profesor_id: this.modo === 'profesor' ? this.selectedProfesor?.id ?? null : null,
    };
    this.showDialog.set(true);
  }

  abrirEditar(e: HorarioEntry): void {
    this.editEntry = e;
    const [h, m] = e.hora_inicio.split(':').map(Number);
    const [hFin, mFin] = e.hora_fin.split(':').map(Number);
    this.form = {
      dia_semana: e.dia_semana,
      hora_inicio: `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`,
      duracion: (hFin * 60 + mFin) - (h * 60 + m),
      materia_id: e.materia_id,
      profesor_id: e.profesor_id,
      grupo_id: e.grupo_id,
      aula_id: e.aula_id,
      fijado: e.fijado || false
    };
    this.showDialog.set(true);
  }

  guardar(): void {
    if (!this.form.dia_semana || !this.form.hora_inicio || !this.form.materia_id) {
      this.notify.warning('Validación', 'Completa los campos obligatorios: Día, Hora inicio y Materia.');
      return;
    }
    this.guardando.set(true);

    const horaFin = this.calcHoraFin(this.form.hora_inicio, this.form.duracion);
    const cicloId = this.ctx.ciclo()?.id;

    const body: Record<string, any> = {
      dia_semana: this.form.dia_semana,
      hora_inicio: this.form.hora_inicio,
      hora_fin: horaFin,
      materia_id: this.form.materia_id,
      profesor_id: this.form.profesor_id || null,
      aula_id: this.form.aula_id || null,
      ciclo_escolar_id: cicloId || null,
      origen: 'MANUAL',
      fijado: this.form.fijado ?? false,
    };

    if (this.modo === 'grupo') {
      body['grupo_id'] = (this.selectedGrupo as any)?.id;
    } else {
      body['grupo_id'] = this.form.grupo_id || null;
    }

    const req = this.editEntry
      ? this.api.patch(`/horarios/${this.editEntry.id}`, body)
      : this.api.post('/horarios', body);

    req.subscribe({
      next: () => {
        this.notify.success(this.editEntry ? 'Entrada actualizada.' : 'Entrada agregada al horario.');
        this.guardando.set(false);
        this.showDialog.set(false);
        this.cargar();
      },
      error: (err: any) => {
        this.notify.error(err?.error?.detail ?? 'Error al guardar la entrada.');
        this.guardando.set(false);
      },
    });
  }

  eliminar(): void {
    if (!this.editEntry) return;
    if (!confirm('¿Eliminar esta entrada del horario?')) return;
    this.guardando.set(true);
    this.api.delete(`/horarios/${this.editEntry.id}`).subscribe({
      next: () => {
        this.notify.success('Entrada eliminada.');
        this.guardando.set(false);
        this.showDialog.set(false);
        this.cargar();
      },
      error: () => {
        this.notify.error('Error al eliminar.');
        this.guardando.set(false);
      },
    });
  }

  exportarASC(): void {
    const cicloId = this.ctx.ciclo()?.id;
    const plantelId = this.ctx.plantel()?.id;
    if (!cicloId) return;
    const params: Record<string, string> = {};
    if (plantelId) params['plantel_id'] = plantelId;
    this.exportandoAsc.set(true);
    this.api.getBlob(`/horarios/exportar-asc/${cicloId}`, params).subscribe({
      next: blob => {
        this.exportandoAsc.set(false);
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'horarios_asc.xml';
        a.click();
        URL.revokeObjectURL(url);
      },
      error: () => {
        this.exportandoAsc.set(false);
        this.notify.error('Error', 'No se pudo exportar el XML aSc');
      },
    });
  }

  onArchivoAscSeleccionado(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file = input.files?.[0];
    if (!file) return;
    input.value = '';   // permite re-subir el mismo archivo
    const cicloId = this.ctx.ciclo()?.id;
    if (!cicloId) {
      this.notify.warning('Ciclo requerido', 'Selecciona un ciclo escolar en el contexto antes de importar');
      return;
    }
    const plantelId = this.ctx.plantel()?.id;
    const form = new FormData();
    form.append('file', file);
    if (plantelId) form.append('plantel_id', plantelId);
    form.append('reemplazar', String(this.reemplazarAsc));

    this.importandoAsc.set(true);
    this.api.upload<any>(`/horarios/importar-asc/${cicloId}`, form).subscribe({
      next: r => {
        this.importandoAsc.set(false);
        const detalle = r.errores > 0 ? ` (${r.errores} con error)` : '';
        const reemplazo = r.eliminados > 0 ? `, ${r.eliminados} reemplazadas` : '';
        this.notify.success('Importación aSc',
          `${r.exitosos} de ${r.total} clases importadas${reemplazo}${detalle}`);
        this.cargar();
      },
      error: e => {
        this.importandoAsc.set(false);
        this.notify.error('Error', e.error?.detail ?? e.error?.message ?? 'No se pudo importar el XML aSc');
      },
    });
  }

  private resetForm() {
    return {
      dia_semana: null as number | null,
      hora_inicio: '08:00',
      duracion: 60,
      materia_id: null as string | null,
      profesor_id: null as string | null,
      grupo_id: this.selectedGrupoId || this.ctx.grupo()?.id || null,
      aula_id: null as string | null,
      fijado: false
    };
  }

  private calcHoraFin(inicio: string, duracionMin: number): string {
    const [h, m] = inicio.split(':').map(Number);
    const total = h * 60 + m + duracionMin;
    return `${String(Math.floor(total / 60)).padStart(2, '0')}:${String(total % 60).padStart(2, '0')}`;
  }
}

/**
 * IaComponent — Asistente pedagógico IA + Panel de alertas académicas.
 *
 * Dos pestañas:
 *   1. Chat con el asistente (Claude vía backend)
 *   2. Alertas académicas del grupo/plantel con botón "Escanear grupo"
 */
import { Component, OnInit, inject, signal, computed, ElementRef, ViewChild, afterNextRender } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { TabsModule } from 'primeng/tabs';
import { CardModule } from 'primeng/card';
import { TagModule } from 'primeng/tag';
import { SelectModule } from 'primeng/select';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';

import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';
import type { Grupo } from '../../core/models';
import { grupoLabel } from '../../core/models';
import { ApexNotificationService } from 'apex-component-library';

type GrupoConLabel = Grupo & { _label: string };

interface Mensaje {
  rol: 'user' | 'assistant';
  contenido: string;
  timestamp: Date;
}

interface Alerta {
  id: string;
  tipo_alerta: string;
  nivel_riesgo: string;
  descripcion: string;
  atendida: boolean;
  fccreacion: string;
}

type AlertaSeverity = 'success' | 'info' | 'warn' | 'danger' | 'secondary';

const RIESGO_SEVERITY: Record<string, AlertaSeverity> = {
  BAJO: 'info', MEDIO: 'warn', ALTO: 'warn', CRITICO: 'danger',
};

@Component({
  selector: 'app-ia',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    ButtonModule, InputTextModule, TabsModule, CardModule,
    TagModule, SelectModule, ProgressSpinnerModule,
    InteractiveGridComponent,
  ],
  template: `

    <div class="page-header">
      <div>
        <h2>Asistente Pedagógico IA</h2>
        <p class="subtitle">Análisis académico y alertas de riesgo — powered by IA</p>
      </div>
    </div>

    <p-tabs>

      <!-- ── Pestaña Chat ── -->
      <p-tabpanel value="0" header="Chat con el asistente">
        <div class="chat-layout">

          <!-- Sugerencias rápidas + selector de sesión -->
          <div style="display:flex;gap:.5rem;align-items:center;flex-wrap:wrap;margin-bottom:.5rem">
            <div class="quick-chips" style="flex:1;margin-bottom:0">
              @for (s of sugerencias; track s) {
                <button class="chip" (click)="usarSugerencia(s)">{{ s }}</button>
              }
            </div>
            @if (sesionesGuardadas().length > 0) {
              <p-button label="Conversaciones" icon="pi pi-history" size="small"
                severity="secondary" [outlined]="true"
                (onClick)="showSesiones.set(!showSesiones())" />
            }
          </div>

          <!-- Panel sesiones guardadas (IA-015) -->
          @if (showSesiones() && sesionesGuardadas().length > 0) {
            <div style="background:var(--surface-50);border:1px solid var(--surface-200);border-radius:8px;padding:.75rem;margin-bottom:.75rem">
              <div style="font-size:.78rem;font-weight:600;color:var(--text-muted);margin-bottom:.5rem;text-transform:uppercase">
                Conversaciones anteriores
              </div>
              @for (ses of sesionesGuardadas(); track ses.sesion_id) {
                <div style="display:flex;gap:.5rem;align-items:center;padding:.35rem 0;border-bottom:1px solid var(--surface-100)">
                  <div style="flex:1;min-width:0">
                    <div style="font-size:.82rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">
                      {{ ses.resumen || '(sin texto)' }}
                    </div>
                    <div style="font-size:.7rem;color:var(--text-muted)">
                      {{ ses.total_mensajes }} mensajes · {{ ses.ultimo_mensaje | date:'dd/MM HH:mm' }}
                    </div>
                  </div>
                  <p-button icon="pi pi-arrow-right" size="small" [text]="true"
                    ariaLabel="Cargar esta conversación" pTooltip="Cargar esta conversación"
                    (onClick)="cargarSesion(ses.sesion_id)" />
                  <p-button icon="pi pi-trash" size="small" [text]="true" severity="danger"
                    ariaLabel="Eliminar conversación" pTooltip="Eliminar" (onClick)="eliminarSesion(ses.sesion_id)" />
                </div>
              }
            </div>
          }

          <!-- Historial de mensajes -->
          <div class="chat-messages" #messagesContainer>
            @if (mensajes().length === 0) {
              <div class="chat-empty">
                <i class="pi pi-comments" style="font-size:2.5rem;color:#CBD5E1"></i>
                <p>¿En qué puedo ayudarte hoy? Pregúntame sobre calificaciones, asistencias, estrategias pedagógicas o normativa SEP/UAEMEX.</p>
              </div>
            }
            @for (m of mensajes(); track m.timestamp) {
              <div [class]="'message-row ' + m.rol">
                <div class="message-bubble">
                  <div class="message-text" [innerHTML]="formatMensaje(m.contenido)"></div>
                  <div class="message-time">{{ m.timestamp | date:'HH:mm' }}</div>
                </div>
              </div>
            }
            @if (cargando()) {
              <div class="message-row assistant">
                <div class="message-bubble typing">
                  <span></span><span></span><span></span>
                </div>
              </div>
            }
          </div>

          <!-- Input -->
          <div class="chat-input-bar">
            <input
              pInputText
              [(ngModel)]="inputMensaje"
              placeholder="Escribe tu pregunta o petición..."
              (keyup.enter)="enviar()"
              [disabled]="cargando()"
              class="chat-input"
            />
            <p-button
              icon="pi pi-send"
              [loading]="cargando()"
              (onClick)="enviar()"
              [disabled]="!inputMensaje.trim()"
              ariaLabel="Enviar mensaje al asistente"
              pTooltip="Enviar"
            />
            <p-button
              icon="pi pi-trash"
              severity="secondary"
              [text]="true"
              (onClick)="limpiarChat()"
              ariaLabel="Iniciar una nueva conversación"
              pTooltip="Nueva conversación"
            />
          </div>
        </div>
      </p-tabpanel>

      <!-- ── Pestaña Alertas ── -->
      <p-tabpanel value="1" header="Alertas académicas">
        <div class="alertas-toolbar">
          <p-select
            [options]="grupos()"
            [(ngModel)]="selectedGrupo"
            optionLabel="_label"
            placeholder="Seleccionar grupo..."
            [showClear]="true"


          [filter]="true" filterPlaceholder="Buscar..."/>
          <p-button
            label="Escanear grupo"
            icon="pi pi-search"
            (onClick)="escanearGrupo()"
            [loading]="escaneando()"
            [disabled]="!selectedGrupo"
          />
          <p-button
            label="Cargar alertas"
            icon="pi pi-refresh"
            severity="secondary"
            [text]="true"
            (onClick)="cargarAlertas()"
          />
        </div>

        <app-interactive-grid
          [data]="alertasFlat()"
          [columns]="alertasColumns"
          [loading]="cargandoAlertas()"
        />
      </p-tabpanel>

      <!-- ── Pestaña Chatbot de Datos (NL→SQL) ── -->
      <p-tabpanel value="2" header="Consulta de datos">
        <div class="datos-layout">
          <p style="font-size:.83rem;color:var(--text-color-secondary);margin:0 0 1rem">
            Pregunta en lenguaje natural sobre alumnos, calificaciones, asistencias y más.
            El sistema genera y ejecuta el SQL automáticamente, respetando tu nivel de acceso.
          </p>

          <div class="quick-chips">
            @for (s of sugerenciasDatos; track s) {
              <button class="chip" (click)="usarSugerenciaDatos(s)">{{ s }}</button>
            }
          </div>

          <div class="datos-input-bar">
            <input pInputText [(ngModel)]="inputDatos"
              placeholder="¿Cuántos alumnos reprobaron matemáticas este bimestre?"
              (keyup.enter)="consultarDatos()"
              [disabled]="cargandoDatos()"
              style="flex:1" />
            <p-button icon="pi pi-search" label="Consultar"
              [loading]="cargandoDatos()" (onClick)="consultarDatos()"
              [disabled]="!inputDatos.trim()" />
          </div>

          @if (respuestaDatos()) {
            <div class="datos-respuesta">
              <p class="datos-texto">{{ respuestaDatos()!.respuesta }}</p>
              @if (respuestaDatos()!.sql_generado) {
                <details class="sql-details">
                  <summary>SQL generado</summary>
                  <pre class="sql-code">{{ respuestaDatos()!.sql_generado }}</pre>
                </details>
              }
              @if (respuestaDatos()!.datos && respuestaDatos()!.datos!.length > 0) {
                <div style="margin-top:1rem;overflow-x:auto">
                  <table class="datos-tabla">
                    <thead>
                      <tr>
                        @for (col of columnasTabla(); track col) {
                          <th>{{ col }}</th>
                        }
                      </tr>
                    </thead>
                    <tbody>
                      @for (row of respuestaDatos()!.datos!.slice(0,50); track $index) {
                        <tr>
                          @for (col of columnasTabla(); track col) {
                            <td>{{ row[col] ?? '—' }}</td>
                          }
                        </tr>
                      }
                    </tbody>
                  </table>
                  @if ((respuestaDatos()!.datos?.length ?? 0) > 50) {
                    <p style="font-size:.75rem;color:var(--text-muted);margin:.5rem 0 0">
                      Mostrando 50 de {{ respuestaDatos()!.datos!.length }} resultados
                    </p>
                  }
                </div>
              }
            </div>
          }
        </div>
      </p-tabpanel>

    </p-tabs>
  `,
  styles: [`
    /* ── Chat layout ──────────────────────────────────────────────────────── */
    .chat-layout { display: flex; flex-direction: column; height: calc(100vh - 220px); gap: 0.75rem; }

    .quick-chips { display: flex; flex-wrap: wrap; gap: 0.4rem; }
    .chip {
      padding: 0.3rem 0.8rem;
      border-radius: 20px;
      background: var(--nevadi-red-lighter);
      border: 1px solid var(--nevadi-red-light);
      color: var(--nevadi-red-dark);
      font-size: 0.78rem;
      cursor: pointer;
      transition: background .15s;
      font-family: var(--font-body);
    }
    .chip:hover { background: var(--nevadi-red-light); }

    .chat-messages {
      flex: 1; overflow-y: auto;
      display: flex; flex-direction: column; gap: 0.75rem;
      padding: 0.5rem;
      background: #F8F9FA;
      border-radius: 8px;
      border: 1px solid var(--surface-border);
    }
    .chat-empty {
      flex: 1; display: flex; flex-direction: column;
      align-items: center; justify-content: center;
      gap: 0.75rem; color: #94A3B8; text-align: center; padding: 2rem;
    }
    .message-row { display: flex; }
    .message-row.user     { justify-content: flex-end; }
    .message-row.assistant { justify-content: flex-start; }

    .message-bubble {
      max-width: 75%;
      padding: 0.6rem 0.9rem;
      border-radius: 12px;
      font-size: 0.88rem;
      line-height: 1.5;
    }
    .message-row.user .message-bubble {
      background: var(--nevadi-red);
      color: #fff;
      border-bottom-right-radius: 3px;
    }
    .message-row.assistant .message-bubble {
      background: #fff;
      border: 1px solid var(--surface-border);
      border-bottom-left-radius: 3px;
    }
    .message-text :global(p) { margin: 0 0 0.4rem; }
    .message-text :global(ul) { margin: 0.4rem 0; padding-left: 1.2rem; }
    .message-time { font-size: 0.68rem; opacity: 0.65; margin-top: 3px; text-align: right; }

    /* Typing animation */
    .typing { padding: 0.5rem 0.9rem; }
    .typing span {
      display: inline-block; width: 7px; height: 7px;
      border-radius: 50%; background: #94A3B8; margin: 0 2px;
      animation: bounce 1.2s infinite;
    }
    .typing span:nth-child(2) { animation-delay: .2s; }
    .typing span:nth-child(3) { animation-delay: .4s; }
    @keyframes bounce {
      0%, 60%, 100% { transform: translateY(0); }
      30% { transform: translateY(-6px); }
    }

    .chat-input-bar { display: flex; gap: 0.5rem; align-items: center; }
    .chat-input { flex: 1; }

    /* ── Alertas ───────────────────────────────────────────────────────────── */
    .alertas-toolbar { display: flex; gap: 0.75rem; margin-bottom: 1rem; align-items: center; flex-wrap: wrap; }
    tr.atendida { opacity: 0.5; }

    /* ── Consulta de Datos (NL→SQL) ────────────────────────────────────────── */
    .datos-layout { display: flex; flex-direction: column; gap: 1rem; }
    .datos-input-bar { display: flex; gap: .5rem; align-items: center; }
    .datos-respuesta { background: #F8F9FA; border: 1px solid var(--surface-border); border-radius: 8px; padding: 1rem; }
    .datos-texto { font-size: .9rem; line-height: 1.6; margin: 0 0 .75rem; }
    .sql-details { margin-top: .5rem; }
    .sql-details summary { font-size: .78rem; color: var(--text-color-secondary); cursor: pointer; }
    .sql-code { font-size: .75rem; background: #1e293b; color: #e2e8f0; padding: .75rem 1rem; border-radius: 6px; overflow-x: auto; white-space: pre-wrap; margin: .5rem 0 0; }
    .datos-tabla { width: 100%; border-collapse: collapse; font-size: .8rem; }
    .datos-tabla th { background: var(--surface-100); padding: .4rem .6rem; text-align: left; font-weight: 600; border-bottom: 2px solid var(--surface-300); }
    .datos-tabla td { padding: .35rem .6rem; border-bottom: 1px solid var(--surface-200); }
    .datos-tabla tr:hover td { background: var(--surface-50); }
  `],
})
export class IaComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);
  private readonly notify = inject(ApexNotificationService);

  @ViewChild('messagesContainer') messagesContainer?: ElementRef<HTMLDivElement>;

  mensajes          = signal<Mensaje[]>([]);
  cargando          = signal(false);
  sesionesGuardadas = signal<any[]>([]);
  showSesiones      = signal(false);
  inputMensaje = '';
  sesionId: string = crypto.randomUUID();

  grupos   = signal<GrupoConLabel[]>([]);
  alertas  = signal<Alerta[]>([]);
  cargandoAlertas = signal(false);

  readonly alertasFlat = computed(() =>
    this.alertas().map(a => ({
      ...a,
      fecha_str:   a.fccreacion ? new Date(a.fccreacion).toLocaleDateString('es-MX') : '—',
      estado_str:  a.atendida ? 'Atendida' : 'Pendiente',
    }))
  );
  readonly alertasColumns: ColumnConfig[] = [
    { field: 'tipo_alerta',  header: 'Tipo',        width: '130px' },
    { field: 'nivel_riesgo', header: 'Riesgo',      width: '90px' },
    { field: 'descripcion',  header: 'Descripción' },
    { field: 'fecha_str',    header: 'Fecha',       width: '110px' },
    { field: 'estado_str',   header: 'Estado',      width: '90px' },
  ];
  escaneando = signal(false);
  selectedGrupo: GrupoConLabel | null = null;

  readonly sugerencias = [
    '¿Cuáles son los alumnos en riesgo de reprobar?',
    'Sugiere estrategias para mejorar la asistencia',
    'Explica los criterios de acreditación UAEMEX',
    'Genera una rúbrica para evaluación de exposición oral',
    'Redacta un comunicado de bajo rendimiento para padres',
  ];

  // ── NL→SQL (FASE 17) ─────────────────────────────────────────────────────
  inputDatos       = '';
  cargandoDatos    = signal(false);
  respuestaDatos   = signal<{ respuesta: string; sql_generado?: string; datos?: any[] } | null>(null);
  columnasTabla    = signal<string[]>([]);
  sesiónDatos      = crypto.randomUUID();

  readonly sugerenciasDatos = [
    '¿Cuántos alumnos tienen calificación menor a 6?',
    '¿Cuál es el promedio por materia en preparatoria?',
    '¿Qué alumnos tienen más del 20% de inasistencias?',
    'Listar los 10 alumnos con mejor promedio general',
    '¿Cuántos alumnos reprobaron al menos una materia?',
  ];

  ngOnInit(): void {
    const plantelId = this.ctx.plantel()?.id;
    if (plantelId) {
      this.api.get<Grupo[]>('/grupos', { plantel_id: plantelId, solo_activos: true, ciclo_vigente: true })
        .subscribe(g => this.grupos.set(g.map(x => ({ ...x, _label: grupoLabel(x) }))));
    }
    this.cargarAlertas();
    this._cargarSesiones();
  }

  private _cargarSesiones(): void {
    this.api.get<any[]>('/ai/mis-sesiones?limite=8').subscribe({
      next: (items) => this.sesionesGuardadas.set(items || []),
      error: () => {},
    });
  }

  cargarSesion(sesionId: string): void {
    this.api.get<any>(`/ai/sesion/${sesionId}`).subscribe({
      next: (data) => {
        const msgs: Mensaje[] = (data.mensajes || []).map((m: any) => ({
          rol: m.rol as 'user' | 'assistant',
          contenido: m.contenido,
          timestamp: new Date(m.timestamp),
        }));
        this.mensajes.set(msgs);
        this.sesionId = sesionId;
        this.showSesiones.set(false);
        setTimeout(() => this._scrollToBottom(), 100);
      },
      error: () => this.notify.error('No se pudo cargar la conversación'),
    });
  }

  eliminarSesion(sesionId: string): void {
    this.api.delete(`/ai/sesion/${sesionId}`).subscribe({
      next: () => {
        this.sesionesGuardadas.update(s => s.filter(x => x.sesion_id !== sesionId));
        if (this.sesionId === sesionId) this.limpiarChat();
        this.notify.success('Conversación eliminada');
      },
      error: () => this.notify.error('Error al eliminar conversación'),
    });
  }

  usarSugerencia(s: string): void {
    this.inputMensaje = s;
    this.enviar();
  }

  enviar(): void {
    const texto = this.inputMensaje.trim();
    if (!texto || this.cargando()) return;

    const userMsg: Mensaje = { rol: 'user', contenido: texto, timestamp: new Date() };
    this.mensajes.update(m => [...m, userMsg]);
    this.inputMensaje = '';
    this.cargando.set(true);

    const historial = this.mensajes().slice(-10).map(m => ({ role: m.rol, content: m.contenido }));
    const contexto: Record<string, any> = {};
    if (this.ctx.plantel()) contexto['plantel'] = this.ctx.plantel()!.nombre_plantel;
    if (this.ctx.ciclo()) contexto['ciclo'] = this.ctx.ciclo()!.nombre_ciclo;

    this.api.post<any>('/ai/chat', {
      sesion_id: this.sesionId,
      mensaje: texto,
      historial: historial.slice(0, -1),
      contexto,
    }).subscribe({
      next: (r) => {
        this.mensajes.update(m => [...m, { rol: 'assistant', contenido: r.respuesta, timestamp: new Date() }]);
        this.cargando.set(false);
        this._scrollToBottom();
      },
      error: (e) => {
        this.cargando.set(false);
        this.notify.error('Error', e.error?.detail || 'Error al contactar al asistente');
      },
    });
  }

  limpiarChat(): void {
    this.mensajes.set([]);
    this.sesionId = crypto.randomUUID();
    this.showSesiones.set(false);
    this._cargarSesiones();
  }

  formatMensaje(texto: string): string {
    return texto
      .replace(/\n\n/g, '</p><p>')
      .replace(/\n/g, '<br>')
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/^- /gm, '• ')
      .replace(/^(\d+)\. /gm, '$1. ');
  }

  cargarAlertas(): void {
    this.cargandoAlertas.set(true);
    const params: Record<string, any> = { atendida: false };
    if (this.selectedGrupo) params['grupo_id'] = this.selectedGrupo.id;
    this.api.get<Alerta[]>('/ai/alertas', params)
      .subscribe({ next: a => { this.alertas.set(a); this.cargandoAlertas.set(false); }, error: () => this.cargandoAlertas.set(false) });
  }

  escanearGrupo(): void {
    if (!this.selectedGrupo) return;
    this.escaneando.set(true);
    this.api.post<any>(`/ai/alertas/scan/${this.selectedGrupo.id}`, {}).subscribe({
      next: (r) => {
        this.escaneando.set(false);
        this.notify.success('Escaneo completado', `${r.alertas_generadas} alerta(s) generadas para ${r.alumnos_analizados} alumnos`);
        this.cargarAlertas();
      },
      error: () => this.escaneando.set(false),
    });
  }

  riesgoSeverity(nivel: string): AlertaSeverity {
    return RIESGO_SEVERITY[nivel] || 'info';
  }

  private _scrollToBottom(): void {
    setTimeout(() => {
      if (this.messagesContainer) {
        this.messagesContainer.nativeElement.scrollTop = this.messagesContainer.nativeElement.scrollHeight;
      }
    }, 50);
  }

  // ── Consulta de datos NL→SQL ──────────────────────────────────────────────

  usarSugerenciaDatos(s: string): void { this.inputDatos = s; this.consultarDatos(); }

  consultarDatos(): void {
    const q = this.inputDatos.trim();
    if (!q) return;
    this.cargandoDatos.set(true);
    this.respuestaDatos.set(null);

    this.api.post<{ respuesta: string; sql_generado?: string; datos?: any[] }>(
      '/chatbot/mensaje',
      { pregunta: q, sesion_id: this.sesiónDatos }
    ).subscribe({
      next: resp => {
        this.respuestaDatos.set(resp);
        if (resp.datos?.length) {
          this.columnasTabla.set(Object.keys(resp.datos[0]));
        }
        this.cargandoDatos.set(false);
      },
      error: (err) => {
        const msg = err?.error?.detail ?? 'Error al procesar la consulta';
        this.respuestaDatos.set({ respuesta: `⚠ ${msg}` });
        this.cargandoDatos.set(false);
      },
    });
  }
}

import { Component, OnInit, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/services/api.service';
import { ButtonModule } from 'primeng/button';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { ToastModule } from 'primeng/toast';
import { TextareaModule } from 'primeng/textarea';
import { MessageService } from 'primeng/api';
import { ApexNotificationService } from 'apex-component-library';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';

type TagSev = 'success' | 'info' | 'warn' | 'danger' | 'secondary' | 'contrast';

interface Justificacion {
  id: string;
  asistencia_id: string;
  tipo_justificacion: string;
  motivo: string;
  documento_url: string | null;
  estado: string;
  motivo_rechazo: string | null;
  fecha_resolucion: string | null;
  fecha_creacion: string;
  alumno_nombre: string;
  estatus_asistencia: string;
  fecha_clase: string | null;
}

const TIPOS_JUST = [
  { label: 'Médica',          value: 'MEDICA' },
  { label: 'Familiar',        value: 'FAMILIAR' },
  { label: 'Deportiva',       value: 'DEPORTIVA' },
  { label: 'Cultural',        value: 'CULTURAL' },
  { label: 'Administrativa',  value: 'ADMINISTRATIVA' },
  { label: 'Otra',            value: 'OTRA' },
];

const ESTADOS_OPT = [
  { label: 'Todos',     value: '' },
  { label: 'Pendiente', value: 'PENDIENTE' },
  { label: 'Aprobada',  value: 'APROBADA' },
  { label: 'Rechazada', value: 'RECHAZADA' },
];

/**
 * Módulo de justificaciones de inasistencias.
 * Permite a docentes y coordinadores registrar, aprobar o rechazar justificantes
 * de faltas de alumnos con evidencia documental adjunta.
 */
@Component({
  selector: 'app-justificaciones',
  standalone: true,
  imports: [
    CommonModule, FormsModule, ButtonModule, DialogModule,
    InputTextModule, SelectModule, ToastModule, TextareaModule,
    InteractiveGridComponent,
  ],
  providers: [MessageService],
  template: `
    <p-toast />
    <div class="apex-page">
      <div class="apex-toolbar">
        <h2 class="apex-title">Justificaciones de Faltas</h2>
        <div class="apex-toolbar-actions">
          <input pInputText [(ngModel)]="filtroEstudianteId" placeholder="UUID estudiante…" style="width:230px" />
          <p-select [options]="estadosOpt" optionLabel="label" optionValue="value"
            [(ngModel)]="filtroEstado" placeholder="Estado…" [style]="{width:'130px'}" />
          <p-button label="Filtrar" icon="pi pi-filter" size="small" (onClick)="cargar()" />
          <p-button label="Nueva justificación" icon="pi pi-plus" size="small" (onClick)="abrirNueva()" />
        </div>
      </div>

      <!-- Resumen chips -->
      <div class="stats-bar">
        <span class="stat-chip">Total: <strong>{{ justificaciones().length }}</strong></span>
        <span class="stat-chip warn">Pendientes: <strong>{{ countEstado('PENDIENTE') }}</strong></span>
        <span class="stat-chip success">Aprobadas: <strong>{{ countEstado('APROBADA') }}</strong></span>
        <span class="stat-chip danger">Rechazadas: <strong>{{ countEstado('RECHAZADA') }}</strong></span>
      </div>

      <app-interactive-grid
        [data]="justificacionesFlat()"
        [columns]="justificacionesColumns"
        [loading]="cargando()"
        [showDelete]="false"
        (rowSelected)="abrirDetalle($event)"
      />
    </div>

    <!-- Dialog: Nueva justificación -->
    <p-dialog header="Nueva Justificación de Falta" [(visible)]="dialogNueva"
      [modal]="true" [style]="{width:'520px'}" [draggable]="false">
      <div class="grid grid-cols-1 gap-3 p-3">
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">UUID de la Asistencia *</label>
          <input pInputText [(ngModel)]="nuevaForm.asistencia_id" placeholder="id de la asistencia" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Tipo de Justificación *</label>
          <p-select [options]="tiposJust" optionLabel="label" optionValue="value"
            [(ngModel)]="nuevaForm.tipo_justificacion" placeholder="Seleccionar…" />
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Motivo *</label>
          <textarea pTextarea [(ngModel)]="nuevaForm.motivo" rows="3"
            placeholder="Descripción del motivo…" style="width:100%"
            [class.p-invalid]="jIntento && !nuevaForm.motivo.trim()"></textarea>
          @if (jIntento && !nuevaForm.motivo.trim()) {
            <small style="color:#dc2626;font-size:.78rem">El motivo es obligatorio</small>
          }
        </div>
        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">URL del Documento de Soporte</label>
          <input pInputText [(ngModel)]="nuevaForm.documento_url" placeholder="https://…" />
        </div>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="dialogNueva=false" />
        <p-button label="Registrar justificación" icon="pi pi-save"
          [loading]="guardando()" (onClick)="guardarNueva()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog: Rechazo con motivo -->
    <p-dialog header="Rechazar Justificación" [(visible)]="dialogRechazo"
      [modal]="true" [style]="{width:'440px'}" [draggable]="false">
      <div class="p-3">
        <label class="text-sm font-medium block mb-1">Motivo del rechazo *</label>
        <textarea pTextarea [(ngModel)]="motivoRechazo" rows="4"
          placeholder="Explique el motivo del rechazo…" style="width:100%"></textarea>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="dialogRechazo=false" />
        <p-button label="Confirmar rechazo" severity="danger" icon="pi pi-times"
          [loading]="guardando()" (onClick)="confirmarRechazo()" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .apex-page { padding: 1rem; }
    .apex-toolbar { display:flex; align-items:center; justify-content:space-between; margin-bottom:.75rem; flex-wrap:wrap; gap:.5rem; }
    .apex-title { margin:0; font-size:1.25rem; font-weight:600; }
    .apex-toolbar-actions { display:flex; gap:.5rem; align-items:center; flex-wrap:wrap; }
    .stats-bar { display:flex; gap:.75rem; margin-bottom:.75rem; flex-wrap:wrap; }
    .stat-chip { background:var(--surface-100); border:1px solid var(--surface-200); padding:.2rem .75rem; border-radius:12px; font-size:.8rem; }
    .stat-chip.warn { border-color:var(--yellow-400); background:var(--yellow-50); }
    .stat-chip.success { border-color:var(--green-400); background:var(--green-50); }
    .stat-chip.danger { border-color:var(--red-400); background:var(--red-50); }
  `],
})
export class JustificacionesComponent implements OnInit {
  private api = inject(ApiService);
  private notify = inject(ApexNotificationService);

  readonly justificacionesColumns: ColumnConfig[] = [
    { field: 'alumno_nombre',    header: 'Alumno' },
    { field: 'fecha_str',        header: 'Fecha Clase',  width: '110px' },
    { field: 'estatus_asistencia', header: 'Asistencia', width: '100px' },
    { field: 'tipo_justificacion', header: 'Tipo',       width: '110px' },
    { field: 'motivo_str',       header: 'Motivo' },
    { field: 'estado',           header: 'Estado',       width: '100px' },
  ];

  readonly justificacionesFlat = computed(() =>
    this.justificaciones().map(j => ({
      ...j,
      fecha_str:  j.fecha_clase ? new Date(j.fecha_clase).toLocaleDateString('es-MX') : '—',
      motivo_str: j.motivo && j.motivo.length > 60 ? j.motivo.slice(0, 60) + '…' : (j.motivo ?? ''),
    }))
  );

  justificaciones = signal<Justificacion[]>([]);
  cargando        = signal(false);
  guardando       = signal(false);

  dialogNueva  = false;
  dialogRechazo = false;
  filtroEstudianteId = '';
  filtroEstado = '';
  jIntento = false;
  motivoRechazo = '';
  rechazandoId: string | null = null;

  tiposJust = TIPOS_JUST;
  estadosOpt = ESTADOS_OPT;

  nuevaForm = { asistencia_id: '', tipo_justificacion: 'MEDICA', motivo: '', documento_url: '' };

  ngOnInit() { this.cargar(); }

  cargar() {
    this.cargando.set(true);
    const params: any = {};
    if (this.filtroEstudianteId) params.estudiante_id = this.filtroEstudianteId;
    if (this.filtroEstado) params.estado = this.filtroEstado;
    this.api.get<Justificacion[]>('/justificaciones', params).subscribe({
      next: d => { this.justificaciones.set(d); this.cargando.set(false); },
      error: () => { this.cargando.set(false); this.notify.error('Error al cargar justificaciones'); },
    });
  }

  abrirNueva() {
    this.nuevaForm = { asistencia_id: '', tipo_justificacion: 'MEDICA', motivo: '', documento_url: '' };
    this.jIntento = false;
    this.dialogNueva = true;
  }

  guardarNueva() {
    this.jIntento = true;
    if (!this.nuevaForm.asistencia_id || !this.nuevaForm.motivo.trim()) {
      this.notify.warning('Asistencia y motivo son obligatorios');
      return;
    }
    this.guardando.set(true);
    this.api.post('/justificaciones', this.nuevaForm).subscribe({
      next: () => { this.guardando.set(false); this.dialogNueva = false; this.notify.success('Justificación registrada'); this.cargar(); },
      error: e => { this.guardando.set(false); this.notify.error(e.error?.detail ?? 'Error al registrar'); },
    });
  }

  resolver(j: Justificacion, accion: string) {
    this.api.post(`/justificaciones/${j.id}/resolver`, { accion }).subscribe({
      next: (r: any) => { this.notify.success(`Justificación ${r.estado}`); this.cargar(); },
      error: e => this.notify.error(e.error?.detail ?? 'Error'),
    });
  }

  abrirRechazo(j: Justificacion) {
    this.rechazandoId = j.id;
    this.motivoRechazo = '';
    this.dialogRechazo = true;
  }

  confirmarRechazo() {
    if (!this.motivoRechazo.trim()) { this.notify.warning('El motivo es obligatorio'); return; }
    this.guardando.set(true);
    this.api.post(`/justificaciones/${this.rechazandoId}/resolver`,
      { accion: 'RECHAZAR', motivo_rechazo: this.motivoRechazo }).subscribe({
      next: () => { this.guardando.set(false); this.dialogRechazo = false; this.notify.success('Justificación rechazada'); this.cargar(); },
      error: e => { this.guardando.set(false); this.notify.error(e.error?.detail ?? 'Error'); },
    });
  }

  abrirDetalle(j: Justificacion) {
    if (j.estado === 'PENDIENTE') this.notify.info(`Asistencia: ${j.estatus_asistencia} | ${j.motivo}`);
  }

  countEstado(estado: string): number {
    return this.justificaciones().filter(j => j.estado === estado).length;
  }

  estadoSev(e: string): TagSev {
    const m: Record<string, TagSev> = { PENDIENTE: 'warn', APROBADA: 'success', RECHAZADA: 'danger' };
    return m[e] ?? 'secondary';
  }

  asistSev(e: string): TagSev {
    const m: Record<string, TagSev> = { PRESENTE: 'success', FALTA: 'danger', TARDE: 'warn', TARDANZA: 'warn' };
    return m[e] ?? 'secondary';
  }
}

import { Component, OnInit, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../core/services/api.service';
import { ButtonModule } from 'primeng/button';
import { SelectModule } from 'primeng/select';
import { ToastModule } from 'primeng/toast';
import { MessageService } from 'primeng/api';
import { ApexNotificationService } from 'apex-component-library';
import { ContextService } from '../../core/services/context.service';
import { ExportService, ExportColumn } from '../../core/services/export.service';

interface GrupoRaw {
  id: string; nombre_grupo: string;
  semestre: string; numero_grado: number;
  nivel: string; plantel: string; plantel_id: string; ciclo: string;
}
interface AlumnoOpt { value: string; label: string; }
interface MateriaKardex {
  materia: string; clave: string | null;
  ordinario: number | null; extraordinario: number | null;
  definitiva: number | null; acreditada: boolean; inasistencias: number;
}
interface Kardex {
  alumno: {
    alumno: string; matricula: string; curp: string;
    semestre: string; grupo: string; plantel: string; ciclo: string;
  } | null;
  escala: string;
  materias: MateriaKardex[];
  promedio_general: number | null;
  materias_acreditadas: number;
  materias_reprobadas: number;
  total_materias: number;
}

/**
 * Kardex académico para alumnos de Preparatoria UAEMEX (nivel CBU).
 * Muestra historial de calificaciones con escala 0-10, mínimo aprobatorio 6.0,
 * y distingue entre calificación ordinaria, extraordinaria y definitiva según RGEMS.
 * Incluye botón para descargar la boleta PDF generada por FastAPI vía proxy BFF.
 */
@Component({
  selector: 'app-kardex',
  standalone: true,
  imports: [CommonModule, FormsModule, ButtonModule, SelectModule, ToastModule],
  providers: [MessageService],
  template: `
    <p-toast />
    <div class="apex-page">
      <div class="apex-toolbar">
        <h2 class="apex-title">Kardex / Historial Académico — UAEMEX</h2>
        <div class="apex-toolbar-actions">

          <!-- Plantel -->
          <p-select [options]="plantelesOpts()" optionLabel="label" optionValue="value"
            placeholder="Plantel…" [(ngModel)]="plantelSel"
            [disabled]="isPlantelDisabled()"
            (ngModelChange)="onPlantelChange()" style="min-width:160px" />

          <!-- Semestre -->
          <p-select [options]="semestresOpts()" optionLabel="label" optionValue="value"
            placeholder="Semestre…" [(ngModel)]="semestreSel"
            (ngModelChange)="onSemestreChange()"
            [disabled]="!plantelSel" style="min-width:140px" />

          <!-- Grupo -->
          <p-select [options]="gruposOpts()" optionLabel="label" optionValue="value"
            placeholder="Grupo…" [(ngModel)]="grupoSel"
            (ngModelChange)="onGrupoChange($event)"
            [disabled]="!semestreSel" style="min-width:110px" />

          <!-- Alumno -->
          <p-select [options]="alumnosOpts()" optionLabel="label" optionValue="value"
            placeholder="Alumno…" [(ngModel)]="alumnoSel"
            [disabled]="!grupoSel" [filter]="true" filterBy="label"
            style="min-width:240px" />

          <p-button label="Consultar" icon="pi pi-search" size="small" (onClick)="cargar()"
            [loading]="cargando()" [disabled]="!alumnoSel" />

          @if (data()?.alumno) {
            <p-button label="Excel" icon="pi pi-file-excel" size="small" severity="success"
              [outlined]="true" (onClick)="exportar()" />
            <p-button label="Constancia PDF" icon="pi pi-file-pdf" size="small" severity="danger"
              [outlined]="true" [loading]="descargando()" (onClick)="descargarPdf()" />
          }
        </div>
      </div>

      @if (data()?.alumno; as a) {
        <div class="ficha">
          <div><span class="lbl">Alumno</span><span class="val">{{ a.alumno }}</span></div>
          <div><span class="lbl">Matrícula</span><span class="val">{{ a.matricula }}</span></div>
          <div><span class="lbl">CURP</span><span class="val">{{ a.curp }}</span></div>
          <div><span class="lbl">Semestre / Grupo</span><span class="val">{{ a.semestre }} · {{ a.grupo }}</span></div>
          <div><span class="lbl">Plantel</span><span class="val">{{ a.plantel }}</span></div>
          <div><span class="lbl">Ciclo</span><span class="val">{{ a.ciclo }}</span></div>
        </div>

        <table class="kardex">
          <thead>
            <tr>
              <th class="left">Asignatura</th>
              <th>Clave</th>
              <th>Ordinario</th>
              <th>Extraord.</th>
              <th>Definitiva</th>
              <th>Estatus</th>
              <th>Inasist.</th>
            </tr>
          </thead>
          <tbody>
            @for (m of data()!.materias; track m.materia) {
              <tr>
                <td class="left">{{ m.materia }}</td>
                <td>{{ m.clave || '—' }}</td>
                <td>{{ fmt(m.ordinario) }}</td>
                <td>{{ fmt(m.extraordinario) }}</td>
                <td class="def" [class.rep]="!m.acreditada">{{ fmt(m.definitiva) }}</td>
                <td [class.ok]="m.acreditada" [class.rep]="!m.acreditada">
                  {{ m.acreditada ? 'Acreditada' : 'No acreditada' }}
                </td>
                <td>{{ m.inasistencias }}</td>
              </tr>
            }
          </tbody>
          <tfoot>
            <tr>
              <td class="left" colspan="4">
                Promedio general: <strong>{{ fmt(data()!.promedio_general) }}</strong>
              </td>
              <td colspan="3" class="right">
                Acreditadas: <strong>{{ data()!.materias_acreditadas }}</strong> /
                {{ data()!.total_materias }}
                @if (data()!.materias_reprobadas) {
                  · <span class="rep">Reprobadas: {{ data()!.materias_reprobadas }}</span>
                }
              </td>
            </tr>
          </tfoot>
        </table>

        <p class="nota">{{ data()!.escala }}. Definitiva = ordinario si ≥ 6.0; en caso
          contrario, la calificación de examen extraordinario.</p>

      } @else if (!cargando()) {
        <p class="text-center text-gray-500 py-6">
          Selecciona plantel, semestre, grupo y alumno para consultar el kardex.
        </p>
      }
    </div>
  `,
  styles: [`
    .apex-page { padding: 1rem; }
    .apex-toolbar { display:flex; align-items:flex-start; justify-content:space-between; margin-bottom:1rem; flex-wrap:wrap; gap:.5rem; }
    .apex-title { margin:0; font-size:1.25rem; font-weight:600; }
    .apex-toolbar-actions { display:flex; gap:.5rem; align-items:center; flex-wrap:wrap; }
    .ficha { display:grid; grid-template-columns:repeat(3,1fr); gap:.5rem 1rem; background:var(--surface-100);
             border:1px solid var(--surface-300); border-radius:6px; padding:.8rem 1rem; margin-bottom:1rem; }
    .ficha .lbl { display:block; font-size:.65rem; text-transform:uppercase; color:var(--text-color-secondary); letter-spacing:.04em; }
    .ficha .val { font-weight:600; font-size:.9rem; }
    table.kardex { width:100%; border-collapse:collapse; font-size:.85rem; }
    .kardex th, .kardex td { border:1px solid var(--surface-300); padding:.35rem .6rem; text-align:center; }
    .kardex th { background:var(--surface-200); font-weight:600; }
    .kardex .left { text-align:left; }
    .kardex .right { text-align:right; }
    .kardex td.def { font-weight:700; }
    .kardex .ok  { color:var(--green-600); font-weight:600; }
    .kardex .rep { color:var(--red-600); font-weight:600; }
    .kardex tfoot td { background:var(--surface-100); }
    .nota { font-size:.78rem; color:var(--text-color-secondary); margin-top:.6rem; }
  `],
})
export class KardexComponent implements OnInit {
  private api      = inject(ApiService);
  private notify   = inject(ApexNotificationService);
  private exporter = inject(ExportService);
  private ctx      = inject(ContextService);

  // ── Cascada: Plantel → Semestre → Grupo → Alumno ────────────────────────
  private _grupos  = signal<GrupoRaw[]>([]);
  private _alumnos = signal<AlumnoOpt[]>([]);

  plantelSel  = '';
  semestreSel = '';
  grupoSel    = '';
  alumnoSel   = '';

  cargando     = signal(false);
  descargando  = signal(false);
  data         = signal<Kardex | null>(null);

  readonly isPlantelDisabled = computed(() => (this.ctx.nivelAcceso() ?? 0) > 2);

  // Client-side derived options (single API call for grupos)
  plantelesOpts = computed(() => {
    const seen = new Set<string>();
    return this._grupos()
      .filter(g => { const ok = !seen.has(g.plantel); seen.add(g.plantel); return ok; })
      .map(g => ({ value: g.plantel, label: g.plantel }));
  });

  semestresOpts = computed(() => {
    const seen = new Set<string>();
    return this._grupos()
      .filter(g => g.plantel === this.plantelSel)
      .filter(g => { const ok = !seen.has(g.semestre); seen.add(g.semestre); return ok; })
      .sort((a, b) => a.numero_grado - b.numero_grado)
      .map(g => ({ value: g.semestre, label: g.semestre }));
  });

  gruposOpts = computed(() =>
    this._grupos()
      .filter(g => g.plantel === this.plantelSel && g.semestre === this.semestreSel)
      .map(g => ({ value: g.id, label: `Grupo ${g.nombre_grupo}` }))
  );

  alumnosOpts = computed(() => this._alumnos());

  ngOnInit() {
    this.api.get<GrupoRaw[]>('/reportes/kardex/grupos').subscribe({
      next: g => {
        this._grupos.set(g);
        const ctxPlantel = this.ctx.plantel();
        if (ctxPlantel) this.plantelSel = ctxPlantel.nombre_plantel ?? '';
      },
      error: () => this.notify.error('No se pudieron cargar los grupos UAEMEX'),
    });
  }

  onPlantelChange() {
    this.semestreSel = ''; this.grupoSel = ''; this.alumnoSel = '';
    this._alumnos.set([]); this.data.set(null);
  }

  onSemestreChange() {
    this.grupoSel = ''; this.alumnoSel = '';
    this._alumnos.set([]); this.data.set(null);
  }

  onGrupoChange(grupoId: string) {
    this.alumnoSel = ''; this._alumnos.set([]); this.data.set(null);
    if (!grupoId) return;
    this.api.get<any[]>(`/reportes/kardex/grupos/${grupoId}/alumnos`).subscribe({
      next: list => this._alumnos.set(list.map(a => ({
        value: a['id'], label: `${a['nombre']} (${a['matricula'] ?? '—'})`,
      }))),
      error: () => this.notify.error('No se pudieron cargar los alumnos del grupo'),
    });
  }

  fmt(v: number | null): string {
    return v === null || v === undefined ? '—' : Number(v).toFixed(1);
  }

  cargar() {
    if (!this.alumnoSel) return;
    this.cargando.set(true);
    this.data.set(null);
    this.api.get<Kardex>(`/reportes/kardex/${this.alumnoSel}`).subscribe({
      next: d => { this.data.set(d); this.cargando.set(false); },
      error: e => {
        this.cargando.set(false);
        this.notify.error(e.error?.message ?? e.error?.detail ?? 'No se encontró kardex UAEMEX');
      },
    });
  }

  descargarPdf() {
    if (!this.alumnoSel) return;
    this.descargando.set(true);
    this.api.getBlob(`/boletas/uaemex/${this.alumnoSel}`).subscribe({
      next: blob => {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        const k = this.data();
        a.href = url;
        a.download = `constancia_uaemex_${k?.alumno?.matricula ?? this.alumnoSel}.pdf`;
        a.click();
        URL.revokeObjectURL(url);
        this.descargando.set(false);
      },
      error: () => {
        this.notify.error('No se pudo descargar la constancia UAEMEX');
        this.descargando.set(false);
      },
    });
  }

  exportar() {
    const k = this.data();
    if (!k?.alumno) return;
    const columns: ExportColumn[] = [
      { field: 'materia', header: 'Asignatura' },
      { field: 'clave', header: 'Clave' },
      { field: 'ordinario', header: 'Ordinario', format: v => this.fmt(v) },
      { field: 'extraordinario', header: 'Extraordinario', format: v => this.fmt(v) },
      { field: 'definitiva', header: 'Definitiva', format: v => this.fmt(v) },
      { field: 'estatus', header: 'Estatus' },
      { field: 'inasistencias', header: 'Inasistencias' },
    ];
    const data = k.materias.map(m => ({
      ...m, estatus: m.acreditada ? 'Acreditada' : 'No acreditada',
    }));
    this.exporter.toXLSX(data, columns, 'Kardex UAEMEX', `kardex_${k.alumno.matricula}`);
    this.notify.success('Kardex exportado');
  }
}

import { Component, inject, OnInit, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';

import { ButtonModule }        from 'primeng/button';
import { CardModule }          from 'primeng/card';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';
import { TagModule }           from 'primeng/tag';
import { TabsModule }          from 'primeng/tabs';
import { DialogModule }        from 'primeng/dialog';
import { SelectModule }        from 'primeng/select';
import { AutoCompleteModule }  from 'primeng/autocomplete';
import { TextareaModule }      from 'primeng/textarea';
import { InputTextModule }     from 'primeng/inputtext';
import { TooltipModule }       from 'primeng/tooltip';
import { ProgressBarModule }   from 'primeng/progressbar';
import { PanelModule }         from 'primeng/panel';
import { DividerModule }       from 'primeng/divider';
import { SkeletonModule }      from 'primeng/skeleton';
import { ChipModule }          from 'primeng/chip';

import { ApexNotificationService } from 'apex-component-library';

import { ApiService }     from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';
import { ExportService, ExportColumn } from '../../core/services/export.service';

type TagSeverity = 'success' | 'info' | 'warn' | 'danger' | 'secondary' | 'contrast';

interface LearningPath {
  id: string;
  nombre: string;
  descripcion: string | null;
  criterio_activacion: string;
  umbral_activacion: number | null;
  is_active: boolean;
  total_recursos: number;
}

interface Recurso {
  id: string;
  orden: number;
  tipo: string;
  titulo: string;
  descripcion: string | null;
  url_recurso: string | null;
  duracion_min: number | null;
  obligatorio: boolean;
}

interface Asignacion {
  id: string;
  path_id: string;
  path_nombre: string;
  estudiante_id: string;
  motivo: string;
  estatus: string;
  pct_completado: number;
  fccreacion: string;
  alumno_nombre?: string;
  ia_recomendacion?: IaRecomendacion | null;
}

interface IaRecomendacion {
  resumen: string;
  fortalezas: string[];
  areas_mejora: string[];
  estrategias: string[];
  recursos_priorizados: string[];
  mensaje_motivacional: string;
}

interface AlertaResumen {
  tipo_alerta: string;
  nivel_riesgo: string;
  count: number;
}

const CRITERIO_LABELS: Record<string, string> = {
  MANUAL:       'Manual',
  REPROBACION:  'Reprobación',
  AUSENTISMO:   'Ausentismo',
  RIESGO_ALTO:  'Riesgo alto',
};

const ESTATUS_SEV: Record<string, TagSeverity> = {
  PENDIENTE:    'secondary',
  EN_PROGRESO:  'info',
  COMPLETADO:   'success',
  ABANDONADO:   'danger',
};

const TIPO_ICON: Record<string, string> = {
  VIDEO:     'pi-play-circle',
  PDF:       'pi-file-pdf',
  EJERCICIO: 'pi-pencil',
  ENLACE:    'pi-link',
  QUIZ:      'pi-check-circle',
};

/**
 * Módulo de rutas de aprendizaje personalizadas.
 * Presenta secuencias de contenidos y actividades adaptadas al perfil del alumno,
 * con seguimiento de progreso y recomendaciones generadas por el agente IA.
 */
@Component({
  selector: 'app-learning-paths',
  standalone: true,
  imports: [
    CommonModule, FormsModule, RouterModule,
    ButtonModule, CardModule, TagModule, TabsModule, InteractiveGridComponent,
    DialogModule, SelectModule, AutoCompleteModule, TextareaModule, InputTextModule,
    TooltipModule, ProgressBarModule, PanelModule, DividerModule,
    SkeletonModule, ChipModule,
  ],
  template: `
    <div class="page-header">
      <div>
        <h2 class="page-title">Learning Paths</h2>
        <span class="page-subtitle">Rutas de refuerzo adaptativas para alumnos en riesgo</span>
      </div>
      <div class="header-actions">
        <p-button label="Nueva ruta" icon="pi pi-plus" size="small" (onClick)="abrirNuevePath()" />
      </div>
    </div>

    <!-- KPI strip de alertas -->
    <div class="kpi-strip">
      <div class="kpi-card kpi-danger">
        <span class="kpi-value">{{ totalAlertas() }}</span>
        <span class="kpi-label">Alertas activas</span>
      </div>
      <div class="kpi-card kpi-warning">
        <span class="kpi-value">{{ alertasReprobacion() }}</span>
        <span class="kpi-label">Riesgo reprobación</span>
      </div>
      <div class="kpi-card kpi-info">
        <span class="kpi-value">{{ alertasAusentismo() }}</span>
        <span class="kpi-label">Ausentismo crítico</span>
      </div>
      <div class="kpi-card kpi-success">
        <span class="kpi-value">{{ asignaciones().length }}</span>
        <span class="kpi-label">Asignaciones activas</span>
      </div>
    </div>

    <p-tabs [(value)]="tabActivo">

      <p-tablist>
        <p-tab value="0"><i class="pi pi-list"></i>&nbsp;Rutas disponibles</p-tab>
        <p-tab value="1"><i class="pi pi-users"></i>&nbsp;Asignaciones</p-tab>
      </p-tablist>

      <p-tabpanels>

        <!-- ── Tab 1: Rutas disponibles ──────────────────────────────────── -->
        <p-tabpanel value="0">
          <div class="paths-grid">
            @for (path of paths(); track path.id) {
              <div class="path-card" [class.inactivo]="!path.is_active">
                <div class="path-card-header">
                  <span class="path-nombre">{{ path.nombre }}</span>
                  <p-tag
                    [value]="criterioLabel(path.criterio_activacion)"
                    [severity]="criteriaSev(path.criterio_activacion)"
                    styleClass="text-xs"
                  />
                </div>
                <p class="path-desc">{{ path.descripcion || 'Sin descripción' }}</p>
                <div class="path-stats">
                  <span><i class="pi pi-book"></i> {{ path.total_recursos }} recursos</span>
                  @if (path.umbral_activacion) {
                    <span><i class="pi pi-exclamation-triangle"></i> Umbral: {{ path.umbral_activacion }}</span>
                  }
                </div>
                <div class="path-actions">
                  <p-button
                    icon="pi pi-eye" label="Ver detalle" [text]="true" size="small"
                    (onClick)="verPath(path)"
                  />
                  <p-button
                    icon="pi pi-user-plus" label="Asignar" [text]="true" size="small"
                    (onClick)="abrirAsignar(path)"
                  />
                </div>
              </div>
            }
            @empty {
              <div class="empty-state"><i class="pi pi-inbox"></i><p>No hay rutas definidas</p></div>
            }
          </div>
        </p-tabpanel>

        <!-- ── Tab 2: Asignaciones activas ───────────────────────────────── -->
        <p-tabpanel value="1">
          <div class="filter-row">
            <p-select
              [options]="estatusOpts"
              [(ngModel)]="filtroEstatus"
              optionLabel="label" optionValue="value"
              placeholder="Filtrar por estatus..."
              (onChange)="cargarAsignaciones()"
              styleClass="w-auto"


            [filter]="true" filterPlaceholder="Buscar..."/>
            <p-button icon="pi pi-refresh" [text]="true" size="small"
              ariaLabel="Actualizar asignaciones" pTooltip="Actualizar" (onClick)="cargarAsignaciones()" />
            <p-button icon="pi pi-file" label="Exportar CSV" [text]="true" size="small"
              (onClick)="exportCSV()" />
            <p-button icon="pi pi-file-excel" label="Excel" [text]="true" size="small"
              (onClick)="exportXLSX()" />
          </div>

          <app-interactive-grid
            [data]="asignacionesFlat()"
            [columns]="asignacionesColumns"
            [loading]="cargandoAsig()"
            (rowSelected)="verAsignacion($event)"
          />
        </p-tabpanel>

      </p-tabpanels>

    </p-tabs>

    <!-- ── Dialog: Detalle de ruta ────────────────────────────────────── -->
    <p-dialog
      [(visible)]="showPathDetail"
      [header]="pathSeleccionado()?.nombre || ''"
      [modal]="true" [style]="{width: '700px'}"
    >
      @if (pathSeleccionado()) {
        <div class="path-detail">
          <p>{{ pathSeleccionado()!.descripcion }}</p>
          <p-divider />
          <h3>Recursos ({{ recursos().length }})</h3>
          @for (rec of recursos(); track rec.id) {
            <div class="recurso-row">
              <i [class]="'pi ' + tipoIcon(rec.tipo)" class="recurso-icon"></i>
              <div class="recurso-info">
                <strong>{{ rec.orden }}. {{ rec.titulo }}</strong>
                @if (rec.descripcion) { <p class="text-sm text-secondary">{{ rec.descripcion }}</p> }
              </div>
              <div class="recurso-meta">
                @if (rec.duracion_min) { <span>{{ rec.duracion_min }} min</span> }
                @if (!rec.obligatorio) { <p-tag value="Opcional" severity="secondary" /> }
                @if (rec.url_recurso) {
                  <a [href]="rec.url_recurso" target="_blank" class="btn-link">
                    <i class="pi pi-external-link"></i>
                  </a>
                }
              </div>
            </div>
          }
          @empty {
            <p class="text-secondary">Esta ruta no tiene recursos aún.</p>
          }
        </div>
      }
    </p-dialog>

    <!-- ── Dialog: Nueva ruta ─────────────────────────────────────────── -->
    <p-dialog
      [(visible)]="showNuevePath"
      header="Nueva ruta de refuerzo"
      [modal]="true" [style]="{width: '520px'}"
    >
      <div class="form-grid">
        <label>Nombre *</label>
        <input pInputText [(ngModel)]="form.nombre" placeholder="Ej. Refuerzo matemáticas" />

        <label>Descripción</label>
        <textarea pTextarea [(ngModel)]="form.descripcion" rows="3" placeholder="Objetivo y contenido..."></textarea>

        <label>Criterio de activación</label>
        <p-select
          [options]="criterioOpts"
          [(ngModel)]="form.criterio_activacion"
          optionLabel="label" optionValue="value"


        [filter]="true" filterPlaceholder="Buscar..."/>

        @if (form.criterio_activacion !== 'MANUAL') {
          <label>Umbral</label>
          <input pInputText type="number" [(ngModel)]="form.umbral_activacion"
            placeholder="{{ form.criterio_activacion === 'REPROBACION' ? 'Ej: 6.0' : 'Ej: 80' }}" />
        }
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="showNuevePath = false" />
        <p-button label="Crear ruta" icon="pi pi-check" (onClick)="crearPath()" [disabled]="!form.nombre" />
      </ng-template>
    </p-dialog>

    <!-- ── Dialog: Recomendación IA ─────────────────────────────────── -->
    <p-dialog
      [(visible)]="showIA"
      [header]="'Recomendación IA — ' + (asigSeleccionada()?.alumno_nombre || '')"
      [modal]="true" [style]="{width: '680px'}" [closable]="!iaGenerando()">
      @if (iaGenerando()) {
        <div class="ia-loading">
          <i class="pi pi-sparkles ia-spinner"></i>
          <p>Claude está analizando el perfil académico del alumno...</p>
          <p-skeleton height="1.5rem" styleClass="mb-2" />
          <p-skeleton height="1.5rem" width="80%" styleClass="mb-2" />
          <p-skeleton height="1.5rem" width="60%" />
        </div>
      } @else if (iaResult()) {
        <div class="ia-result">
          <div class="ia-resumen">
            <i class="pi pi-info-circle"></i>
            <p>{{ iaResult()!.resumen }}</p>
          </div>
          <div class="ia-grid">
            <div class="ia-section">
              <h5><i class="pi pi-check-circle" style="color:var(--green-500)"></i> Fortalezas</h5>
              @for (f of iaResult()!.fortalezas; track f) {
                <p-chip [label]="f" styleClass="chip-success mb-1" />
              }
            </div>
            <div class="ia-section">
              <h5><i class="pi pi-exclamation-triangle" style="color:var(--orange-500)"></i> Áreas de mejora</h5>
              @for (a of iaResult()!.areas_mejora; track a) {
                <p-chip [label]="a" styleClass="chip-warn mb-1" />
              }
            </div>
          </div>
          <p-divider />
          <h5><i class="pi pi-lightbulb" style="color:var(--yellow-500)"></i> Estrategias recomendadas</h5>
          <ol class="ia-list">
            @for (e of iaResult()!.estrategias; track e) { <li>{{ e }}</li> }
          </ol>
          <h5><i class="pi pi-book" style="color:var(--primary-color)"></i> Empieza por estos recursos</h5>
          <ul class="ia-list">
            @for (r of iaResult()!.recursos_priorizados; track r) { <li>{{ r }}</li> }
          </ul>
          <div class="ia-motivacional">
            <i class="pi pi-heart"></i>
            <em>{{ iaResult()!.mensaje_motivacional }}</em>
          </div>
        </div>
      } @else {
        <div class="ia-prompt">
          <i class="pi pi-sparkles" style="font-size:2rem;color:var(--primary-color)"></i>
          <p>Claude analizará el historial de calificaciones, asistencia y recursos de la ruta asignada para generar recomendaciones personalizadas.</p>
          <p-button label="Generar análisis con IA" icon="pi pi-sparkles"
            (onClick)="generarIA()" />
        </div>
      }
      <ng-template pTemplate="footer">
        @if (!iaGenerando()) {
          <p-button label="Cerrar" [text]="true" (onClick)="showIA = false" />
          @if (iaResult()) {
            <p-button label="Regenerar" icon="pi pi-refresh" [text]="true"
              severity="secondary" (onClick)="generarIA()" />
          }
        }
      </ng-template>
    </p-dialog>

    <!-- ── Dialog: Asignar a alumno ───────────────────────────────────── -->
    <p-dialog
      [(visible)]="showAsignar"
      [header]="'Asignar: ' + (pathAsignar()?.nombre || '')"
      [modal]="true" [style]="{width: '440px'}"
    >
      <div class="form-grid">
        <label>Alumno *</label>
        <p-autoComplete
          [(ngModel)]="formAsig._alumnoObj"
          [suggestions]="alumnosSuggAsig()"
          (completeMethod)="buscarAlumnosAsig($event)"
          optionLabel="nombre_completo"
          [forceSelection]="true"
          placeholder="Buscar alumno..."
          (onSelect)="onAlumnoAsigSelect($event.value)"
        />
        <label>Motivo</label>
        <p-select
          [options]="motivoOpts"
          [(ngModel)]="formAsig.motivo"
          optionLabel="label" optionValue="value"


        [filter]="true" filterPlaceholder="Buscar..."/>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="showAsignar = false" />
        <p-button label="Asignar" icon="pi pi-user-plus" (onClick)="confirmarAsignar()"
          [disabled]="!formAsig.estudiante_id" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .page-header {
      display: flex; justify-content: space-between; align-items: flex-start;
      margin-bottom: 1.25rem;
    }
    .page-title    { font-family: 'Jost', sans-serif; font-size: 1.45rem; font-weight: 700; margin: 0; }
    .page-subtitle { font-size: 0.82rem; color: var(--text-color-secondary); }
    .header-actions { display: flex; gap: .5rem; align-items: center; }

    .paths-grid {
      display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
      gap: 1rem; padding: 1rem 0;
    }
    .path-card {
      background: var(--surface-card); border: 1px solid var(--surface-border);
      border-radius: 8px; padding: 1rem;
      display: flex; flex-direction: column; gap: .5rem;
    }
    .path-card.inactivo { opacity: .6; }
    .path-card-header { display: flex; justify-content: space-between; align-items: flex-start; gap: .5rem; }
    .path-nombre { font-weight: 600; font-size: .95rem; flex: 1; }
    .path-desc { font-size: .82rem; color: var(--text-color-secondary); margin: 0; flex: 1; }
    .path-stats { display: flex; gap: 1rem; font-size: .78rem; color: var(--text-color-secondary); }
    .path-stats i { margin-right: 3px; }
    .path-actions { display: flex; gap: .25rem; margin-top: .25rem; }

    .filter-row { display: flex; gap: .5rem; align-items: center; margin-bottom: 1rem; flex-wrap: wrap; }

    .progress-cell { display: flex; align-items: center; gap: .5rem; }
    .pct-label { font-size: .78rem; min-width: 36px; }

    .path-detail { display: flex; flex-direction: column; gap: .75rem; }
    .recurso-row {
      display: flex; align-items: flex-start; gap: .75rem;
      padding: .5rem; border-radius: 6px;
      border: 1px solid var(--surface-border);
    }
    .recurso-icon { font-size: 1.25rem; color: var(--primary-color); margin-top: 2px; }
    .recurso-info { flex: 1; }
    .recurso-meta { display: flex; align-items: center; gap: .5rem; font-size: .78rem; }
    .btn-link { color: var(--primary-color); }

    .form-grid { display: grid; grid-template-columns: 120px 1fr; gap: .75rem; align-items: center; }
    .form-grid label { font-size: .85rem; font-weight: 500; }
    .form-grid input,
    .form-grid textarea { width: 100%; }

    .empty-state { grid-column: 1 / -1; text-align: center; padding: 3rem; color: var(--text-color-secondary); }
    .empty-state i { font-size: 2rem; display: block; margin-bottom: .5rem; }

    .text-secondary { color: var(--text-color-secondary); }
    .text-sm { font-size: .82rem; }
    .actions-cell { display: flex; gap: .15rem; }

    /* KPI strip */
    .kpi-strip {
      display: grid; grid-template-columns: repeat(4, 1fr); gap: .75rem; margin-bottom: 1.25rem;
    }
    .kpi-card {
      background: var(--surface-card); border: 1px solid var(--surface-border); border-radius: 8px;
      padding: .75rem 1rem; text-align: center; border-top: 3px solid transparent;
    }
    .kpi-danger  { border-top-color: var(--red-500); }
    .kpi-warning { border-top-color: var(--orange-400); }
    .kpi-info    { border-top-color: var(--blue-500); }
    .kpi-success { border-top-color: var(--green-500); }
    .kpi-value { display: block; font-size: 1.6rem; font-weight: 700; line-height: 1.2; }
    .kpi-label { font-size: .75rem; color: var(--text-color-secondary); }

    /* IA dialog */
    .ia-loading { display: flex; flex-direction: column; align-items: center; gap: .75rem; padding: 1.5rem; text-align: center; }
    .ia-spinner { font-size: 2.5rem; color: var(--primary-color); animation: pulse 1.5s infinite; }
    @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:.4} }
    .ia-prompt { display: flex; flex-direction: column; align-items: center; gap: 1rem; padding: 2rem; text-align: center; }
    .ia-resumen { display: flex; gap: .75rem; align-items: flex-start; background: var(--surface-ground); border-radius: 6px; padding: .75rem 1rem; margin-bottom: .75rem; }
    .ia-resumen i { color: var(--primary-color); font-size: 1.1rem; margin-top: 2px; }
    .ia-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: .75rem; }
    .ia-section h5 { margin: 0 0 .5rem; font-size: .85rem; display: flex; align-items: center; gap: .35rem; }
    .ia-section :host ::ng-deep .p-chip { margin: 2px; font-size: .78rem; }
    .ia-list { margin: .25rem 0 .75rem 1rem; padding: 0; font-size: .88rem; line-height: 1.6; }
    .ia-motivacional { background: linear-gradient(135deg,var(--primary-50),var(--surface-ground)); border-radius: 8px; padding: .75rem 1rem; display: flex; gap: .75rem; align-items: center; margin-top: .5rem; }
    .ia-motivacional i { color: var(--red-400); }
    .ia-motivacional em { font-style: italic; font-size: .9rem; }
    h5 { margin: .5rem 0; font-size: .9rem; display: flex; align-items: center; gap: .4rem; }
  `],
})
export class LearningPathsComponent implements OnInit {
  private readonly api    = inject(ApiService);
  private readonly ctx    = inject(ContextService);
  private readonly export = inject(ExportService);
  private readonly notif  = inject(ApexNotificationService);

  tabActivo = '0';

  paths        = signal<LearningPath[]>([]);
  asignaciones = signal<Asignacion[]>([]);
  recursos     = signal<Recurso[]>([]);
  alertas      = signal<AlertaResumen[]>([]);
  cargandoAsig = signal(false);

  pathSeleccionado  = signal<LearningPath | null>(null);
  pathAsignar       = signal<LearningPath | null>(null);
  asigSeleccionada  = signal<Asignacion | null>(null);

  showPathDetail = false;
  showNuevePath  = false;
  showAsignar    = false;
  showIA         = false;

  iaGenerando = signal(false);
  iaResult    = signal<IaRecomendacion | null>(null);

  readonly totalAlertas      = computed(() => this.alertas().reduce((s, a) => s + a.count, 0));
  readonly alertasReprobacion = computed(() =>
    this.alertas().filter(a => a.tipo_alerta === 'RIESGO_REPROBACION').reduce((s, a) => s + a.count, 0));
  readonly alertasAusentismo  = computed(() =>
    this.alertas().filter(a => a.tipo_alerta === 'AUSENTISMO_CRITICO').reduce((s, a) => s + a.count, 0));

  readonly asignacionesFlat = computed(() =>
    this.asignaciones().map(a => ({
      ...a,
      pct_str: `${a.pct_completado}%`,
      fecha_str: a.fccreacion ? new Date(a.fccreacion).toLocaleDateString('es-MX') : '—',
    }))
  );
  readonly asignacionesColumns: ColumnConfig[] = [
    { field: 'alumno_nombre',  header: 'Alumno' },
    { field: 'path_nombre',    header: 'Ruta de aprendizaje' },
    { field: 'motivo',         header: 'Motivo',       width: '110px' },
    { field: 'estatus',        header: 'Estado',       width: '100px' },
    { field: 'pct_str',        header: 'Completado',   width: '100px' },
    { field: 'fecha_str',      header: 'Asignada',     width: '110px' },
  ];

  filtroEstatus: string | null = null;

  form: { nombre: string; descripcion: string; criterio_activacion: string; umbral_activacion: number | null } = {
    nombre: '', descripcion: '', criterio_activacion: 'MANUAL', umbral_activacion: null,
  };
  formAsig: { estudiante_id: string; motivo: string; _alumnoObj: any } = {
    estudiante_id: '', motivo: 'MANUAL', _alumnoObj: null,
  };
  alumnosSuggAsig = signal<any[]>([]);

  readonly criterioOpts = [
    { label: 'Manual',       value: 'MANUAL' },
    { label: 'Reprobación',  value: 'REPROBACION' },
    { label: 'Ausentismo',   value: 'AUSENTISMO' },
    { label: 'Riesgo alto',  value: 'RIESGO_ALTO' },
  ];
  readonly motivoOpts = [
    { label: 'Manual',              value: 'MANUAL' },
    { label: 'Auto-Reprobación',    value: 'AUTO_REPROBACION' },
    { label: 'Auto-Ausentismo',     value: 'AUTO_AUSENTISMO' },
    { label: 'Auto-Riesgo alto',    value: 'AUTO_RIESGO' },
  ];
  readonly estatusOpts = [
    { label: 'Todos',        value: null },
    { label: 'Pendiente',    value: 'PENDIENTE' },
    { label: 'En progreso',  value: 'EN_PROGRESO' },
    { label: 'Completado',   value: 'COMPLETADO' },
    { label: 'Abandonado',   value: 'ABANDONADO' },
  ];

  private readonly exportCols: ExportColumn[] = [
    { field: 'path_nombre',     header: 'Ruta' },
    { field: 'alumno_nombre',   header: 'Alumno' },
    { field: 'motivo',          header: 'Motivo' },
    { field: 'estatus',         header: 'Estatus' },
    { field: 'pct_completado',  header: '% Completado', format: v => `${v}%` },
    { field: 'fccreacion',      header: 'Asignado',
      format: v => v ? new Date(v).toLocaleDateString('es-MX') : '' },
  ];

  ngOnInit(): void {
    this.cargarPaths();
    this.cargarAsignaciones();
    this.cargarAlertas();
  }

  cargarAlertas(): void {
    this.api.get<AlertaResumen[]>('/ai/alertas/resumen').subscribe({
      next: r => this.alertas.set(r),
      error: () => {},
    });
  }

  cargarPaths(): void {
    this.api.get<LearningPath[]>('/learning-paths').subscribe(p => this.paths.set(p));
  }

  cargarAsignaciones(): void {
    this.cargandoAsig.set(true);
    const params: Record<string, string> = {};
    if (this.filtroEstatus) params['estatus'] = this.filtroEstatus;
    this.api.get<Asignacion[]>('/learning-paths/asignaciones', params).subscribe({
      next: a => { this.asignaciones.set(a); this.cargandoAsig.set(false); },
      error: () => this.cargandoAsig.set(false),
    });
  }

  verPath(path: LearningPath): void {
    this.pathSeleccionado.set(path);
    this.api.get<{ recursos: Recurso[] }>(`/learning-paths/${path.id}`).subscribe(d => {
      this.recursos.set(d.recursos || []);
    });
    this.showPathDetail = true;
  }

  abrirAsignar(path: LearningPath): void {
    this.pathAsignar.set(path);
    this.formAsig = { estudiante_id: '', motivo: 'MANUAL', _alumnoObj: null };
    this.showAsignar = true;
  }

  buscarAlumnosAsig(event: { query: string }): void {
    const params: Record<string, any> = { q: event.query };
    const plantelId = this.ctx.plantel()?.id;
    if (plantelId) params['plantel_id'] = plantelId;
    this.api.get<any[]>('/portal/buscar', params).subscribe({
      next: (r: any) => {
        this.alumnosSuggAsig.set((r ?? []).map((a: any) => ({
          id: a.id,
          nombre_completo: [a.nombre, a.apellido_paterno, a.apellido_materno]
            .filter(Boolean).join(' ') + (a.matricula ? ` — ${a.matricula}` : ''),
        })));
      },
      error: () => this.alumnosSuggAsig.set([]),
    });
  }

  onAlumnoAsigSelect(alumno: any): void {
    this.formAsig.estudiante_id = alumno?.id ?? '';
  }

  confirmarAsignar(): void {
    const path = this.pathAsignar();
    if (!path || !this.formAsig.estudiante_id) return;
    const { _alumnoObj, ...payload } = this.formAsig;
    this.api.post(`/learning-paths/${path.id}/asignar`, payload).subscribe(() => {
      this.showAsignar = false;
      this.cargarAsignaciones();
    });
  }

  abrirNuevePath(): void {
    this.form = { nombre: '', descripcion: '', criterio_activacion: 'MANUAL', umbral_activacion: null };
    this.showNuevePath = true;
  }

  crearPath(): void {
    this.api.post('/learning-paths', this.form).subscribe(() => {
      this.showNuevePath = false;
      this.cargarPaths();
    });
  }

  verAsignacion(asig: Asignacion): void {
    this.asigSeleccionada.set(asig);
    this.iaResult.set(asig.ia_recomendacion ?? null);
    this.showIA = true;
  }

  abrirIA(asig: Asignacion): void {
    this.asigSeleccionada.set(asig);
    this.iaResult.set(asig.ia_recomendacion ?? null);
    this.showIA = true;
  }

  generarIA(): void {
    const asig = this.asigSeleccionada();
    if (!asig) return;
    this.iaGenerando.set(true);
    this.iaResult.set(null);
    this.api.post<{ ia_recomendacion: IaRecomendacion }>(
      `/learning-paths/asignaciones/${asig.id}/recomendar-ia`, {}
    ).subscribe({
      next: r => {
        this.iaResult.set(r.ia_recomendacion);
        this.iaGenerando.set(false);
        // Actualizar la asignación en la lista local
        this.asignaciones.update(list =>
          list.map(a => a.id === asig.id ? { ...a, ia_recomendacion: r.ia_recomendacion } : a)
        );
        this.notif.success('Análisis IA generado correctamente');
      },
      error: (err) => {
        this.iaGenerando.set(false);
        this.notif.error(err?.error?.detail ?? 'Error al generar análisis IA');
      },
    });
  }

  criterioLabel(c: string): string { return CRITERIO_LABELS[c] ?? c; }
  tipoIcon(t: string): string       { return TIPO_ICON[t] ?? 'pi-file'; }
  estatusSev(e: string): TagSeverity { return ESTATUS_SEV[e] ?? 'secondary'; }
  criteriaSev(c: string): TagSeverity {
    const map: Record<string, TagSeverity> = {
      MANUAL: 'secondary', REPROBACION: 'danger', AUSENTISMO: 'warn', RIESGO_ALTO: 'danger',
    };
    return map[c] ?? 'secondary';
  }

  exportCSV():  void { this.export.toCSV(this.asignaciones(), this.exportCols, 'learning-paths'); }
  exportXLSX(): void { this.export.toXLSX(this.asignaciones(), this.exportCols, 'Learning Paths', 'learning-paths'); }
}

import { Component, OnInit, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule, ReactiveFormsModule } from '@angular/forms';
import { ApiService } from '../../core/services/api.service';
import { ButtonModule } from 'primeng/button';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';
import { DialogModule } from 'primeng/dialog';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { TextareaModule } from 'primeng/textarea';
import { TagModule } from 'primeng/tag';
import { ToastModule } from 'primeng/toast';
import { DatePickerModule } from 'primeng/datepicker';
import { CheckboxModule } from 'primeng/checkbox';
import { ConfirmDialogModule } from 'primeng/confirmdialog';
import { AutoCompleteModule } from 'primeng/autocomplete';
import { MessageService, ConfirmationService } from 'primeng/api';
import { ApexNotificationService } from 'apex-component-library';

interface Licencia {
  id: string;
  personal_id: string;
  nombre_completo?: string;
  tipo_licencia: string;
  fecha_inicio: string;
  fecha_fin: string;
  dias_habiles: number;
  estado: string;
  motivo: string | null;
  observaciones_rh: string | null;
  con_goce_sueldo: boolean;
  row_version: number;
  fecha_creacion: string;
}

/**
 * Módulo de gestión de licencias y permisos del personal (DP-006).
 * Permite registrar, aprobar y consultar licencias médicas, personales y de capacitación.
 * Requiere nivelAcceso 4 (AdminPlantel) o superior.
 */
@Component({
  selector: 'app-licencias',
  standalone: true,
  imports: [
    CommonModule, FormsModule, ReactiveFormsModule,
    ButtonModule, DialogModule,
    InputTextModule, SelectModule, TextareaModule,
    TagModule, ToastModule, DatePickerModule,
    CheckboxModule, ConfirmDialogModule, AutoCompleteModule,
    InteractiveGridComponent,
  ],
  providers: [MessageService, ConfirmationService],
  template: `
    <p-toast />
    <p-confirmDialog />

    <div class="apex-page">
      <div class="apex-toolbar">
        <h2 class="apex-title">Licencias y Permisos de Personal</h2>
        <div class="apex-toolbar-actions">
          <input pInputText [(ngModel)]="filtroNombre" (input)="onFiltroNombre()"
            placeholder="Buscar por nombre…" style="min-width:200px" />
          <p-select [options]="estadoOpts" [(ngModel)]="filtroEstado" placeholder="Todos los estados"
            [showClear]="true" (onChange)="cargar()" style="min-width:160px" />
          <p-select [options]="tipoOpts" [(ngModel)]="filtroTipo" placeholder="Todos los tipos"
            [showClear]="true" (onChange)="cargar()" style="min-width:160px" />
          <p-button label="Nueva Licencia" icon="pi pi-plus" size="small" (onClick)="abrirNueva()" />
        </div>
      </div>

      <app-interactive-grid
        [data]="licenciasFlat()"
        [columns]="licenciaColumns"
        [loading]="cargando()"
        [showDelete]="false"
        (rowSelected)="verDetalle($event)"
      />
    </div>

    <!-- Dialog: Nueva Licencia -->
    <p-dialog header="Solicitar Licencia o Permiso" [(visible)]="dialogNueva"
      [modal]="true" [style]="{width:'580px'}" [draggable]="false">

      <div class="grid grid-cols-2 gap-3 p-2">
        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Personal <span class="text-red-500">*</span></label>
          <p-autocomplete
            [(ngModel)]="personalSeleccionado"
            [suggestions]="personalSugerencias()"
            (completeMethod)="buscarPersonal($event)"
            optionLabel="label"
            [dropdown]="false"
            placeholder="Escriba nombre del empleado…"
            [forceSelection]="true"
            [delay]="300"
            style="width:100%"
          />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Tipo de Licencia <span class="text-red-500">*</span></label>
          <p-select [options]="tipoOpts" [(ngModel)]="form.tipo_licencia" placeholder="Selecciona…" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Goce de Sueldo</label>
          <div class="flex items-center gap-2 mt-2">
            <p-checkbox [(ngModel)]="form.con_goce_sueldo" [binary]="true" inputId="goce" />
            <label for="goce" class="text-sm">Con goce de sueldo</label>
          </div>
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Fecha Inicio <span class="text-red-500">*</span></label>
          <p-datepicker [(ngModel)]="form.fecha_inicio" dateFormat="yy-mm-dd" [showIcon]="true" />
        </div>

        <div class="flex flex-col gap-1">
          <label class="text-sm font-medium">Fecha Fin <span class="text-red-500">*</span></label>
          <p-datepicker [(ngModel)]="form.fecha_fin" dateFormat="yy-mm-dd" [showIcon]="true" />
        </div>

        <div class="col-span-2 flex flex-col gap-1">
          <label class="text-sm font-medium">Motivo</label>
          <textarea pTextarea [(ngModel)]="form.motivo" rows="3" placeholder="Descripción del motivo…"></textarea>
        </div>
      </div>

      <ng-template pTemplate="footer">
        <p-button label="Cancelar" icon="pi pi-times" [text]="true" (onClick)="dialogNueva=false" />
        <p-button label="Guardar" icon="pi pi-save" [loading]="guardando()" (onClick)="guardar()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog: Detalle -->
    <p-dialog header="Detalle de Licencia" [(visible)]="dialogDetalle"
      [modal]="true" [style]="{width:'560px'}" [draggable]="false">
      @if (seleccionada()) {
        <div class="grid grid-cols-2 gap-y-3 gap-x-4 p-2 text-sm">
          <div class="col-span-2"><span class="font-medium">Personal:</span> {{ seleccionada()!.nombre_completo || seleccionada()!.personal_id }}</div>
          <div><span class="font-medium">Tipo:</span> {{ tipoLabel(seleccionada()!.tipo_licencia) }}</div>
          <div><span class="font-medium">Estado:</span>
            <p-tag [value]="seleccionada()!.estado" [severity]="estadoSeverity(seleccionada()!.estado)" class="ml-1" />
          </div>
          <div><span class="font-medium">Inicio:</span> {{ seleccionada()!.fecha_inicio }}</div>
          <div><span class="font-medium">Fin:</span> {{ seleccionada()!.fecha_fin }}</div>
          <div><span class="font-medium">Días hábiles:</span> {{ seleccionada()!.dias_habiles }}</div>
          <div><span class="font-medium">Goce sueldo:</span> {{ seleccionada()!.con_goce_sueldo ? 'Sí' : 'No' }}</div>
          @if (seleccionada()!.motivo) {
            <div class="col-span-2"><span class="font-medium">Motivo:</span> {{ seleccionada()!.motivo }}</div>
          }
          @if (seleccionada()!.observaciones_rh) {
            <div class="col-span-2"><span class="font-medium">Observaciones RH:</span> {{ seleccionada()!.observaciones_rh }}</div>
          }
        </div>
      }
    </p-dialog>

    <!-- Dialog: Rechazar -->
    <p-dialog header="Rechazar Licencia" [(visible)]="dialogRechazar"
      [modal]="true" [style]="{width:'420px'}" [draggable]="false">
      <div class="flex flex-col gap-2 p-2">
        <label class="text-sm font-medium">Motivo de rechazo <span class="text-red-500">*</span></label>
        <textarea pTextarea [(ngModel)]="motivoRechazo" rows="3" placeholder="Indique el motivo…"></textarea>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" [text]="true" (onClick)="dialogRechazar=false" />
        <p-button label="Confirmar rechazo" severity="danger" [loading]="guardando()"
          [disabled]="motivoRechazo.length < 5" (onClick)="confirmarRechazo()" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .apex-page { padding: 1rem; }
    .apex-toolbar {
      display: flex; align-items: center; justify-content: space-between;
      margin-bottom: 1rem; flex-wrap: wrap; gap: 0.5rem;
    }
    .apex-title { margin: 0; font-size: 1.25rem; font-weight: 600; }
    .apex-toolbar-actions { display: flex; gap: 0.5rem; align-items: center; flex-wrap: wrap; }
  `],
})
export class LicenciasComponent implements OnInit {
  private api = inject(ApiService);
  private notify = inject(ApexNotificationService);

  licencias = signal<Licencia[]>([]);
  personalSugerencias = signal<{ label: string; value: string }[]>([]);
  personalSeleccionado: { label: string; value: string } | null = null;

  readonly licenciaColumns: ColumnConfig[] = [
    { field: 'nombrePersonal',  header: 'Personal',     sortable: true, filterable: true },
    { field: 'tipoLabel',       header: 'Tipo',         sortable: true, filterable: true,  width: '140px' },
    { field: 'fecha_inicio',    header: 'Fecha Inicio', sortable: true, filterable: false, width: '110px' },
    { field: 'fecha_fin',       header: 'Fecha Fin',    sortable: true, filterable: false, width: '110px' },
    { field: 'dias_habiles',    header: 'Días',         sortable: true, filterable: false, width: '80px' },
    { field: 'goceLabel',       header: 'Goce',         sortable: true, filterable: true,  width: '90px' },
    { field: 'estado',          header: 'Estado',       sortable: true, filterable: true,  width: '120px' },
    { field: 'motivoCorto',     header: 'Motivo',       sortable: false, filterable: true },
  ];

  readonly licenciasFlat = computed(() =>
    this.licencias().map(lic => ({
      ...lic,
      nombrePersonal: lic.nombre_completo || lic.personal_id,
      tipoLabel: this.tipoOpts.find(o => o.value === lic.tipo_licencia)?.label ?? lic.tipo_licencia,
      goceLabel: lic.con_goce_sueldo ? 'Con goce' : 'Sin goce',
      motivoCorto: lic.motivo ? lic.motivo.slice(0, 60) : '',
    }))
  );

  cargando  = signal(false);
  guardando = signal(false);
  seleccionada = signal<Licencia | null>(null);

  dialogNueva    = false;
  dialogDetalle  = false;
  dialogRechazar = false;

  filtroEstado = '';
  filtroTipo   = '';
  filtroNombre = '';
  motivoRechazo = '';
  licenciaARechazar: Licencia | null = null;

  form = this.resetForm();

  private filtroTimer: ReturnType<typeof setTimeout> | null = null;

  estadoOpts = [
    { label: 'Pendiente',  value: 'PENDIENTE' },
    { label: 'Aprobada',   value: 'APROBADA' },
    { label: 'Rechazada',  value: 'RECHAZADA' },
    { label: 'Cancelada',  value: 'CANCELADA' },
  ];

  tipoOpts = [
    { label: 'Médica',        value: 'MEDICA' },
    { label: 'Maternidad',    value: 'MATERNIDAD' },
    { label: 'Paternidad',    value: 'PATERNIDAD' },
    { label: 'Duelo',         value: 'DUELO' },
    { label: 'Personal',      value: 'PERSONAL' },
    { label: 'Comisión',      value: 'COMISION' },
    { label: 'Capacitación',  value: 'CAPACITACION' },
    { label: 'Otro',          value: 'OTRO' },
  ];

  ngOnInit() { this.cargar(); }

  onFiltroNombre() {
    if (this.filtroTimer) clearTimeout(this.filtroTimer);
    this.filtroTimer = setTimeout(() => this.cargar(), 400);
  }

  cargar() {
    this.cargando.set(true);
    const params: Record<string, string> = {};
    if (this.filtroEstado) params['estado'] = this.filtroEstado;
    if (this.filtroTipo)   params['tipo']   = this.filtroTipo;
    if (this.filtroNombre) params['q']      = this.filtroNombre;
    this.api.get<Licencia[]>('/licencias', params).subscribe({
      next: data => { this.licencias.set(data); this.cargando.set(false); },
      error: () => { this.cargando.set(false); this.notify.error('Error al cargar licencias'); },
    });
  }

  buscarPersonal(event: { query: string }) {
    if (!event.query || event.query.length < 2) { this.personalSugerencias.set([]); return; }
    this.api.get<any>('/profesores', { buscar: event.query }).subscribe({
      next: res => {
        const data = res?.data ?? res ?? [];
        this.personalSugerencias.set(data.map((p: any) => ({
          label: [p.nombre ?? p.persona?.nombre, p.apellido_paterno ?? p.persona?.apellido_paterno, p.apellido_materno ?? p.persona?.apellido_materno].filter(Boolean).join(' '),
          value: p.id,
        })));
      },
      error: () => this.personalSugerencias.set([]),
    });
  }

  abrirNueva() {
    this.form = this.resetForm();
    this.personalSeleccionado = null;
    this.dialogNueva = true;
  }

  guardar() {
    if (!this.personalSeleccionado?.value || !this.form.tipo_licencia || !this.form.fecha_inicio || !this.form.fecha_fin) {
      this.notify.warning('Complete los campos obligatorios');
      return;
    }
    this.guardando.set(true);
    const payload = {
      personal_id:     this.personalSeleccionado.value,
      tipo_licencia:   this.form.tipo_licencia,
      fecha_inicio:    this.toDateStr(this.form.fecha_inicio),
      fecha_fin:       this.toDateStr(this.form.fecha_fin),
      motivo:          this.form.motivo || null,
      con_goce_sueldo: this.form.con_goce_sueldo,
    };
    this.api.post<Licencia>('/licencias', payload).subscribe({
      next: () => {
        this.guardando.set(false);
        this.dialogNueva = false;
        this.notify.success('Licencia registrada');
        this.cargar();
      },
      error: () => { this.guardando.set(false); this.notify.error('Error al guardar'); },
    });
  }

  verDetalle(lic: Licencia) {
    this.seleccionada.set(lic);
    this.dialogDetalle = true;
  }

  aprobar(lic: Licencia) {
    this.api.post<Licencia>(`/licencias/${lic.id}/aprobar`, null).subscribe({
      next: () => { this.notify.success('Licencia aprobada'); this.cargar(); },
      error: (e) => this.notify.error(e.error?.detail ?? 'Error al aprobar'),
    });
  }

  rechazar(lic: Licencia) {
    this.licenciaARechazar = lic;
    this.motivoRechazo = '';
    this.dialogRechazar = true;
  }

  confirmarRechazo() {
    if (!this.licenciaARechazar) return;
    this.guardando.set(true);
    this.api.post<Licencia>(
      `/licencias/${this.licenciaARechazar.id}/rechazar?motivo_rechazo=${encodeURIComponent(this.motivoRechazo)}`,
      null
    ).subscribe({
      next: () => {
        this.guardando.set(false);
        this.dialogRechazar = false;
        this.notify.success('Licencia rechazada');
        this.cargar();
      },
      error: (e) => { this.guardando.set(false); this.notify.error(e.error?.detail ?? 'Error'); },
    });
  }

  cancelar(lic: Licencia) {
    this.api.delete(`/licencias/${lic.id}`).subscribe({
      next: () => { this.notify.success('Licencia cancelada'); this.cargar(); },
      error: (e) => this.notify.error(e.error?.detail ?? 'Error al cancelar'),
    });
  }

  estadoSeverity(estado: string): 'warn' | 'success' | 'danger' | 'secondary' {
    const map: Record<string, 'warn' | 'success' | 'danger' | 'secondary'> = {
      PENDIENTE: 'warn', APROBADA: 'success', RECHAZADA: 'danger', CANCELADA: 'secondary',
    };
    return map[estado] ?? 'secondary';
  }

  tipoLabel(tipo: string): string {
    return this.tipoOpts.find(o => o.value === tipo)?.label ?? tipo;
  }

  private resetForm() {
    return { tipo_licencia: '', fecha_inicio: null as Date | null, fecha_fin: null as Date | null, motivo: '', con_goce_sueldo: true };
  }

  private toDateStr(d: Date | null): string {
    if (!d) return '';
    return d.toISOString().split('T')[0];
  }
}

