      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true" (onClick)="showIncidenteDialog = false" />
        <p-button label="Guardar y Crear Acta" icon="pi pi-save" [loading]="savingInc()" (onClick)="guardarIncidente()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog medicamento -->
    <p-dialog [(visible)]="showMedicamentoDialog" header="Registrar Medicamento Controlado" [modal]="true" [style]="{width:'460px'}">
      <div class="form-fields">
        <div class="field">
          <label>Nombre del Medicamento *</label>
          <input pInputText [(ngModel)]="medForm.nombre_medicamento" />
        </div>
        <div class="field-row">
          <div class="field" style="flex:1">
            <label>Dosis *</label>
            <input pInputText [(ngModel)]="medForm.dosis" placeholder="Ej: 500mg, 1 tableta" />
          </div>
          <div class="field" style="flex:1">
            <label>Vía *</label>
            <p-select [options]="vias" [(ngModel)]="medForm.via_administracion" />
          </div>
        </div>
        <div class="field">
          <label>Frecuencia *</label>
          <input pInputText [(ngModel)]="medForm.frecuencia" placeholder="Ej: Cada 8 horas" />
        </div>
        <div class="field">
          <label>Horario sugerido</label>
          <input pInputText [(ngModel)]="medForm.horario" placeholder="Ej: 08:00, 16:00, 24:00" />
        </div>
        <div class="field">
          <label>Prescrito por</label>
          <input pInputText [(ngModel)]="medForm.prescrito_por" placeholder="Nombre del médico" />
        </div>
        <div class="field">
          <label>Observaciones o indicaciones adicionales</label>
          <textarea pTextarea [(ngModel)]="medForm.observaciones" rows="2" style="width:100%"></textarea>
        </div>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true" (onClick)="showMedicamentoDialog = false" />
        <p-button label="Registrar" icon="pi pi-save" [loading]="savingMed()" (onClick)="guardarMedicamento()" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    :host ::ng-deep .tipo-sangre-select { width: 110px; }
    .cascade-hint { background: #fff8e1; border: 1px solid #ffe082; border-radius: 8px; padding: 0.65rem 1rem; margin-bottom: 0.75rem; font-size: 0.85rem; color: #5d4037; display: flex; align-items: center; gap: 0.5rem; }
    .cascade-hint i { color: #f59e0b; font-size: 1rem; }
    .sec-title { margin: 0.25rem 0 0.1rem; font-size: 0.72rem; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: var(--nevadi-red); }
    .filter-bar { display: flex; gap: 0.75rem; align-items: center; margin-bottom: 1.25rem; flex-wrap: wrap; }
    .filter-select { min-width: 220px; }
    .expediente-layout { display: grid; grid-template-columns: 1fr 1fr; gap: 1.25rem; margin-top: 1rem; }
    @media (max-width: 900px) { .expediente-layout { grid-template-columns: 1fr; } }
    .card-title-row { display: flex; justify-content: space-between; align-items: center; }
    .matricula-badge { background: var(--nevadi-red-lighter); color: var(--nevadi-red-dark); border-radius: 12px; padding: 0.15rem 0.6rem; font-size: 0.78rem; font-weight: 700; }
    .expediente-form { display: flex; flex-direction: column; gap: 0.75rem; }
    .field { display: flex; flex-direction: column; gap: 0.2rem; }
    .field label { font-size: 0.8rem; font-weight: 600; color: var(--text-secondary); }
    .field-row { display: flex; gap: 1rem; }
    .form-fields { display: flex; flex-direction: column; gap: 0.75rem; }
    .field-inline { display: flex; align-items: center; gap: 0.5rem; }
    .field-inline label { font-size: 0.85rem; }
    .flex-buttons { display: flex; gap: 0.75rem; margin-top: 0.75rem; }
    .tab-header-row { display: flex; justify-content: space-between; align-items: center; margin-bottom: 0.75rem; }
    .tab-header-row h4 { margin: 0; font-family: 'Jost', sans-serif; }
  `],
})
export class MedicoComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);
  private readonly notify = inject(ApexNotificationService);

  alumnosOpts = signal<Estudiante[]>([]);
  selectedAlumnoId: string | null = null;

  alumnoSeleccionado = signal<Estudiante | null>(null);
  expediente = signal<ExpedienteMedico | null>(null);
  incidentes = signal<IncidenteMedico[]>([]);
  medicamentos = signal<Medicamento[]>([]);

  savingExp = signal(false);
  savingInc = signal(false);
  savingMed = signal(false);

  showIncidenteDialog = false;
  showMedicamentoDialog = false;

  incForm = { descripcion: '', tratamiento_aplicado: '', requirio_traslado: false, notificado_tutor: false };
  medForm = { nombre_medicamento: '', dosis: '', frecuencia: '', horario: '', via_administracion: 'ORAL', prescrito_por: '', observaciones: '' };

  readonly tiposSangre = ['A+', 'A-', 'B+', 'B-', 'O+', 'O-', 'AB+', 'AB-'];
  readonly tiposSeguro = ['IMSS', 'ISSSTE', 'PRIVADO', 'NINGUNO'];
  readonly vias = ['ORAL', 'TOPICA', 'INHALADA', 'INYECTABLE', 'OFTALMICA', 'OTICA'];

  readonly incidentesTimeline = computed(() =>
    this.incidentes().map(inc => ({
      title: inc.descripcion,
      date: inc.fecha_incidente
        ? new Date(inc.fecha_incidente).toLocaleDateString('es-MX')
        : '—',
      description: [
        inc.tratamiento_aplicado ? `Tratamiento: ${inc.tratamiento_aplicado}` : null,
        inc.requirio_traslado ? 'Requirió traslado de emergencia' : null,
        inc.notificado_tutor  ? 'Tutor notificado' : null,
      ].filter(Boolean).join(' · ') || undefined,
      severity: inc.requirio_traslado ? 'error' : 'warning',
      icon: inc.requirio_traslado ? 'pi pi-exclamation-triangle' : 'pi pi-heart',
    }))
  );

  readonly medicamentosColumns: ColumnConfig[] = [
    { field: 'nombre_medicamento', header: 'Medicamento' },
    { field: 'dosis',              header: 'Dosis',       width: '100px' },
    { field: 'frecuencia',         header: 'Frecuencia',  width: '110px' },
    { field: 'via_administracion', header: 'Vía',         width: '110px' },
  ];

  constructor() {
    // Recargar lista de alumnos cuando cambia el grupo en el contexto global.
    effect(() => {
      const grupo = this.ctx.grupo();
      this.selectedAlumnoId = null;
      this.alumnosOpts.set([]);
      this.alumnoSeleccionado.set(null);
      if (!grupo?.id) return;

      const params: Record<string, any> = { grupo_id: grupo.id };
      const plantelId = this.ctx.plantel()?.id;
      if (plantelId) params['plantel_id'] = plantelId;

      this.api.get<any>('/alumnos', params).subscribe({
        next: resp => {
          const list = resp.data ?? resp;
          this.alumnosOpts.set(list.map((a: any) => ({
            ...a,
            _label: `${a.persona?.apellido_paterno ?? ''} ${a.persona?.nombre ?? ''}`.trim() || a.matricula
          })));
        },
        error: () => this.alumnosOpts.set([])
      });
    });
  }

  ngOnInit(): void {
    // ngOnInit no necesita cargar planteles — la cascada vive en el topbar.
  }

  onAlumnoChange(): void {
    this.alumnoSeleccionado.set(null);
    if (!this.selectedAlumnoId) return;
    const selected = this.alumnosOpts().find(a => a.id === this.selectedAlumnoId);
    if (selected) {
      this.seleccionar(selected);
    }
  }

  seleccionar(a: Estudiante): void {
    this.alumnoSeleccionado.set(a);
    this.cargarExpediente(a.id);
    this.cargarIncidentes(a.id);
    this.cargarMedicamentos(a.id);
  }

  private cargarExpediente(id: string): void {
    this.api.get<ExpedienteMedico>(`/expedientes-medicos/alumno/${id}`)
      .subscribe({ next: e => this.expediente.set(e), error: () => this.expediente.set(null) });
  }

  private cargarIncidentes(id: string): void {
    this.api.get<IncidenteMedico[]>(`/incidentes-medicos/alumno/${id}`)
      .subscribe(r => this.incidentes.set(r));
  }

  private cargarMedicamentos(id: string): void {
    this.api.get<Medicamento[]>(`/salud-avanzada/medicamentos/${id}`)
      .subscribe(r => this.medicamentos.set(r));
  }

  crearExpediente(): void {
    const alumno = this.alumnoSeleccionado();
    if (!alumno) return;
    this.api.post<ExpedienteMedico>('/expedientes-medicos', { estudiante_id: alumno.id }).subscribe({
      next: e => { this.expediente.set(e); this.notify.success('Expediente creado'); },
      error: (e) => this.notify.error('Error', e.error?.detail),
    });
  }

  guardarExpediente(): void {
    const exp = this.expediente();
    if (!exp) return;
    this.savingExp.set(true);
    const { estudiante_id, ...datos } = exp as any;
    this.api.put(`/expedientes-medicos/${exp.id}`, datos).subscribe({
      next: () => { this.savingExp.set(false); this.notify.success('Expediente actualizado'); },
      error: () => this.savingExp.set(false),
    });
  }

  abrirIncidente(): void {
    this.incForm = { descripcion: '', tratamiento_aplicado: '', requirio_traslado: false, notificado_tutor: false };
    this.showIncidenteDialog = true;
  }

  guardarIncidente(): void {
    const alumno = this.alumnoSeleccionado();
    if (!alumno || !this.incForm.descripcion) return;
    this.savingInc.set(true);

    // Primero registrar el incidente médico básico
    const payload = { ...this.incForm, estudiante_id: alumno.id };
    this.api.post<IncidenteMedico>('/incidentes-medicos', payload).subscribe({
      next: (r) => {
        // Generar acta formal en el backend (SB-005)
        const actaPayload = {
          descripcion_detallada: this.incForm.descripcion,
          medidas_tomadas: this.incForm.tratamiento_aplicado || 'Primeros auxilios',
          requirio_traslado: this.incForm.requirio_traslado,
          notificado_familia: this.incForm.notificado_tutor
        };

        this.api.post(`/salud-avanzada/actas-incidente/${r.id}`, actaPayload).subscribe({
          next: () => {
            this.incidentes.update(list => [r, ...list]);
            this.showIncidenteDialog = false;
            this.savingInc.set(false);
            this.notify.success('Incidente registrado y Acta formal generada');
          },
          error: () => {
            this.incidentes.update(list => [r, ...list]);
            this.showIncidenteDialog = false;
            this.savingInc.set(false);
            this.notify.warning('Incidente registrado pero falló la generación de acta formal.');
          }
        });
      },
      error: () => this.savingInc.set(false),
    });
  }

  abrirMedicamento(): void {
    this.medForm = { nombre_medicamento: '', dosis: '', frecuencia: '', horario: '', via_administracion: 'ORAL', prescrito_por: '', observaciones: '' };
    this.showMedicamentoDialog = true;
  }

  guardarMedicamento(): void {
    const alumno = this.alumnoSeleccionado();
    if (!alumno || !this.medForm.nombre_medicamento || !this.medForm.dosis || !this.medForm.frecuencia) {
      this.notify.warning('Completa todos los campos obligatorios');
      return;
    }
    this.savingMed.set(true);
    this.api.post<any>(`/salud-avanzada/medicamentos/${alumno.id}`, this.medForm).subscribe({
      next: () => {
        this.cargarMedicamentos(alumno.id);
        this.showMedicamentoDialog = false;
        this.savingMed.set(false);
        this.notify.success('Medicamento registrado');
      },
      error: () => this.savingMed.set(false),
    });
  }

  suspenderMedicamento(medId: string): void {
    const alumno = this.alumnoSeleccionado();
    if (!alumno) return;
    this.api.delete(`/salud-avanzada/medicamentos/${medId}`).subscribe({
      next: () => {
        this.cargarMedicamentos(alumno.id);
        this.notify.success('Medicamento suspendido');
      },
      error: () => this.notify.error('Error al suspender medicamento'),
    });
  }

  descargarCertificado(): void {
    const alumno = this.alumnoSeleccionado();
    if (!alumno) return;
    this.api.getBlob(`/salud-avanzada/certificado-deportivo/${alumno.id}`).subscribe({
      next: blob => this._downloadBlob(blob, `certificado_deportivo_${alumno.matricula}.pdf`),
      error: () => this.notify.error('Error', 'No se pudo generar el certificado'),
    });
  }

  descargarActa(incidenteId: string): void {
    this.api.getBlob(`/salud-avanzada/incidentes/${incidenteId}/acta-pdf`).subscribe({
      next: blob => this._downloadBlob(blob, `acta_incidente_${incidenteId}.pdf`),
      error: () => this.notify.error('Error', 'No se pudo generar el acta'),
    });
  }

  private _downloadBlob(blob: Blob, filename: string): void {
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    URL.revokeObjectURL(url);
  }
}

import { Component, inject, signal, computed, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { SelectModule } from 'primeng/select';
import { CardModule } from 'primeng/card';
import { ProgressBarModule } from 'primeng/progressbar';
import { TooltipModule } from 'primeng/tooltip';
import { DialogModule } from 'primeng/dialog';
import { TabsModule } from 'primeng/tabs';
import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';
import { ApexNotificationService } from 'apex-component-library';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';

interface MateriaSummary {
  materia_id: string;
  nombre_materia: string;
  calificacion_final: number | null;
  calificacion_calculada: number | null;
  escala_maxima: number;
  minimo_aprobatorio: number;
  score_por_item: Record<string, number>;
}

interface EntregaPendiente {
  id: string;
  titulo: string;
  tipo_item: string;
  fecha_limite: string;
  nombre_materia: string;
  vencida: boolean;
  estatus_entrega: string;
}

interface EntregaHistorial extends EntregaPendiente {
  calificacion_obtenida: number | null;
  comentario_profesor: string | null;
  fecha_entrega: string;
}

/**
 * Panel de progreso académico personal del alumno (nivelAcceso 1).
 * Muestra calificaciones, asistencias, actividades pendientes y metas del período
 * usando datos del contexto activo (plantel + ciclo escolar).
 */
@Component({
  selector: 'app-mi-progreso',
  standalone: true,
  imports: [
    CommonModule, FormsModule, ButtonModule, SelectModule,
    CardModule, ProgressBarModule, TooltipModule,
    DialogModule, TabsModule, InteractiveGridComponent,
  ],
  template: `
<div class="page-header">
  <div class="page-title"><i class="pi pi-chart-line"></i> Mi Progreso</div>
</div>

<p-tabs value="0">
  <!-- ── TAB 1: Resumen por materia ── -->
  <p-tabpanel header="Calificaciones" value="0">
    <div class="materias-grid">
      @for (m of materias(); track m.nombre_materia) {
        <div class="materia-card"
             [class.reprobada]="m.calificacion_final !== null && m.calificacion_final < m.minimo_aprobatorio">
          <div class="materia-nombre">{{ m.nombre_materia }}</div>
          <div [class]="calClass(m.calificacion_final, m.escala_maxima)" class="materia-cal">
            {{ m.calificacion_final ?? '—' }}
          </div>
          <p-progressBar [value]="pctCal(m)" [style]="{'height':'6px','margin':'8px 0'}"
                         [color]="progressColor(m)" [showValue]="false" />
          @if (m.score_por_item) {
            <div class="score-desglose">
              @for (item of itemsScore(m); track item.label) {
                <span class="score-item">{{ item.label }}: <strong>{{ item.val }}</strong></span>
              }
            </div>
          }
          @if (m.calificacion_final !== null && m.calificacion_final < m.minimo_aprobatorio) {
            <small class="text-danger">⚠ En riesgo</small>
          }
        </div>
      }
    </div>
    @if (!materias().length && !cargando()) {
      <p class="text-center text-muted p-4">No hay calificaciones para el período seleccionado.</p>
    }
  </p-tabpanel>

  <!-- ── TAB 2: Tareas pendientes ── -->
  <p-tabpanel header="Tareas pendientes" value="1">
    <app-interactive-grid
      [data]="pendientesFlat()"
      [columns]="pendientesColumns"
      [loading]="cargando()"
    />
  </p-tabpanel>

  <!-- ── TAB 3: Historial de entregas ── -->
  <p-tabpanel header="Historial" value="2">
    <app-interactive-grid
      [data]="historialFlat()"
      [columns]="historialColumns"
      [loading]="cargando()"
    />
  </p-tabpanel>
</p-tabs>

<!-- ── Dialog: subir entrega ── -->
<p-dialog [(visible)]="dialogSubirVisible" header="Subir entrega"
          [modal]="true" [style]="{width:'420px'}">
  @if (entregaActiva) {
    <div>
      <p><strong>{{ entregaActiva.titulo }}</strong></p>
      <p><small>{{ entregaActiva.nombre_materia }}</small></p>
      <div class="field mt-3">
        <label>Archivo</label>
        <input type="file" (change)="onFileChange($event)"
               class="w-full" style="width:100%;padding:4px;border:1px solid #ccc;border-radius:4px" />
      </div>
      <div class="field mt-2">
        <label>Comentario (opcional)</label>
        <textarea [(ngModel)]="comentarioEntrega" rows="3"
                  class="w-full" style="width:100%;padding:6px;border:1px solid #ccc;border-radius:4px"></textarea>
      </div>
    </div>
  }
  <ng-template pTemplate="footer">
    <button pButton label="Cancelar" severity="secondary" (click)="dialogSubirVisible = false"></button>
    <button pButton label="Subir" icon="pi pi-upload" (click)="subirEntrega()" [loading]="subiendoArchivo()"></button>
  </ng-template>
</p-dialog>
  `,
  styles: [`
    .materias-grid { display:grid; grid-template-columns:repeat(auto-fill,minmax(220px,1fr)); gap:16px; padding:8px 0; }
    .materia-card { background:var(--p-surface-0); border:1px solid var(--p-surface-border);
                    border-radius:8px; padding:16px; }
    .materia-card.reprobada { border-left:4px solid #dc2626; }
    .materia-nombre { font-weight:600; margin-bottom:4px; font-size:0.9rem; }
    .materia-cal { font-size:2.4rem; font-weight:700; font-family:'Jost',sans-serif; }
    .score-desglose { display:flex; flex-wrap:wrap; gap:4px; margin-top:8px; }
    .score-item { font-size:0.75rem; background:#f3f4f6; border-radius:4px; padding:2px 6px; }
    .row-vencida td { background:#fff5f5 !important; }
    .cal-excelente { color:#15803d; } .cal-bien { color:#0369a1; }
    .cal-regular   { color:#b45309; } .cal-reprobado { color:#dc2626; }
  `],
})
export class MiProgresoComponent implements OnInit {
  private api = inject(ApiService);
  private ctx = inject(ContextService);
  private readonly notify = inject(ApexNotificationService);

  materias = signal<MateriaSummary[]>([]);
  pendientes = signal<EntregaPendiente[]>([]);
  historial = signal<EntregaHistorial[]>([]);
  cargando = signal(false);

  readonly pendientesFlat = computed(() =>
    this.pendientes().map(t => ({
      ...t,
      fecha_limite_str: t.fecha_limite ? new Date(t.fecha_limite).toLocaleDateString('es-MX') : '—',
      estatus_str: t.estatus_entrega,
    }))
  );
  readonly pendientesColumns: ColumnConfig[] = [
    { field: 'titulo',           header: 'Tarea' },
    { field: 'nombre_materia',   header: 'Materia' },
    { field: 'tipo_item',        header: 'Tipo',        width: '90px' },
    { field: 'fecha_limite_str', header: 'Fecha límite', width: '120px' },
    { field: 'estatus_str',      header: 'Estado',      width: '110px' },
  ];

  readonly historialFlat = computed(() =>
    this.historial().map(e => ({
      ...e,
      fecha_entrega_str: e.fecha_entrega ? new Date(e.fecha_entrega).toLocaleDateString('es-MX') : '—',
      calificacion_str: e.calificacion_obtenida !== null ? String(e.calificacion_obtenida) : '—',
    }))
  );
  readonly historialColumns: ColumnConfig[] = [
    { field: 'titulo',           header: 'Actividad' },
    { field: 'nombre_materia',   header: 'Materia' },
    { field: 'fecha_entrega_str',header: 'Entregada',   width: '110px' },
    { field: 'calificacion_str', header: 'Calificación', width: '100px' },
    { field: 'comentario_profesor', header: 'Feedback' },
  ];
  subiendoArchivo = signal(false);

  dialogSubirVisible = false;
  entregaActiva: EntregaPendiente | null = null;
  archivoSeleccionado: File | null = null;
  comentarioEntrega = '';

  // En producción, el alumno_id viene del token JWT
  alumnoId: string | null = null;

  ngOnInit() {
    // Para demo, se obtiene de ContextService o del perfil del usuario
    this.api.get('/usuarios/mi-perfil').subscribe((u: any) => {
      if (u.estudiante_id) {
        this.alumnoId = u.estudiante_id;
        this.cargarDatos();
      }
    });
  }

  cargarDatos() {
    if (!this.alumnoId) return;
    this.cargando.set(true);

    this.api.get(`/gradebook/alumno/${this.alumnoId}/boleta`).subscribe({
      next: (r: any) => { this.materias.set(r); this.cargando.set(false); },
      error: () => this.cargando.set(false),
    });

    this.api.get(`/entregas/alumno/${this.alumnoId}?solo_pendientes=true`).subscribe(
      (r: any) => this.pendientes.set(r));

    this.api.get(`/entregas/alumno/${this.alumnoId}`).subscribe(
      (r: any) => this.historial.set(r.filter((e: any) => e.estatus_entrega === 'CALIFICADA')));
  }

  abrirSubirEntrega(t: EntregaPendiente) {
    this.entregaActiva = t;
    this.comentarioEntrega = '';
    this.archivoSeleccionado = null;
    this.dialogSubirVisible = true;
  }

  onFileChange(evt: Event) {
    const input = evt.target as HTMLInputElement;
    this.archivoSeleccionado = input.files?.[0] ?? null;
  }

  subirEntrega() {
    if (!this.entregaActiva || !this.alumnoId) return;
    const fd = new FormData();
    fd.append('tarea_id', this.entregaActiva.id);
    fd.append('alumno_id', this.alumnoId);
    if (this.comentarioEntrega) fd.append('comentario', this.comentarioEntrega);
    if (this.archivoSeleccionado) fd.append('archivo', this.archivoSeleccionado);

    this.subiendoArchivo.set(true);
    this.api.post('/entregas', fd).subscribe({
      next: () => {
        this.notify.success('Entrega registrada');
        this.dialogSubirVisible = false;
        this.subiendoArchivo.set(false);
        this.cargarDatos();
      },
      error: () => this.subiendoArchivo.set(false),
    });
  }

  itemsScore(m: MateriaSummary) {
    return Object.entries(m.score_por_item ?? {}).map(([k, v]) => ({ label: k, val: v }));
  }

  pctCal(m: MateriaSummary): number {
    const cal = m.calificacion_final ?? 0;
    return Math.round((cal / m.escala_maxima) * 100);
  }

  progressColor(m: MateriaSummary): string {
    const pct = this.pctCal(m);
    if (pct >= 80) return '#15803d';
    if (pct >= 60) return '#0369a1';
    return '#dc2626';
  }

  calClass(cal: number | null, escala: number): string {
    if (cal === null) return '';
    const ratio = escala >= 100 ? cal / 10 : cal;
    if (ratio >= 9) return 'cal-excelente';
    if (ratio >= 7.5) return 'cal-bien';
    if (ratio >= 6) return 'cal-regular';
    return 'cal-reprobado';
  }

  estatusSev(s: string): 'success' | 'info' | 'warn' | 'danger' | 'secondary' {
    const m: Record<string, any> = { CALIFICADA: 'success', ENTREGADA: 'info', PENDIENTE: 'warn', SIN_ENTREGA: 'danger' };
    return m[s] ?? 'secondary';
  }
}

