export class ReinscripcionComponent implements OnInit {
  private api      = inject(ApiService);
  private ctx      = inject(ContextService);
  private exporter = inject(ExportService);
  private notify   = inject(ApexNotificationService);

  ciclos   = signal<CicloOpt[]>([]);
  alumnos  = signal<any[]>([]);
  reporte  = signal<any>(null);

  cargando  = signal(false);
  validando = signal(false);
  aprobando = signal(false);

  cicloOrigenId:  string | null = null;
  cicloDestinoId: string | null = null;
  plantelFiltro:  string | null = null;
  estadoFiltro:   string | null = null;

  seleccionado    = signal<any>(null);
  dialogVisible   = false;
  confirmAprobarVisible = false;
  mostrarRazonRechazo   = false;
  razonRechazo = '';

  estadoOpts = [
    { label: 'Pendiente',  value: 'PENDIENTE' },
    { label: 'Validado',   value: 'VALIDADO'  },
    { label: 'Aprobado',   value: 'APROBADO'  },
    { label: 'Rechazado',  value: 'RECHAZADO' },
  ];

  readonly columnas: ColumnConfig[] = [
    { field: 'alumno',          header: 'Alumno',       sortable: true,  filterable: true  },
    { field: 'matricula',       header: 'Matrícula',    sortable: true,  filterable: true,  width: '120px' },
    { field: 'grado_grupo',     header: 'Grado / Grupo', sortable: true, filterable: true,  width: '150px' },
    { field: 'nombre_plantel',  header: 'Plantel',      sortable: true,  filterable: true,  width: '150px' },
    { field: 'estado',          header: 'Estado',       sortable: true,  filterable: true,  width: '110px' },
    { field: 'adeudo_str',      header: 'Adeudo',       sortable: true,  filterable: false, width: '110px' },
    { field: 'fecha_val_str',   header: 'Validado',     sortable: false, filterable: false, width: '110px' },
  ];

  readonly totalValidados  = computed(() => this.reporte()?.resumen?.validados  ?? 0);
  readonly totalPendientes = computed(() => this.reporte()?.resumen?.pendientes ?? 0);
  readonly puedeAprobar    = computed(() => this.totalValidados() > 0 && !this.aprobando());

  constructor() {
    effect(() => {
      this.plantelFiltro = this.ctx.plantel()?.id ?? null;
      if (this.cicloDestinoId) {
        this.cargarEstado();
        this.cargarReporte();
      }
    });
  }

  ngOnInit() {
    this.cargarCiclos();
  }

  cargarCiclos() {
    this.api.get('/catalogs/ciclos').subscribe((r: any) =>
      this.ciclos.set(r ?? []));
  }

  onCicloChange() {
    if (this.cicloOrigenId && this.cicloDestinoId) {
      this.cargarEstado();
      this.cargarReporte();
    }
  }

  cargarEstado() {
    if (!this.cicloDestinoId) return;
    this.cargando.set(true);
    let url = `/reinscripcion/${this.cicloDestinoId}/estado?por_pagina=500`;
    if (this.estadoFiltro)  url += `&estado=${this.estadoFiltro}`;
    if (this.plantelFiltro) url += `&plantel_id=${this.plantelFiltro}`;
    this.api.get(url).subscribe({
      next: (r: any) => {
        const flat = (r.data ?? []).map((x: any) => ({
          ...x,
          adeudo_str:   x.tiene_adeudos ? `$${Number(x.monto_adeudado).toFixed(2)}` : '—',
          fecha_val_str: x.fecha_validacion ? x.fecha_validacion.substring(0, 10) : '—',
        }));
        this.alumnos.set(flat);
        this.cargando.set(false);
      },
      error: () => this.cargando.set(false),
    });
  }

  cargarReporte() {
    if (!this.cicloDestinoId) return;
    this.api.get(`/reinscripcion/${this.cicloDestinoId}/reporte`).subscribe(
      (r: any) => this.reporte.set(r)
    );
  }

  validarMasivo() {
    if (!this.cicloOrigenId || !this.cicloDestinoId) return;
    this.validando.set(true);
    this.api.post(
      `/reinscripcion/${this.cicloDestinoId}/validar-masivo?ciclo_origen_id=${this.cicloOrigenId}`,
      {}
    ).subscribe({
      next: (r: any) => {
        this.validando.set(false);
        const res = r.resumen;
        this.notify.success(
          'Validación completada',
          `${res.validados} listos · ${res.bloqueados} con bloqueos`
        );
        this.cargarEstado();
        this.cargarReporte();
      },
      error: () => this.validando.set(false),
    });
  }

  confirmarAprobarMasivo() {
    this.confirmAprobarVisible = true;
  }

  aprobarMasivo() {
    if (!this.cicloOrigenId || !this.cicloDestinoId) return;
    this.aprobando.set(true);
    this.confirmAprobarVisible = false;
    this.api.post(
      `/reinscripcion/${this.cicloDestinoId}/aprobar-masivo?ciclo_origen_id=${this.cicloOrigenId}`,
      {}
    ).subscribe({
      next: (r: any) => {
        this.aprobando.set(false);
        const promo = r.resultado_promocion;
        this.notify.success(
          'Reinscripción completada',
          `${r.aprobados} aprobados · ${promo?.promovidos ?? 0} promovidos`
        );
        this.cargarEstado();
        this.cargarReporte();
      },
      error: (err: any) => {
        this.aprobando.set(false);
        const msg = err?.error?.detail ?? 'Error en la aprobación masiva';
        this.notify.error('Error', typeof msg === 'string' ? msg : JSON.stringify(msg));
      },
    });
  }

  abrirDetalle(row: any) {
    this.seleccionado.set(row);
    this.mostrarRazonRechazo = false;
    this.razonRechazo = '';
    this.dialogVisible = true;
  }

  accionIndividual(accion: 'APROBAR' | 'RECHAZAR') {
    const reg = this.seleccionado();
    if (!reg) return;
    if (accion === 'RECHAZAR' && !this.razonRechazo.trim()) return;
    this.api.patch(`/reinscripcion/${reg.id}`, {
      accion,
      razon_rechazo: accion === 'RECHAZAR' ? this.razonRechazo : null,
    }).subscribe({
      next: () => {
        this.notify.success(
          accion === 'APROBAR' ? 'Alumno aprobado' : 'Alumno rechazado',
          reg.alumno
        );
        this.dialogVisible = false;
        this.cargarEstado();
        this.cargarReporte();
      },
      error: () => this.notify.error('Error', 'No se pudo procesar la acción'),
    });
  }

  exportar() {
    const cols = [
      { field: 'alumno',         header: 'Alumno' },
      { field: 'matricula',      header: 'Matrícula' },
      { field: 'grado_grupo',    header: 'Grado / Grupo' },
      { field: 'nombre_plantel', header: 'Plantel' },
      { field: 'estado',         header: 'Estado' },
      { field: 'adeudo_str',     header: 'Adeudo' },
      { field: 'fecha_val_str',  header: 'Validado', format: (v: any) => v || '—' },
      { field: 'razon_rechazo',  header: 'Razón rechazo' },
    ];
    this.exporter.toXLSX(this.alumnos(), cols, 'Reinscripción', 'reinscripcion');
  }

  estadoSeverity(estado: string | undefined): 'success' | 'info' | 'warn' | 'danger' | 'secondary' {
    const map: Record<string, any> = {
      APROBADO: 'success', VALIDADO: 'info',
      PENDIENTE: 'warn',   RECHAZADO: 'danger',
    };
    return map[estado ?? ''] ?? 'secondary';
  }
}

/**
 * Módulo de Reportes — FASE 18 (Carbone)
 *
 * Tabs:
 *   1. Generador — selecciona alumno + plantilla → descarga PDF
 *   2. Plantillas — gestión de plantillas DOCX/XLSX (solo admin)
 *   3. Estado    — disponibilidad del servicio Carbone
 */
import { Component, OnInit, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { SelectModule } from 'primeng/select';
import { TagModule } from 'primeng/tag';
import { InteractiveGridComponent, ColumnConfig } from '../../shared/components/interactive-grid/interactive-grid.component';
import { TabsModule } from 'primeng/tabs';
import { TooltipModule } from 'primeng/tooltip';
import { FileUploadModule } from 'primeng/fileupload';
import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';
import { AuthService } from '../../core/services/auth.service';
import { ApexNotificationService } from 'apex-component-library';
import { grupoLabel } from '../../core/models';

interface Plantilla {
  id: string;
  nombre: string;
  tipo_documento: string;
  descripcion: string;
  extension: string;
  tamano_bytes: number;
  fccreacion: string;
}

interface Alumno {
  id: string;
  persona?: { nombre: string; apellido_paterno: string; apellido_materno?: string };
  matricula?: string;
}

const TIPOS_DOC = [
  { label: 'Boleta Oficial',           value: 'BOLETA' },
  { label: 'Constancia de Estudios',   value: 'CONSTANCIA_ESTUDIOS' },
  { label: 'Constancia Calificaciones',value: 'CONSTANCIA_CALIFICACIONES' },
  { label: 'Kardex Académico',         value: 'KARDEX' },
  { label: 'Reporte de Conducta',      value: 'CONDUCTA' },
  { label: 'Certificado',              value: 'CERTIFICADO' },
  { label: 'Genérico',                 value: 'GENERICO' },
];

@Component({
  selector: 'app-reportes',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    ButtonModule, SelectModule, TagModule,
    TabsModule,
    TooltipModule, FileUploadModule, MessageModule, ProgressSpinnerModule,
    InteractiveGridComponent,
  ],
  template: `

    <div class="page-header">
      <div>
        <h2>Generador de Reportes</h2>
        <p class="subtitle">Reportes PDF a partir de plantillas Word/Excel — Carbone</p>
      </div>
      <div style="display:flex;gap:.5rem">
        <p-tag [value]="carboneStatus()" [severity]="carboneOnline() ? 'success' : 'danger'" />
      </div>
    </div>

    <p-tabs [value]="tabActivo()">
      <p-tablist>
        <p-tab value="generar"><i class="pi pi-file-pdf"></i> Reporte Individual</p-tab>
        <p-tab value="grupo"><i class="pi pi-users"></i> Boletas Grupo</p-tab>
        <p-tab value="plantillas"><i class="pi pi-folder"></i> Plantillas</p-tab>
        <p-tab value="subir"><i class="pi pi-upload"></i> Subir Plantilla</p-tab>
      </p-tablist>

      <p-tabpanels>

        <!-- ── Generador ── -->
        <p-tabpanel value="generar">
          @if (!carboneOnline()) {
            <p-message severity="warn"
              text="Servicio Carbone no disponible. Verificar que el contenedor ades-carbone esté corriendo." />
          } @else {
            <div class="gen-form">
              <div class="form-row">
                <label>Alumno</label>
                <p-select
                  [options]="alumnos()"
                  [(ngModel)]="alumnoSel"
                  [filter]="true"
                  filterBy="label"
                  optionLabel="label"
                  optionValue="id"
                  placeholder="Buscar alumno..."
                  style="width:320px"
                  (onChange)="onAlumnoChange($event.value)" />
              </div>

              <div class="form-row">
                <label>Plantilla</label>
                <p-select
                  [options]="plantillas()"
                  [(ngModel)]="plantillaSel"
                  optionLabel="nombre"
                  optionValue="id"
                  placeholder="Seleccionar plantilla..."
                  style="width:320px" 
 [filter]="true" filterPlaceholder="Buscar..."/>
              </div>

              <div class="form-row">
                <label>Tipo de documento</label>
                <p-select
                  [options]="tiposDoc"
                  [(ngModel)]="tipoDocSel"
                  optionLabel="label"
                  optionValue="value"
                  style="width:220px" 
 [filter]="true" filterPlaceholder="Buscar..."/>
              </div>

              @if (tipoDocSel === 'BOLETA') {
                <div class="form-row">
                  <label>Periodo</label>
                  <p-select
                    [options]="[{label:'Todos los periodos',value:null},{label:'Periodo 1',value:1},{label:'Periodo 2',value:2},{label:'Periodo 3',value:3}]"
                    [(ngModel)]="periodoSel"
                    optionLabel="label"
                    optionValue="value"
                    style="width:200px" 
 [filter]="true" filterPlaceholder="Buscar..."/>
                </div>
              }

              <div class="form-row">
                <label></label>
                <p-button
                  label="Generar PDF"
                  icon="pi pi-file-pdf"
                  [loading]="generando()"
                  [disabled]="!alumnoSel || !plantillaSel"
                  (onClick)="generarPdf()" />
              </div>
            </div>
          }
        </p-tabpanel>

        <!-- ── Boletas del Grupo (Stirling-PDF merge) ── -->
        <p-tabpanel value="grupo">
          <p style="font-size:.83rem;color:var(--text-color-secondary);margin:0 0 1rem">
            Genera la boleta de <strong>todos los alumnos del grupo</strong> con Carbone y las fusiona en un único PDF
            usando Stirling-PDF. Si Stirling-PDF no está disponible, descarga un ZIP individual.
          </p>

          @if (!carboneOnline()) {
            <p-message severity="warn" text="Carbone no disponible — los PDFs no pueden generarse." />
          } @else {
            <div class="gen-form">
              <div class="form-row">
                <label>Grupo</label>
                <p-select [options]="grupos()" [(ngModel)]="grupoSel"
                  optionLabel="label" optionValue="id"
                  [filter]="true" filterBy="label"
                  placeholder="Seleccionar grupo..."
                  style="width:320px" />
              </div>

              <div class="form-row">
                <label>Plantilla boleta</label>
                <p-select [options]="plantillasBoleta()"
                  [(ngModel)]="plantillaGrupoSel"
                  optionLabel="nombre" optionValue="id"
                  placeholder="Plantilla de tipo BOLETA..."
                  style="width:320px" 
 [filter]="true" filterPlaceholder="Buscar..."/>
              </div>

              <div class="form-row">
                <label>Periodo</label>
                <p-select
                  [options]="[{label:'Todos',value:null},{label:'Periodo 1',value:1},{label:'Periodo 2',value:2},{label:'Periodo 3',value:3}]"
                  [(ngModel)]="periodoGrupoSel"
                  optionLabel="label" optionValue="value"
                  style="width:180px" 
 [filter]="true" filterPlaceholder="Buscar..."/>
              </div>

              <div class="form-row">
                <label>Marca de agua</label>
                <p-toggleswitch [(ngModel)]="marcaAgua" />
                <span style="font-size:.78rem;color:var(--text-muted);margin-left:.5rem">Añadir "INSTITUTO NEVADI" como marca de agua</span>
              </div>

              <div class="form-row">
                <label></label>
                <p-button label="Generar PDF del grupo"
                  icon="pi pi-file-pdf"
                  [loading]="generandoGrupo()"
                  [disabled]="!grupoSel || !plantillaGrupoSel"
                  (onClick)="generarBoletasGrupo()" />
              </div>

              <p-message severity="info"
                text="El proceso puede tardar 1-3 minutos según el tamaño del grupo. El PDF se descargará automáticamente cuando esté listo." />
            </div>
          }
        </p-tabpanel>

        <!-- ── Plantillas ── -->
        <p-tabpanel value="plantillas">
          <app-interactive-grid
            [data]="plantillasFlat()"
            [columns]="plantillaColumns"
            [loading]="cargandoPlantillas()"
            [showDelete]="ctx.nivelAcceso() <= 1"
            (rowDeleted)="eliminarPlantilla($event.id)"
          />
        </p-tabpanel>

        <!-- ── Subir Plantilla (admin) ── -->
        <p-tabpanel value="subir">
          @if (ctx.nivelAcceso() <= 1) {
            <div class="upload-form">
              <div class="form-grid">
                <label>Nombre de la plantilla</label>
                <input pInputText [(ngModel)]="nuevaPlantillaNombre" placeholder="ej. Boleta Primaria 2026" />
                <label>Tipo de documento</label>
                <p-select [options]="tiposDoc" [(ngModel)]="nuevaPlantillaTipo"
                  optionLabel="label" optionValue="value" style="width:100%" 
 [filter]="true" filterPlaceholder="Buscar..."/>
                <label>Descripción</label>
                <input pInputText [(ngModel)]="nuevaPlantillaDesc" placeholder="Descripción opcional" />
              </div>

              <div style="margin-top:1.5rem">
                <p-fileupload
                  mode="advanced"
                  [customUpload]="true"
                  (uploadHandler)="onUpload($event)"
                  accept=".docx,.xlsx,.odt,.ods"
                  [maxFileSize]="20000000"
                  [auto]="false"
                  chooseLabel="Seleccionar archivo"
                  uploadLabel="Subir plantilla"
                  cancelLabel="Cancelar">
                  <ng-template pTemplate="empty">
                    <div style="text-align:center;padding:2rem;color:var(--text-muted)">
                      <i class="pi pi-cloud-upload" style="font-size:2rem"></i>
                      <p>Arrastra un archivo DOCX o XLSX aquí</p>
                      <p style="font-size:.75rem">
                        Usa marcadores <strong>&#123;d.alumno.nombre&#125;</strong> en el documento.<br>
                        Ver documentación de Carbone para la sintaxis completa.
                      </p>
                    </div>
                  </ng-template>
                </p-fileupload>
              </div>
            </div>
          } @else {
            <p-message severity="info" text="Solo administradores pueden subir plantillas." />
          }
        </p-tabpanel>

      </p-tabpanels>
    </p-tabs>
  `,
  styles: [`
    .page-header { display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:1rem }
    .subtitle { font-size:.82rem;color:var(--text-color-secondary);margin:0 }
    .gen-form { max-width:600px;padding:1rem 0 }
    .form-row { display:flex;align-items:center;gap:1rem;margin-bottom:1rem }
    .form-row label { width:150px;font-size:.85rem;color:var(--text-color-secondary);flex-shrink:0 }
    .upload-form { max-width:700px;padding:1rem 0 }
    .form-grid { display:grid;grid-template-columns:140px 1fr;gap:.75rem;align-items:center }
    .form-grid label { font-size:.85rem;color:var(--text-color-secondary) }
    code { background:var(--surface-100);padding:.1rem .3rem;border-radius:3px;font-size:.75rem }
  `],
})
export class ReportesComponent implements OnInit {
  readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);
  private readonly auth = inject(AuthService);
  private readonly notify = inject(ApexNotificationService);

  tabActivo          = signal('generar');
  plantillas         = signal<Plantilla[]>([]);
  alumnos            = signal<{id:string;label:string}[]>([]);
  grupos             = signal<{id:string;label:string}[]>([]);
  cargandoPlantillas = signal(false);
  generando          = signal(false);
  generandoGrupo     = signal(false);
  carboneOnline      = signal(false);
  carboneStatus      = computed(() => this.carboneOnline() ? 'Carbone activo' : 'Carbone sin conexión');

  readonly plantillaColumns: ColumnConfig[] = [
    { field: 'nombre',          header: 'Nombre',   sortable: true, filterable: true },
    { field: 'tipo_documento',  header: 'Tipo',     sortable: true, filterable: true, width: '150px' },
    { field: 'extension',       header: 'Ext.',     sortable: true, filterable: false, width: '70px' },
    { field: 'tamanoKb',        header: 'Tamaño',   sortable: true, filterable: false, width: '90px' },
    { field: 'fechaCreacion',   header: 'Fecha',    sortable: true, filterable: false, width: '130px' },
  ];

  readonly plantillasFlat = computed(() =>
    this.plantillas().map(p => ({
      ...p,
      tamanoKb: `${(p.tamano_bytes / 1024).toFixed(0)} KB`,
      fechaCreacion: p.fccreacion ? new Date(p.fccreacion).toLocaleDateString('es-MX') : '',
    }))
  );

  // Plantillas filtradas por tipo BOLETA para generación grupal
  plantillasBoleta = computed(() => this.plantillas().filter(p => p.tipo_documento === 'BOLETA' || p.tipo_documento === 'GENERICO'));

  tiposDoc = TIPOS_DOC;

  alumnoSel: string | null = null;
  plantillaSel: string | null = null;
  tipoDocSel = 'BOLETA';
  periodoSel: number | null = null;

  // Boletas de grupo (FASE 21 — Stirling-PDF)
  grupoSel: string | null = null;
  plantillaGrupoSel: string | null = null;
  periodoGrupoSel: number | null = null;
  marcaAgua = false;

  nuevaPlantillaNombre = '';
  nuevaPlantillaTipo   = 'GENERICO';
  nuevaPlantillaDesc   = '';

  ngOnInit(): void {
    this.verificarCarbone();
    this.cargarPlantillas();
    this.cargarAlumnos();
    this.cargarGrupos();
  }

  verificarCarbone(): void {
    this.api.get<{disponible:boolean}>('/carbone/status').subscribe({
      next: r  => this.carboneOnline.set(r.disponible),
      error: () => this.carboneOnline.set(false),
    });
  }

  cargarPlantillas(): void {
    this.cargandoPlantillas.set(true);
    this.api.get<Plantilla[]>('/carbone/templates').subscribe({
      next: p  => { this.plantillas.set(p); this.cargandoPlantillas.set(false); },
      error: () => this.cargandoPlantillas.set(false),
    });
  }

  cargarAlumnos(): void {
    const params: Record<string,any> = { pagina: 1, por_pagina: 500 };
    const plantelId = this.ctx.plantel()?.id;
    if (plantelId) params['plantel_id'] = plantelId;
    this.api.get<{data:Alumno[];total:number}>('/alumnos', params).subscribe({
      next: resp => {
        this.alumnos.set(resp.data.map(a => ({
          id: a.id,
          label: `${a.persona?.apellido_paterno} ${a.persona?.apellido_materno ?? ''}, ${a.persona?.nombre} — ${a.matricula ?? ''}`.trim(),
        })));
      },
      error: () => {},
    });
  }

  cargarGrupos(): void {
    const params: Record<string,any> = { solo_activos: true, ciclo_vigente: true };
    const plantelId = this.ctx.plantel()?.id;
    if (plantelId) params['plantel_id'] = plantelId;
    this.api.get<any[]>('/grupos', params).subscribe({
      next: gs => this.grupos.set(gs.map(g => ({
        id: g.id,
        label: (g._label ?? grupoLabel(g)) || g.nombre_grupo || g.nombre || '—',
      }))),
      error: () => {},
    });
  }

  onAlumnoChange(_id: string): void {}

  // ── FASE 21 — Generar boletas fusionadas de todo el grupo ─────────────────
  generarBoletasGrupo(): void {
    if (!this.grupoSel || !this.plantillaGrupoSel) return;
    this.generandoGrupo.set(true);
    const token = this.auth.accessToken() ?? '';
    const base = (window as any).__env?.apiUrl || '';
    let qs = `template_id=${this.plantillaGrupoSel}&agregar_marca_agua=${this.marcaAgua}`;
    if (this.periodoGrupoSel) qs += `&periodo=${this.periodoGrupoSel}`;

    fetch(`${base}/api/v1/pdf/boletas-grupo/${this.grupoSel}?${qs}`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(r => {
        if (!r.ok) return r.json().then(e => { throw new Error(e.detail || 'Error al generar'); });
        const ct = r.headers.get('content-type') ?? '';
        const ext = ct.includes('zip') ? 'zip' : 'pdf';
        return r.blob().then(b => ({ blob: b, ext }));
      })
      .then(({ blob, ext }) => {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `boletas_grupo.${ext}`;
        a.click();
        URL.revokeObjectURL(url);
        this.notify.success('PDF generado', `Boletas del grupo descargadas (.${ext})`);
      })
      .catch(err => this.notify.error('Error', err.message))
      .finally(() => this.generandoGrupo.set(false));
  }

  generarPdf(): void {
    if (!this.alumnoSel || !this.plantillaSel) return;
    this.generando.set(true);

    const endpoint = this.tipoDocSel === 'BOLETA'
      ? `/carbone/boleta/${this.alumnoSel}`
      : `/carbone/constancia/${this.alumnoSel}`;

    const params: Record<string,any> = { template_id: this.plantillaSel };
    if (this.tipoDocSel === 'BOLETA' && this.periodoSel) params['periodo'] = this.periodoSel;

    // Usar fetch directo para descargar blob
    const token = this.auth.accessToken() ?? '';
    const base = (window as any).__env?.apiUrl || '';
    const qs = Object.entries(params).map(([k,v]) => `${k}=${v}`).join('&');

    fetch(`${base}/api/v1${endpoint}?${qs}`, {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
    })
      .then(r => {
        if (!r.ok) return r.json().then(e => { throw new Error(e.detail || 'Error'); });
        return r.blob();
      })
      .then(blob => {
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `reporte_${Date.now()}.pdf`;
        a.click();
        URL.revokeObjectURL(url);
        this.notify.success('PDF generado', 'Descarga iniciada');
      })
      .catch(err => this.notify.error('Error', err.message))
      .finally(() => this.generando.set(false));
  }

  eliminarPlantilla(id: string): void {
    this.api.delete(`/carbone/templates/${id}`).subscribe({
      next: () => {
        this.plantillas.update(p => p.filter(x => x.id !== id));
        this.notify.success('Eliminada');
      },
      error: () => this.notify.error('Error al eliminar'),
    });
  }

  onUpload(event: any): void {
    const file: File = event.files[0];
    if (!file) return;

    const fd = new FormData();
    fd.append('template', file, file.name);
    fd.append('nombre', this.nuevaPlantillaNombre || file.name);
    fd.append('tipo_documento', this.nuevaPlantillaTipo);
    fd.append('descripcion', this.nuevaPlantillaDesc);

    this.api.postFormData<Plantilla>('/carbone/templates', fd).subscribe({
      next: p => {
        this.plantillas.update(lst => [...lst, p]);
        this.notify.success('Plantilla subida', p.nombre);
        this.nuevaPlantillaNombre = '';
        this.nuevaPlantillaDesc  = '';
      },
      error: () => this.notify.error('Error al subir plantilla'),
    });
  }
}

import { Component, inject, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { TableModule } from 'primeng/table';
import { DialogModule } from 'primeng/dialog';
import { SelectModule } from 'primeng/select';
import { InputTextModule } from 'primeng/inputtext';
import { InputNumberModule } from 'primeng/inputnumber';
import { TextareaModule } from 'primeng/textarea';
import { TooltipModule } from 'primeng/tooltip';
import { TagModule } from 'primeng/tag';
import { DividerModule } from 'primeng/divider';

import { ApiService } from '../../core/services/api.service';
import { ContextService } from '../../core/services/context.service';

interface Rubrica {
  id: string;
  nombre_rubrica: string;
  descripcion: string | null;
  nombre_materia: string | null;
  nombre_nivel: string | null;
  total_criterios: number;
  ponderacion_total: number;
}

interface Criterio {
  id: string;
  nombre_criterio: string;
  descripcion: string | null;
  ponderacion: number;
  orden: number;
  niveles_logro: NivelLogro[] | null;
  _editando?: boolean;
}

interface NivelLogro {
  nivel: number;
  etiqueta: string;
  descripcion: string;
}

const NIVEL_COLORS = ['var(--red-400)', 'var(--yellow-400)', 'var(--teal-400)', 'var(--green-500)'];

/**
 * Módulo de gestión de rúbricas de evaluación docente.
 * Permite crear y administrar criterios de evaluación con niveles de desempeño
 * codificados por color, asociados a materias o actividades específicas.
 */
@Component({
  selector: 'app-rubricas',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    ButtonModule, TableModule, DialogModule, SelectModule,
    InputTextModule, InputNumberModule, TextareaModule,
    TooltipModule, TagModule, DividerModule,
  ],
  template: `
    <div class="page-header">
      <div>
        <h2 class="page-title">Rúbricas de Evaluación</h2>
        <p class="page-subtitle">Criterios ponderados y niveles de logro por materia</p>
      </div>
      <div class="page-actions">
        <p-button icon="pi pi-plus" label="Nueva rúbrica" (onClick)="abrirNueva()" />
      </div>
    </div>

    <div class="layout-split">

      <!-- Panel izquierdo: lista de rúbricas -->
      <div class="panel-list">
        <div class="filter-bar">
          <p-select [options]="materias()" [(ngModel)]="filtroMateriaId"
                    optionLabel="label" optionValue="value"
                    placeholder="Filtrar por materia..."
                    [showClear]="true" styleClass="w-full"
                    (onChange)="cargar()" 
 [filter]="true" filterPlaceholder="Buscar..."/>
        </div>

        @if (rubricas().length === 0) {
          <div class="empty-msg">No hay rúbricas. Crea la primera.</div>
        }
        @for (r of rubricas(); track r.id) {
          <div class="rubrica-item" [class.selected]="selRubrica?.id === r.id"
               (click)="seleccionar(r)">
            <div class="rubrica-item-title">{{ r.nombre_rubrica }}</div>
            <div class="rubrica-item-meta">
              @if (r.nombre_materia) { <span>{{ r.nombre_materia }}</span> }
              @if (r.nombre_nivel)   { <span>{{ r.nombre_nivel }}</span> }
              <span>{{ r.total_criterios }} criterios</span>
            </div>
            <div class="rubrica-ponderacion">
              <span [class]="r.ponderacion_total === 100 ? 'pond-ok' : 'pond-warn'">
                {{ r.ponderacion_total | number:'1.0-1' }}% total
              </span>
            </div>
          </div>
        }
      </div>

      <!-- Panel derecho: builder de rúbrica -->
      <div class="panel-detail">
        @if (!selRubrica) {
          <div class="empty-panel">
            <i class="pi pi-table" style="font-size:3rem; color:var(--surface-400)"></i>
            <p>Selecciona una rúbrica para editarla</p>
          </div>
        } @else {
          <div class="rubrica-detail-header">
            <div>
              <h3>{{ selRubrica.nombre_rubrica }}</h3>
              @if (detalle()?.descripcion) {
                <p class="text-muted" style="font-size:.82rem; margin:.25rem 0 0">{{ detalle()?.descripcion }}</p>
              }
            </div>
            <div class="page-actions">
              <p-button icon="pi pi-trash" severity="danger" [text]="true"
                        ariaLabel="Eliminar rúbrica" pTooltip="Eliminar rúbrica" (onClick)="eliminarRubrica()" />
            </div>
          </div>

          <!-- Tabla de criterios -->
          <div class="criterios-builder">
            @for (c of criterios(); track c.id; let i = $index) {
              <div class="criterio-card">
                <div class="criterio-header">
                  <div class="criterio-info">
                    <span class="criterio-num">{{ i + 1 }}</span>
                    <strong>{{ c.nombre_criterio }}</strong>
                    @if (c.descripcion) {
                      <span class="text-muted" style="font-size:.78rem">— {{ c.descripcion }}</span>
                    }
                  </div>
                  <div class="criterio-meta">
                    <span class="pond-badge">{{ c.ponderacion | number:'1.0-1' }}%</span>
                    <p-button icon="pi pi-trash" size="small" severity="danger" [text]="true"
                              ariaLabel="Eliminar criterio" (onClick)="eliminarCriterio(c)" />
                  </div>
                </div>

                <!-- Niveles de logro -->
                @if (c.niveles_logro && c.niveles_logro.length > 0) {
                  <div class="niveles-grid">
                    @for (n of c.niveles_logro; track n.nivel) {
                      <div class="nivel-card" [style.border-top]="'3px solid ' + nivelColor(n.nivel)">
                        <div class="nivel-header" [style.color]="nivelColor(n.nivel)">
                          {{ n.nivel }}. {{ n.etiqueta }}
                        </div>
                        <div class="nivel-desc">{{ n.descripcion }}</div>
                      </div>
                    }
                  </div>
                }
              </div>
            }

            <p-button icon="pi pi-plus" label="Agregar criterio"
                      severity="secondary" [outlined]="true"
                      styleClass="w-full mt-2"
                      (onClick)="abrirCriterio()" />
          </div>
        }
      </div>
    </div>

    <!-- Dialog nueva rúbrica -->
    <p-dialog header="Nueva rúbrica" [(visible)]="showNueva" [modal]="true"
              [style]="{width:'460px'}">
      <div class="form-grid">
        <div class="form-field full">
          <label>Nombre *</label>
          <input pInputText [(ngModel)]="formNueva.nombre" placeholder="Ej. Rúbrica redacción" style="width:100%" />
        </div>
        <div class="form-field full">
          <label>Descripción</label>
          <textarea pTextarea [(ngModel)]="formNueva.descripcion" rows="2" style="width:100%"></textarea>
        </div>
        <div class="form-field">
          <label>Materia</label>
          <p-select [options]="materias()" [(ngModel)]="formNueva.materia_id"
                    optionLabel="label" optionValue="value"
                    placeholder="Opcional..." [showClear]="true" styleClass="w-full" 
 [filter]="true" filterPlaceholder="Buscar..."/>
        </div>
        <div class="form-field">
          <label>Nivel educativo</label>
          <p-select [options]="niveles()" [(ngModel)]="formNueva.nivel_educativo_id"
                    optionLabel="label" optionValue="value"
                    placeholder="Opcional..." [showClear]="true" styleClass="w-full" 
 [filter]="true" filterPlaceholder="Buscar..."/>
        </div>
      </div>
      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true" (onClick)="showNueva = false" />
        <p-button label="Crear" icon="pi pi-check" (onClick)="crearRubrica()" />
      </ng-template>
    </p-dialog>

    <!-- Dialog nuevo criterio -->
    <p-dialog header="Agregar criterio" [(visible)]="showCriterio" [modal]="true"
              [style]="{width:'560px'}">
      <div class="form-grid">
        <div class="form-field full">
          <label>Nombre del criterio *</label>
          <input pInputText [(ngModel)]="formCrit.nombre" style="width:100%" />
        </div>
        <div class="form-field">
          <label>Descripción</label>
          <input pInputText [(ngModel)]="formCrit.descripcion" style="width:100%" />
        </div>
        <div class="form-field">
          <label>Ponderación (%)</label>
          <p-inputNumber [(ngModel)]="formCrit.ponderacion" [min]="0" [max]="100"
                         suffix="%" inputStyleClass="w-full" />
        </div>
        <div class="form-field">
          <label>Orden</label>
          <p-inputNumber [(ngModel)]="formCrit.orden" [min]="1" inputStyleClass="w-full" />
        </div>
      </div>

      <p-divider />
      <p style="font-size:.85rem; font-weight:600; margin-bottom:.75rem">Niveles de logro (opcional)</p>
      <div class="niveles-form">
        @for (n of formCrit.niveles; track n.nivel) {
          <div class="nivel-form-row">
            <div class="nivel-num" [style.background]="nivelColor(n.nivel)">{{ n.nivel }}</div>
            <input pInputText [(ngModel)]="n.etiqueta" placeholder="Etiqueta (ej. Destacado)"
                   style="width:110px; font-size:.82rem" />
            <input pInputText [(ngModel)]="n.descripcion" placeholder="Descripción del nivel"
                   style="flex:1; font-size:.82rem" />
          </div>
        }
      </div>

      <ng-template pTemplate="footer">
        <p-button label="Cancelar" severity="secondary" [text]="true" (onClick)="showCriterio = false" />
        <p-button label="Agregar" icon="pi pi-plus" (onClick)="guardarCriterio()" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .page-header   { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:1.25rem; }
    .page-title    { font-size:1.25rem; font-weight:700; margin:0 0 .2rem; }
    .page-subtitle { color:var(--text-color-secondary); font-size:.82rem; margin:0; }
    .page-actions  { display:flex; gap:.5rem; align-items:center; }

    /* Layout split */
    .layout-split { display:grid; grid-template-columns:280px 1fr; gap:1.25rem; }
    @media (max-width:800px) { .layout-split { grid-template-columns:1fr; } }

    /* Panel lista */
    .panel-list { display:flex; flex-direction:column; gap:.4rem; }
    .filter-bar { margin-bottom:.5rem; }

    .rubrica-item {
      padding:.65rem .85rem; border-radius:6px; cursor:pointer;
      background:var(--surface-card); border:1px solid var(--surface-200);
      transition:border-color .12s, box-shadow .12s;
    }
    .rubrica-item:hover { border-color:var(--primary-color); }
    .rubrica-item.selected { border-color:var(--primary-color); box-shadow:0 0 0 2px var(--primary-200, #ffd0d5); }
    .rubrica-item-title { font-weight:600; font-size:.88rem; margin-bottom:.2rem; }
    .rubrica-item-meta  { display:flex; gap:.5rem; font-size:.72rem; color:var(--text-color-secondary); flex-wrap:wrap; }
    .rubrica-item-meta span + span::before { content:'·'; margin-right:.5rem; }
    .rubrica-ponderacion { margin-top:.3rem; font-size:.72rem; }
    .pond-ok   { color:var(--green-600); font-weight:600; }
    .pond-warn { color:var(--orange-500); font-weight:600; }

    /* Panel detalle */
    .panel-detail { min-height:400px; }
    .empty-panel  { height:300px; display:flex; flex-direction:column; align-items:center;
      justify-content:center; gap:1rem; color:var(--text-color-secondary); }

    .rubrica-detail-header { display:flex; justify-content:space-between; align-items:flex-start;
      margin-bottom:1rem; padding-bottom:.75rem; border-bottom:1px solid var(--surface-200); }
    .rubrica-detail-header h3 { font-size:1.05rem; font-weight:700; margin:0; }

    /* Criterios builder */
    .criterios-builder { display:flex; flex-direction:column; gap:.6rem; }
    .criterio-card {
      background:var(--surface-card); border:1px solid var(--surface-200); border-radius:8px;
      padding:.75rem 1rem;
    }
    .criterio-header { display:flex; justify-content:space-between; align-items:center; margin-bottom:.5rem; }
    .criterio-info   { display:flex; align-items:center; gap:.5rem; flex-wrap:wrap; }
    .criterio-num    { background:var(--primary-color); color:#fff; border-radius:50%;
      width:20px; height:20px; display:flex; align-items:center; justify-content:center;
      font-size:.7rem; font-weight:700; flex-shrink:0; }
    .criterio-meta   { display:flex; align-items:center; gap:.35rem; }
    .pond-badge      { background:var(--surface-200); border-radius:10px; font-size:.72rem;
      font-weight:700; padding:0 .5rem; }

    /* Niveles grid */
    .niveles-grid { display:grid; grid-template-columns:repeat(4,1fr); gap:.4rem; margin-top:.5rem; }
    @media (max-width:900px) { .niveles-grid { grid-template-columns:repeat(2,1fr); } }
    .nivel-card { border-radius:5px; padding:.4rem .5rem; background:var(--surface-50); }
    .nivel-header { font-size:.72rem; font-weight:700; margin-bottom:.2rem; }
    .nivel-desc   { font-size:.72rem; color:var(--text-color-secondary); }

    /* Form */
    .form-grid  { display:grid; grid-template-columns:1fr 1fr; gap:.75rem; }
    .form-field { display:flex; flex-direction:column; gap:.3rem; font-size:.875rem; }
    .form-field.full { grid-column:1/-1; }
    label       { font-weight:500; font-size:.82rem; }

    .niveles-form { display:flex; flex-direction:column; gap:.35rem; }
    .nivel-form-row { display:flex; align-items:center; gap:.5rem; }
    .nivel-num { width:24px; height:24px; border-radius:50%; display:flex; align-items:center;
      justify-content:center; color:#fff; font-weight:700; font-size:.8rem; flex-shrink:0; }

    .text-muted { color:var(--text-color-secondary); }
    .empty-msg  { text-align:center; padding:2rem; color:var(--text-color-secondary); font-size:.85rem; }
    .w-full     { width:100% !important; }
    .mt-2       { margin-top:.5rem; }
  `],
})
export class RubricasComponent implements OnInit {
  private readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);

  rubricas = signal<Rubrica[]>([]);
  materias = signal<{ label: string; value: string }[]>([]);
  niveles = signal<{ label: string; value: string }[]>([]);
  criterios = signal<Criterio[]>([]);
  detalle = signal<Rubrica | null>(null);

  selRubrica: Rubrica | null = null;
  filtroMateriaId = '';
  showNueva = false;
  showCriterio = false;

  formNueva = { nombre: '', descripcion: '', materia_id: '', nivel_educativo_id: '' };
  formCrit = this.emptyFormCrit();

  ngOnInit(): void {
    this.cargar();
    this.cargarCatalogos();
  }

  cargar(): void {
    const params: Record<string, string> = {};
    if (this.filtroMateriaId) params['materia_id'] = this.filtroMateriaId;
    this.api.get<Rubrica[]>('/rubricas', params).subscribe(r => this.rubricas.set(r));
  }

  cargarCatalogos(): void {
    this.api.get<any[]>('/materias').subscribe(list => {
      this.materias.set(list.map(m => ({ label: m.nombre_materia, value: m.id })));
    });
    this.api.get<any[]>('/catalogs/niveles').subscribe(list => {
      this.niveles.set(list.map(n => ({ label: n.nombre_nivel, value: n.id })));
    });
  }

  seleccionar(r: Rubrica): void {
    this.selRubrica = r;
    this.api.get<any>(`/rubricas/${r.id}`).subscribe(d => {
      this.detalle.set(d);
      this.criterios.set(d.criterios ?? []);
    });
  }

  abrirNueva(): void { this.formNueva = { nombre: '', descripcion: '', materia_id: '', nivel_educativo_id: '' }; this.showNueva = true; }

  crearRubrica(): void {
    if (!this.formNueva.nombre) return;
    this.api.post('/rubricas', {
      nombre_rubrica: this.formNueva.nombre,
      descripcion: this.formNueva.descripcion || null,
      materia_id: this.formNueva.materia_id || null,
      nivel_educativo_id: this.formNueva.nivel_educativo_id || null,
    }).subscribe(() => { this.showNueva = false; this.cargar(); });
  }

  abrirCriterio(): void { this.formCrit = this.emptyFormCrit(); this.showCriterio = true; }

  guardarCriterio(): void {
    if (!this.selRubrica || !this.formCrit.nombre) return;
    const nivelesValidos = this.formCrit.niveles.filter(n => n.etiqueta.trim());
    this.api.post(`/rubricas/${this.selRubrica.id}/criterios`, {
      nombre_criterio: this.formCrit.nombre,
      descripcion: this.formCrit.descripcion || null,
      ponderacion: this.formCrit.ponderacion,
      orden: this.formCrit.orden,
      niveles_logro: nivelesValidos.length ? nivelesValidos : null,
    }).subscribe(() => { this.showCriterio = false; this.seleccionar(this.selRubrica!); });
  }

  eliminarCriterio(c: Criterio): void {
    if (!this.selRubrica) return;
    this.api.delete(`/rubricas/${this.selRubrica.id}/criterios/${c.id}`).subscribe(() => {
      this.seleccionar(this.selRubrica!);
    });
  }

  eliminarRubrica(): void {
    if (!this.selRubrica) return;
    this.api.delete(`/rubricas/${this.selRubrica.id}`).subscribe(() => {
      this.selRubrica = null;
      this.criterios.set([]);
      this.cargar();
    });
  }

  nivelColor(nivel: number): string { return NIVEL_COLORS[nivel - 1] ?? '#999'; }

  private emptyFormCrit() {
    return {
      nombre: '', descripcion: '', ponderacion: 25.0, orden: 1,
      niveles: [
        { nivel: 1, etiqueta: 'Inicial', descripcion: '' },
        { nivel: 2, etiqueta: 'En desarrollo', descripcion: '' },
        { nivel: 3, etiqueta: 'Logrado', descripcion: '' },
        { nivel: 4, etiqueta: 'Destacado', descripcion: '' },
      ],
    };
  }
}

