import { Component, Input, OnInit, OnChanges, SimpleChanges, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../../../core/services/api.service';
import { ContextService } from '../../../core/services/context.service';
import { ButtonModule } from 'primeng/button';
import { MessageService } from 'primeng/api';

export interface Franja {
  id: string;
  dia_semana: number;
  hora_inicio: string;
  hora_fin: string;
}

export interface Indisponibilidad {
  id?: string;
  profesorId: string;
  cicloEscolarId: string;
  franjaId: string;
  tipo: 'DISPONIBLE' | 'CONDICIONAL' | 'NO_DISPONIBLE';
}

@Component({
  selector: 'app-disponibilidad-grid',
  standalone: true,
  imports: [CommonModule, FormsModule, ButtonModule],
  template: `
    <div class="disp-container">
      <div class="disp-header">
        <div>
          <h4 style="margin:0 0 0.5rem 0">Matriz de Disponibilidad</h4>
          <p style="margin:0; font-size: 0.85rem; color: var(--text-color-secondary)">
            Haz clic en las celdas para cambiar el estado.
          </p>
        </div>
        <div style="display:flex; gap: 1rem; align-items:center;">
          <div class="leyenda">
            <span class="box disp-verde"></span> Disponible
          </div>
          <div class="leyenda">
            <span class="box disp-amarillo"></span> Condicional
          </div>
          <div class="leyenda">
            <span class="box disp-rojo"></span> No Disponible
          </div>
        </div>
      </div>

      @if (cargando()) {
        <div style="text-align:center; padding: 2rem;">
          <i class="pi pi-spin pi-spinner" style="font-size: 2rem"></i>
        </div>
      } @else if (!ctx.ciclo()?.id) {
        <div class="disp-empty">
          Selecciona un ciclo escolar en la barra superior.
        </div>
      } @else if (franjas().length === 0) {
        <div class="disp-empty">
          No hay franjas horarias configuradas para este nivel/plantel.
        </div>
      } @else {
        <div class="disp-grid-wrapper">
          <table class="disp-table">
            <thead>
              <tr>
                <th style="width: 120px;">Hora</th>
                @for (d of diasSemana; track d.num) {
                  <th>{{ d.label }}</th>
                }
              </tr>
            </thead>
            <tbody>
              @for (h of horasUnicas(); track h) {
                <tr>
                  <td class="hora-col">{{ h }}</td>
                  @for (d of diasSemana; track d.num) {
                    <td class="celda-estado"
                        [ngClass]="getClaseEstado(d.num, h)"
                        (click)="toggleEstado(d.num, h)">
                      {{ getEtiquetaEstado(d.num, h) }}
                    </td>
                  }
                </tr>
              }
            </tbody>
          </table>
        </div>

        <div style="display:flex; justify-content:flex-end; margin-top: 1rem;">
          <p-button label="Guardar Matriz" icon="pi pi-save" [loading]="guardando()" (onClick)="guardar()" />
        </div>
      }
    </div>
  `,
  styles: [`
    .disp-container { display: flex; flex-direction: column; gap: 1rem; }
    .disp-header { display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1rem; margin-bottom: 0.5rem; }
    .leyenda { display: flex; align-items: center; gap: 0.35rem; font-size: 0.8rem; color: var(--text-color-secondary); }
    .leyenda .box { width: 16px; height: 16px; border-radius: 4px; border: 1px solid rgba(0,0,0,0.1); }
    .disp-empty { padding: 2rem; text-align: center; color: var(--text-color-secondary); background: var(--surface-100); border-radius: 8px; }
    .disp-grid-wrapper { overflow-x: auto; border: 1px solid var(--surface-border); border-radius: 8px; }
    .disp-table { width: 100%; border-collapse: collapse; text-align: center; font-size: 0.85rem; }
    .disp-table th { background: var(--surface-200); padding: 0.75rem; border-bottom: 2px solid var(--surface-border); font-weight: 600; }
    .disp-table td { padding: 0; border: 1px solid var(--surface-border); height: 45px; }
    .hora-col { background: var(--surface-50); font-weight: 600; color: var(--text-color-secondary); }
    .celda-estado { cursor: pointer; transition: all 0.2s; user-select: none; font-size: 0.75rem; font-weight: 600; }
    .celda-estado:hover { filter: brightness(0.95); }
    .disp-verde { background-color: #dcfce7; color: #166534; }
    .disp-amarillo { background-color: #fef9c3; color: #854d0e; }
    .disp-rojo { background-color: #fee2e2; color: #991b1b; }
    .disp-gris { background-color: var(--surface-100); color: var(--text-color-secondary); cursor: not-allowed; }
  `]
})
export class DisponibilidadGridComponent implements OnInit, OnChanges {
  private readonly api = inject(ApiService);
  readonly ctx = inject(ContextService);
  private readonly msg = inject(MessageService);

  @Input() profesorId!: string;

  diasSemana = [
    { num: 1, label: 'Lunes' },
    { num: 2, label: 'Martes' },
    { num: 3, label: 'Miércoles' },
    { num: 4, label: 'Jueves' },
    { num: 5, label: 'Viernes' }
  ];

  franjas = signal<Franja[]>([]);
  horasUnicas = computed(() => {
    const horas = new Set(this.franjas().map(f => f.hora_inicio.substring(0, 5)));
    return Array.from(horas).sort();
  });

  // Mapa: franjaId -> tipo
  estadoMap = signal<Map<string, 'DISPONIBLE' | 'CONDICIONAL' | 'NO_DISPONIBLE'>>(new Map());
  cargando = signal(false);
  guardando = signal(false);

  ngOnInit() {
    this.cargarDatos();
  }

  ngOnChanges(changes: SimpleChanges) {
    if (changes['profesorId'] && !changes['profesorId'].isFirstChange()) {
      this.cargarDatos();
    }
  }

  cargarDatos() {
    const cicloId = this.ctx.ciclo()?.id;
    if (!cicloId || !this.profesorId) return;

    this.cargando.set(true);

    // 1. Cargar Franjas del ciclo y plantel/nivel activo
    const params: any = { cicloId };
    if (this.ctx.plantel()?.id) params.plantelId = this.ctx.plantel()?.id;
    if (this.ctx.nivel()?.id) params.nivelEducativoId = this.ctx.nivel()?.id;

    this.api.get<Franja[]>('/horario-franjas', params).subscribe({
      next: (fList) => {
        this.franjas.set(fList);

        // 2. Cargar Matriz actual del profesor
        this.api.get<Indisponibilidad[]>('/horario-indisponibilidad', { profesorId: this.profesorId, cicloEscolarId: cicloId }).subscribe({
          next: (iList) => {
            const map = new Map<string, 'DISPONIBLE' | 'CONDICIONAL' | 'NO_DISPONIBLE'>();
            // Por defecto, si hay franja, está DISPONIBLE
            fList.forEach(f => map.set(f.id, 'DISPONIBLE'));
            // Sobrescribir con lo guardado
            iList.forEach(ind => map.set(ind.franjaId, ind.tipo));
            this.estadoMap.set(map);
            this.cargando.set(false);
          },
          error: () => this.cargando.set(false)
        });
      },
      error: () => this.cargando.set(false)
    });
  }

  getFranja(dia: number, hora: string): Franja | undefined {
    return this.franjas().find(f => f.dia_semana === dia && f.hora_inicio.startsWith(hora));
  }

  getClaseEstado(dia: number, hora: string): string {
    const f = this.getFranja(dia, hora);
    if (!f) return 'disp-gris';
    const st = this.estadoMap().get(f.id);
    if (st === 'DISPONIBLE') return 'disp-verde';
    if (st === 'CONDICIONAL') return 'disp-amarillo';
    if (st === 'NO_DISPONIBLE') return 'disp-rojo';
    return 'disp-verde';
  }

  getEtiquetaEstado(dia: number, hora: string): string {
    const f = this.getFranja(dia, hora);
    if (!f) return '-';
    const st = this.estadoMap().get(f.id);
    if (st === 'DISPONIBLE') return 'DISP';
    if (st === 'CONDICIONAL') return 'COND';
    if (st === 'NO_DISPONIBLE') return 'NO';
    return 'DISP';
  }

  toggleEstado(dia: number, hora: string) {
    const f = this.getFranja(dia, hora);
    if (!f) return;

    const current = this.estadoMap().get(f.id) || 'DISPONIBLE';
    let next: 'DISPONIBLE' | 'CONDICIONAL' | 'NO_DISPONIBLE' = 'DISPONIBLE';

    if (current === 'DISPONIBLE') next = 'CONDICIONAL';
    else if (current === 'CONDICIONAL') next = 'NO_DISPONIBLE';
    else if (current === 'NO_DISPONIBLE') next = 'DISPONIBLE';

    const newMap = new Map(this.estadoMap());
    newMap.set(f.id, next);
    this.estadoMap.set(newMap);
  }

  guardar() {
    const cicloId = this.ctx.ciclo()?.id;
    if (!cicloId || !this.profesorId) return;

    this.guardando.set(true);

    const payload: Indisponibilidad[] = [];
    this.estadoMap().forEach((tipo, franjaId) => {
      // Solo enviamos los que no son DISPONIBLE para ahorrar espacio, 
      // o todos si el backend hace replace. El backend hace replace completo.
      // Enviaremos todos los modificados. A nivel base de datos es mejor enviar todo
      // para que el backend borre y reinserte.
      payload.push({
        profesorId: this.profesorId,
        cicloEscolarId: cicloId,
        franjaId: franjaId,
        tipo: tipo
      });
    });

    this.api.post(`/horario-indisponibilidad?profesorId=${this.profesorId}&cicloEscolarId=${cicloId}`, payload).subscribe({
      next: () => {
        this.msg.add({ severity: 'success', summary: 'Éxito', detail: 'Matriz guardada correctamente' });
        this.guardando.set(false);
      },
      error: () => {
        this.msg.add({ severity: 'error', summary: 'Error', detail: 'No se pudo guardar la matriz' });
        this.guardando.set(false);
      }
    });
  }
}

/**
 * DomicilioComponent — Gestión de direcciones y medios de contacto de una persona.
 * Reusable: se embebe en alumno-perfil, profesor-perfil, y cualquier formulario de actor.
 * Integra catálogo SEPOMEX (ades_codigos_postales / ades_localidades) para cascada CP→Asentamiento→Municipio→Estado.
 * Geocodificación vía Nominatim (OpenStreetMap, sin clave API, uso razonable).
 */
import {
  Component, Input, OnChanges, OnInit, SimpleChanges, inject, signal, computed
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { HttpClient } from '@angular/common/http';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { TextareaModule } from 'primeng/textarea';
import { TagModule } from 'primeng/tag';
import { ToastModule } from 'primeng/toast';
import { DividerModule } from 'primeng/divider';
import { TooltipModule } from 'primeng/tooltip';
import { MessageService } from 'primeng/api';
import { ApiService } from '../../../core/services/api.service';

// ─── Catálogos locales ────────────────────────────────────────────────────────
const TIPOS_DIR   = ['PRINCIPAL','TRABAJO','TEMPORAL','ANTERIOR','CORRESPONDENCIA'];
const TIPOS_VIA   = ['CALLE','AVENIDA','BOULEVARD','CALZADA','PRIVADA','CERRADA','ANDADOR','CARRETERA','CAMINO','OTRO'];
const MEDIOS      = ['CELULAR','FIJO','WHATSAPP','EMAIL','TELEGRAM','FAX','OTRO'];
const TIPOS_CONT  = ['PERSONAL','TRABAJO','FAMILIAR','INSTITUCIONAL','EMERGENCIA'];

interface SepomexRow {
  cp_id: string;
  localidad_id: string;
  codigo_postal: string;
  nombre_localidad: string;
  tipo_asentamiento: string;
  nombre_municipio: string;
  nombre_estado: string;
  nombre_pais: string;
}

interface Direccion {
  id: string;
  tipo_direccion: string;
  es_principal: boolean;
  tipo_via: string | null;
  calle: string | null;
  numero_exterior: string | null;
  numero_interior: string | null;
  entre_calle_1: string | null;
  entre_calle_2: string | null;
  referencia: string | null;
  codigo_postal: string | null;
  nombre_localidad: string | null;
  tipo_asentamiento: string | null;
  nombre_municipio: string | null;
  nombre_estado: string | null;
  nombre_pais: string | null;
  latitud: number | null;
  longitud: number | null;
  row_version: number;
}

interface PersonaContacto {
  id: string;
  medio: string;
  tipo: string;
  valor: string;
  etiqueta: string | null;
  es_principal: boolean;
  orden: number;
  notas: string | null;
  row_version: number;
}

@Component({
  selector: 'app-domicilio',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    ButtonModule, InputTextModule, SelectModule, TextareaModule,
    TagModule, ToastModule, DividerModule, TooltipModule,
  ],
  providers: [MessageService],
  template: `
    <p-toast />

    @if (!personaId) {
      <div class="empty-state">
        <i class="pi pi-info-circle"></i>
        Guarda el perfil principal antes de gestionar domicilios y contactos.
      </div>
    } @else {

      <!-- ═══ SECCIÓN 1: Medios de Contacto ═══════════════════════════════ -->
      <div class="section-header">
        <h4 class="sec-title">
          <i class="pi pi-phone"></i> Medios de Contacto
        </h4>
        <p-button label="Agregar" icon="pi pi-plus" size="small" [text]="true"
          (onClick)="abrirNuevoContacto()" />
      </div>

      <!-- Lista de contactos agrupados por medio -->
      @if (contactos().length === 0 && !editandoContacto()) {
        <p class="empty-msg">Sin medios de contacto registrados.</p>
      }

      <div class="contactos-list">
        @for (c of contactos(); track c.id) {
          <div class="contacto-item" [class.principal]="c.es_principal">
            <div class="contacto-icon">
              <i [class]="iconMedio(c.medio)"></i>
            </div>
            <div class="contacto-info">
              <span class="contacto-valor">{{ c.valor }}</span>
              <span class="contacto-meta">
                {{ c.medio }} · {{ c.tipo }}
                @if (c.etiqueta) { <em>— {{ c.etiqueta }}</em> }
              </span>
            </div>
            <div class="contacto-actions">
              @if (c.es_principal) { <p-tag value="Principal" severity="success" /> }
              <p-button icon="pi pi-pencil" [text]="true" [rounded]="true" size="small"
                (onClick)="editarContacto(c)" />
              <p-button icon="pi pi-trash" [text]="true" [rounded]="true" size="small"
                severity="danger" (onClick)="eliminarContacto(c.id)" />
            </div>
          </div>
        }
      </div>

      <!-- Formulario inline contacto -->
      @if (editandoContacto()) {
        <div class="inline-form">
          <h5>{{ contactoEdit.id ? 'Editar' : 'Nuevo' }} medio de contacto</h5>
          <div class="form-grid">
            <div class="form-row">
              <label>Medio *</label>
              <p-select [options]="mediosOpts" [(ngModel)]="contactoEdit.medio"
                optionLabel="label" optionValue="value" />
            </div>
            <div class="form-row">
              <label>Tipo</label>
              <p-select [options]="tiposContOpts" [(ngModel)]="contactoEdit.tipo"
                optionLabel="label" optionValue="value" />
            </div>
            <div class="form-row full">
              <label>{{ contactoEdit.medio === 'EMAIL' ? 'Correo electrónico *' : 'Número *' }}</label>
              <input pInputText [(ngModel)]="contactoEdit.valor"
                [type]="contactoEdit.medio === 'EMAIL' ? 'email' : 'tel'"
                [placeholder]="contactoEdit.medio === 'EMAIL' ? 'usuario@correo.com' : '10 dígitos'" />
            </div>
            <div class="form-row full">
              <label>Etiqueta</label>
              <input pInputText [(ngModel)]="contactoEdit.etiqueta"
                placeholder="Ej: Celular mamá, WhatsApp trabajo" maxlength="50" />
            </div>
            <div class="form-row">
              <label>Notas</label>
              <input pInputText [(ngModel)]="contactoEdit.notas" maxlength="200" />
            </div>
            <div class="form-row">
              <label>¿Principal?</label>
              <input type="checkbox" [(ngModel)]="contactoEdit.es_principal" />
            </div>
          </div>
          <div class="form-btns">
            <p-button label="Cancelar" severity="secondary" [text]="true" size="small"
              (onClick)="cancelarContacto()" />
            <p-button label="Guardar" icon="pi pi-save" size="small"
              [loading]="savingContacto()" (onClick)="guardarContacto()" />
          </div>
        </div>
      }

      <p-divider />

      <!-- ═══ SECCIÓN 2: Domicilios ════════════════════════════════════════ -->
      <div class="section-header">
        <h4 class="sec-title">
          <i class="pi pi-map-marker"></i> Domicilios
        </h4>
        <p-button label="Agregar" icon="pi pi-plus" size="small" [text]="true"
          (onClick)="abrirNuevaDireccion()" />
      </div>

      @if (direcciones().length === 0 && !editandoDireccion()) {
        <p class="empty-msg">Sin domicilios registrados.</p>
      }

      <div class="dirs-list">
        @for (d of direcciones(); track d.id) {
          <div class="dir-card" [class.principal]="d.es_principal">
            <div class="dir-header">
              <div>
                <strong>{{ d.tipo_direccion }}</strong>
                @if (d.es_principal) { <p-tag value="Principal" severity="success" /> }
              </div>
              <div class="dir-actions">
                @if (!d.es_principal) {
                  <p-button label="Marcar principal" [text]="true" size="small"
                    (onClick)="setPrincipal(d.id)" />
                }
                <p-button icon="pi pi-pencil" [text]="true" [rounded]="true" size="small"
                  (onClick)="editarDireccion(d)" />
                <p-button icon="pi pi-trash" [text]="true" [rounded]="true" size="small"
                  severity="danger" (onClick)="eliminarDireccion(d.id)" />
              </div>
            </div>
            <div class="dir-detalle">
              {{ formatDireccion(d) }}
            </div>
            @if (d.nombre_localidad) {
              <div class="dir-ubic">
                <i class="pi pi-map-marker"></i>
                {{ d.nombre_localidad }}
                @if (d.tipo_asentamiento) { ({{ d.tipo_asentamiento }}) }
                @if (d.nombre_municipio) { , {{ d.nombre_municipio }} }
                @if (d.nombre_estado) { , {{ d.nombre_estado }} }
                @if (d.codigo_postal) { CP {{ d.codigo_postal }} }
              </div>
            }
            @if (d.latitud && d.longitud) {
              <div class="dir-mapa">
                <a [href]="urlMapa(d.latitud, d.longitud)" target="_blank" class="mapa-link">
                  <i class="pi pi-external-link"></i> Ver en mapa
                </a>
                <span class="coords">{{ d.latitud | number:'1.6-6' }}, {{ d.longitud | number:'1.6-6' }}</span>
              </div>
            }
          </div>
        }
      </div>

      <!-- Formulario inline dirección -->
      @if (editandoDireccion()) {
        <div class="inline-form dir-form">
          <h5>{{ dirEdit.id ? 'Editar' : 'Nueva' }} dirección</h5>

          <!-- SEPOMEX -->
          <div class="sepomex-block">
            <!-- CP input -->
            <div class="form-row">
              <label>Código Postal *</label>
              <div class="cp-input-wrap">
                <input pInputText [(ngModel)]="cpBusqueda"
                  (ngModelChange)="onCpChange($event)"
                  maxlength="5" placeholder="5 dígitos"
                  style="font-family:monospace;width:100px" />
                @if (buscandoCp()) {
                  <i class="pi pi-spin pi-spinner" style="margin-left:.5rem"></i>
                }
                @if (cpSelId()) {
                  <p-button icon="pi pi-times-circle" [text]="true" size="small"
                    severity="secondary" pTooltip="Limpiar para captura manual"
                    (onClick)="limpiarSeleccionCp()" styleClass="ml-1" />
                }
              </div>
            </div>

            <!-- LOV de asentamientos -->
            @if (asentamientos().length > 0) {
              <div class="form-row">
                <label>Colonia / Asentamiento *</label>
                <p-select
                  [options]="asentamientoOpts()"
                  [ngModel]="cpSelId()"
                  (ngModelChange)="cpSelId.set($event)"
                  optionLabel="label" optionValue="value"
                  [filter]="true" filterPlaceholder="Buscar colonia…"
                  placeholder="Seleccionar asentamiento…"
                  (onChange)="onAsentamientoSelect($event)"
                  style="width:100%" />
              </div>
            } @else if (cpBusqueda.length === 5 && !buscandoCp()) {
              <p class="sepomex-nota">
                <i class="pi pi-info-circle"></i>
                CP no encontrado — captura el asentamiento manualmente.
              </p>
            }

            <!-- Geolocalización: bloqueada si viene de SEPOMEX, editable si es manual -->
            @if (cpSelId()) {
              <!-- Modo bloqueado: auto-llenado desde SEPOMEX -->
              <div class="sep-locked">
                <div class="sep-locked-row">
                  <span class="sep-locked-lbl">Colonia</span>
                  <span class="sep-locked-val">
                    <i class="pi pi-lock"></i> {{ dirEdit.nombre_localidad }}
                  </span>
                </div>
                <div class="sep-locked-row">
                  <span class="sep-locked-lbl">Municipio</span>
                  <span class="sep-locked-val">
                    <i class="pi pi-lock"></i> {{ dirEdit.nombre_municipio }}
                  </span>
                </div>
                <div class="sep-locked-row">
                  <span class="sep-locked-lbl">Estado</span>
                  <span class="sep-locked-val">
                    <i class="pi pi-lock"></i> {{ dirEdit.nombre_estado }}
                  </span>
                </div>
                <div class="sep-locked-row">
                  <span class="sep-locked-lbl">País</span>
                  <span class="sep-locked-val">
                    <i class="pi pi-lock"></i> {{ dirEdit.nombre_pais }}
                  </span>
                </div>
              </div>
            } @else {
              <!-- Modo manual: editable cuando no hay CP seleccionado -->
              <div class="form-row">
                <label>Colonia</label>
                <input pInputText [(ngModel)]="dirEdit.nombre_localidad"
                  placeholder="Colonia, Fraccionamiento, Ejido…" />
              </div>
              <div class="form-row">
                <label>Municipio</label>
                <input pInputText [(ngModel)]="dirEdit.nombre_municipio"
                  placeholder="Municipio o Alcaldía" />
              </div>
              <div class="form-row">
                <label>Estado</label>
                <input pInputText [(ngModel)]="dirEdit.nombre_estado"
                  placeholder="Estado o Entidad federativa" />
              </div>
              <div class="form-row">
                <label>País</label>
                <input pInputText [(ngModel)]="dirEdit.nombre_pais" />
              </div>
            }
          </div>

          <p-divider align="left"><small>Vialidad</small></p-divider>

          <div class="form-grid">
            <div class="form-row">
              <label>Tipo de vía</label>
              <p-select [options]="tiposViaOpts" [(ngModel)]="dirEdit.tipo_via"
                optionLabel="label" optionValue="value" [showClear]="true" />
            </div>
            <div class="form-row">
              <label>Nombre de calle</label>
              <input pInputText [(ngModel)]="dirEdit.calle" placeholder="Ej: Morelos" />
            </div>
            <div class="form-row">
              <label>Núm. exterior</label>
              <input pInputText [(ngModel)]="dirEdit.numero_exterior" maxlength="20"
                placeholder="Ej: 42-A" />
            </div>
            <div class="form-row">
              <label>Núm. interior</label>
              <input pInputText [(ngModel)]="dirEdit.numero_interior" maxlength="20"
                placeholder="Ej: 3-B (opcional)" />
            </div>
            <div class="form-row full">
              <label>Entre calles</label>
              <div style="display:grid;grid-template-columns:1fr auto 1fr;gap:.4rem;align-items:center">
                <input pInputText [(ngModel)]="dirEdit.entre_calle_1" placeholder="Primera calle" />
                <span style="font-size:.75rem;color:#94a3b8">y</span>
                <input pInputText [(ngModel)]="dirEdit.entre_calle_2" placeholder="Segunda calle" />
              </div>
            </div>
            <div class="form-row full">
              <label>Referencia</label>
              <input pInputText [(ngModel)]="dirEdit.referencia"
                maxlength="255" placeholder="Ej: Frente al parque, casa azul" />
            </div>
            <div class="form-row">
              <label>Tipo dirección</label>
              <p-select [options]="tiposDirOpts" [(ngModel)]="dirEdit.tipo_direccion"
                optionLabel="label" optionValue="value" />
            </div>
            <div class="form-row">
              <label>¿Principal?</label>
              <input type="checkbox" [(ngModel)]="dirEdit.es_principal" />
            </div>
          </div>

          <p-divider align="left"><small>Geolocalización (opcional)</small></p-divider>

          <div class="form-grid">
            <div class="form-row">
              <label>Latitud</label>
              <input pInputText [(ngModel)]="dirEdit.latitud" type="number"
                step="0.000001" placeholder="Ej: 19.432608" />
            </div>
            <div class="form-row">
              <label>Longitud</label>
              <input pInputText [(ngModel)]="dirEdit.longitud" type="number"
                step="0.000001" placeholder="Ej: -99.133209" />
            </div>
            <div class="form-row full" style="justify-content:flex-end;gap:.5rem;display:flex">
              <p-button label="Geocodificar" icon="pi pi-map" size="small" [text]="true"
                [loading]="geocodificando()" (onClick)="geocodificar()" />
              @if (dirEdit.latitud && dirEdit.longitud) {
                <a [href]="urlMapa(dirEdit.latitud, dirEdit.longitud)" target="_blank" class="mapa-link-btn">
                  <i class="pi pi-external-link"></i> Ver en mapa
                </a>
              }
            </div>
          </div>

          <div class="form-btns">
            <p-button label="Cancelar" severity="secondary" [text]="true" size="small"
              (onClick)="cancelarDireccion()" />
            <p-button label="Guardar dirección" icon="pi pi-save" size="small"
              [loading]="savingDir()" (onClick)="guardarDireccion()" />
          </div>
        </div>
      }
    }
  `,
  styles: [`
    .empty-state { color: #94a3b8; font-size: .85rem; padding: .5rem 0; }
    .empty-msg   { color: #94a3b8; font-size: .82rem; margin: .25rem 0 .5rem; }

    .section-header {
      display: flex; justify-content: space-between; align-items: center;
      margin-bottom: .5rem;
    }
    .sec-title {
      font-size: .82rem; font-weight: 700; text-transform: uppercase;
      letter-spacing: .05em; color: var(--primary-color); margin: 0;
      display: flex; align-items: center; gap: .4rem;
    }

    /* Contactos */
    .contactos-list { display: flex; flex-direction: column; gap: .4rem; margin-bottom: .75rem; }
    .contacto-item {
      display: flex; align-items: center; gap: .75rem;
      padding: .5rem .75rem; border: 1px solid var(--surface-200); border-radius: 6px;
    }
    .contacto-item.principal { border-color: var(--green-300); background: var(--green-50); }
    .contacto-icon { font-size: 1.1rem; color: var(--primary-color); width: 24px; text-align: center; }
    .contacto-info { flex: 1; min-width: 0; }
    .contacto-valor { font-weight: 600; font-size: .88rem; display: block; }
    .contacto-meta  { font-size: .75rem; color: #64748b; }
    .contacto-actions { display: flex; gap: .25rem; align-items: center; }

    /* Direcciones */
    .dirs-list { display: flex; flex-direction: column; gap: .6rem; margin-bottom: .75rem; }
    .dir-card {
      border: 1px solid var(--surface-200); border-radius: 8px; padding: .75rem;
    }
    .dir-card.principal { border-color: var(--primary-color); background: var(--primary-50, #fef2f3); }
    .dir-header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: .3rem; }
    .dir-actions { display: flex; gap: .2rem; align-items: center; }
    .dir-detalle { font-size: .88rem; font-weight: 500; margin-bottom: .2rem; }
    .dir-ubic { font-size: .78rem; color: #64748b; margin-bottom: .2rem; }
    .dir-mapa { display: flex; align-items: center; gap: .75rem; font-size: .78rem; margin-top: .25rem; }
    .mapa-link { color: var(--primary-color); text-decoration: none; }
    .mapa-link:hover { text-decoration: underline; }
    .coords { color: #94a3b8; font-family: monospace; font-size: .72rem; }

    /* Formularios inline */
    .inline-form {
      background: var(--surface-50); border: 1px solid var(--surface-200);
      border-radius: 8px; padding: 1rem; margin-bottom: .75rem;
    }
    .inline-form h5 { margin: 0 0 .75rem; font-size: .9rem; }
    .form-grid { display: flex; flex-direction: column; gap: .4rem; }
    .form-row {
      display: grid; grid-template-columns: 130px 1fr; gap: .5rem;
      align-items: center;
    }
    .form-row.full { grid-column: 1 / -1; }
    .form-row label { font-size: .8rem; color: var(--text-color-secondary); }
    .form-btns { display: flex; justify-content: flex-end; gap: .5rem; margin-top: .75rem; }

    /* SEPOMEX */
    .sepomex-block { display: flex; flex-direction: column; gap: .4rem; margin-bottom: .5rem; }
    .cp-input-wrap { display: flex; align-items: center; }
    .sepomex-nota { font-size: .78rem; color: #f59e0b; margin: .25rem 0; }

    /* Campos bloqueados por SEPOMEX */
    .sep-locked {
      background: var(--surface-100); border: 1px solid var(--surface-300);
      border-radius: 6px; padding: .5rem .75rem;
      display: flex; flex-direction: column; gap: .3rem; margin-top: .25rem;
    }
    .sep-locked-row { display: flex; align-items: center; gap: .5rem; }
    .sep-locked-lbl {
      font-size: .75rem; color: var(--text-color-secondary);
      width: 70px; flex-shrink: 0; text-align: right;
    }
    .sep-locked-val {
      font-size: .85rem; font-weight: 500; color: var(--text-color);
      display: flex; align-items: center; gap: .3rem;
    }
    .sep-locked-val .pi-lock { color: var(--surface-400); font-size: .65rem; }

    /* Mapa link button */
    .mapa-link-btn {
      font-size: .8rem; color: var(--primary-color); text-decoration: none;
      display: flex; align-items: center; gap: .25rem;
      padding: .3rem .6rem; border: 1px solid var(--primary-color);
      border-radius: 4px;
    }
  `],
})
export class DomicilioComponent implements OnChanges {
  private readonly api = inject(ApiService);
  private readonly http = inject(HttpClient);
  private readonly msg = inject(MessageService);

  @Input() personaId: string | null = null;
  @Input() entidadTipo: string = 'PERSONA';

  direcciones  = signal<Direccion[]>([]);
  contactos    = signal<PersonaContacto[]>([]);

  editandoDireccion = signal(false);
  editandoContacto  = signal(false);
  savingDir         = signal(false);
  savingContacto    = signal(false);
  buscandoCp        = signal(false);
  geocodificando    = signal(false);

  asentamientos = signal<SepomexRow[]>([]);
  cpSelId       = signal('');   // signal → garantiza reactividad en @if del template
  cpBusqueda    = '';
  dirEdit: any  = {};
  contactoEdit: any = {};

  asentamientoOpts = computed(() =>
    this.asentamientos().map(a => ({
      label: `${a.nombre_localidad} (${a.tipo_asentamiento || 'Colonia'})`,
      value: a.cp_id,
      row: a,
    }))
  );

  readonly tiposDirOpts  = TIPOS_DIR.map(v => ({ label: v, value: v }));
  readonly tiposViaOpts  = TIPOS_VIA.map(v => ({ label: v, value: v }));
  readonly mediosOpts    = MEDIOS.map(v => ({ label: v, value: v }));
  readonly tiposContOpts = TIPOS_CONT.map(v => ({ label: v, value: v }));

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['personaId'] && this.personaId) {
      this.cargar();
    }
  }

  private cargar(): void {
    this.cargarDirecciones();
    this.cargarContactos();
  }

  private cargarDirecciones(): void {
    if (!this.personaId) return;
    this.api.get<Direccion[]>('/direcciones', {
      entidad_tipo: this.entidadTipo,
      entidad_id: this.personaId,
    }).subscribe({ next: d => this.direcciones.set(d), error: () => {} });
  }

  private cargarContactos(): void {
    if (!this.personaId) return;
    this.api.get<PersonaContacto[]>('/persona-contactos', { persona_id: this.personaId })
      .subscribe({ next: c => this.contactos.set(c), error: () => {} });
  }

  // ── Direcciones ──────────────────────────────────────────────────────────

  abrirNuevaDireccion(): void {
    this.cpBusqueda = '';
    this.cpSelId.set('');
    this.asentamientos.set([]);
    this.dirEdit = {
      tipo_direccion: 'PRINCIPAL',
      es_principal: this.direcciones().length === 0,
      tipo_via: null, calle: '', numero_exterior: '', numero_interior: '',
      entre_calle_1: '', entre_calle_2: '', referencia: '',
      nombre_localidad: '', nombre_municipio: '', nombre_estado: '', nombre_pais: 'México',
      latitud: null, longitud: null,
    };
    this.editandoDireccion.set(true);
  }

  editarDireccion(d: Direccion): void {
    this.cpBusqueda = d.codigo_postal ?? '';
    this.cpSelId.set('');
    this.asentamientos.set([]);
    this.dirEdit = { ...d };
    if (this.cpBusqueda.length === 5) {
      // Carga asentamientos — usuario puede re-seleccionar si necesita cambiar colonia
      this.buscarPorCp(this.cpBusqueda);
    }
    this.editandoDireccion.set(true);
  }

  cancelarDireccion(): void {
    this.editandoDireccion.set(false);
    this.dirEdit = {};
    this.cpBusqueda = '';
    this.cpSelId.set('');
    this.asentamientos.set([]);
  }

  onCpChange(cp: string): void {
    this.cpSelId.set('');
    if (cp.length === 5) {
      this.buscarPorCp(cp);
    } else {
      this.asentamientos.set([]);
    }
  }

  private buscarPorCp(cp: string): void {
    this.buscandoCp.set(true);
    this.api.get<SepomexRow[]>('/catalogs/sepomex/por-cp', { cp }).subscribe({
      next: rows => {
        this.asentamientos.set(rows);
        this.buscandoCp.set(false);
      },
      error: () => this.buscandoCp.set(false),
    });
  }

  onAsentamientoSelect(event: any): void {
    const selectedValue = event?.value ?? event;
    const opt = this.asentamientoOpts().find(o => o.value === selectedValue);
    if (!opt) return;
    const row = opt.row as SepomexRow;
    this.dirEdit.nombre_localidad  = row.nombre_localidad;
    this.dirEdit.tipo_asentamiento = row.tipo_asentamiento;
    this.dirEdit.nombre_municipio  = row.nombre_municipio;
    this.dirEdit.nombre_estado     = row.nombre_estado;
    this.dirEdit.nombre_pais       = row.nombre_pais || 'México';
    this.dirEdit.codigo_postal     = row.codigo_postal;
    this.dirEdit._cp_id            = row.cp_id;
    this.dirEdit._localidad_id     = row.localidad_id;
  }

  limpiarSeleccionCp(): void {
    this.cpSelId.set('');
    this.dirEdit._cp_id = null;
    this.dirEdit._localidad_id = null;
  }

  guardarDireccion(): void {
    if (!this.personaId) return;
    this.savingDir.set(true);

    const payload: any = {
      entidad_tipo: this.entidadTipo,
      entidad_id: this.personaId,
      tipo_direccion: this.dirEdit.tipo_direccion || 'PRINCIPAL',
      es_principal: this.dirEdit.es_principal,
      tipo_via: this.dirEdit.tipo_via || null,
      calle: this.dirEdit.calle || null,
      numero_exterior: this.dirEdit.numero_exterior || null,
      numero_interior: this.dirEdit.numero_interior || null,
      entre_calle_1: this.dirEdit.entre_calle_1 || null,
      entre_calle_2: this.dirEdit.entre_calle_2 || null,
      referencia: this.dirEdit.referencia || null,
      latitud: this.dirEdit.latitud || null,
      longitud: this.dirEdit.longitud || null,
      precision_gps: this.dirEdit.precision_gps || null,
    };

    if (this.dirEdit._cp_id) {
      payload.codigo_postal_id = this.dirEdit._cp_id;
      payload.localidad_id     = this.dirEdit._localidad_id;
    }
    if (this.dirEdit.row_version !== undefined) {
      payload.row_version = this.dirEdit.row_version;
    }

    const req = this.dirEdit.id
      ? this.api.patch(`/direcciones/${this.dirEdit.id}`, payload)
      : this.api.post('/direcciones', payload);

    req.subscribe({
      next: () => {
        this.msg.add({ severity: 'success', summary: 'Guardado', detail: 'Dirección actualizada' });
        this.cancelarDireccion();
        this.cargarDirecciones();
      },
      error: e => {
        this.msg.add({ severity: 'error', summary: 'Error', detail: e.error?.detail ?? 'Error al guardar' });
        this.savingDir.set(false);
      },
    });
  }

  eliminarDireccion(id: string): void {
    this.api.delete(`/direcciones/${id}`).subscribe({
      next: () => this.cargarDirecciones(),
      error: () => {},
    });
  }

  setPrincipal(id: string): void {
    this.api.patch(`/direcciones/${id}/principal`, {}).subscribe({
      next: () => this.cargarDirecciones(),
      error: () => {},
    });
  }

  geocodificar(): void {
    const parts = [
      this.dirEdit.calle, this.dirEdit.numero_exterior,
      this.dirEdit.nombre_localidad, this.dirEdit.nombre_municipio,
      this.dirEdit.nombre_estado, this.dirEdit.nombre_pais || 'México',
    ].filter(Boolean);
    if (parts.length < 2) {
      this.msg.add({ severity: 'warn', summary: 'Datos insuficientes',
        detail: 'Ingresa al menos calle y municipio para geocodificar' });
      return;
    }
    this.geocodificando.set(true);
    const q = encodeURIComponent(parts.join(', '));
    this.http.get<any[]>(
      `https://nominatim.openstreetmap.org/search?q=${q}&format=json&limit=1`,
      { headers: { 'Accept-Language': 'es' } }
    ).subscribe({
      next: results => {
        if (results.length > 0) {
          this.dirEdit.latitud  = parseFloat(results[0].lat);
          this.dirEdit.longitud = parseFloat(results[0].lon);
          this.dirEdit.precision_gps = 'APROXIMADA';
          this.msg.add({ severity: 'success', summary: 'Geocodificado',
            detail: `${results[0].display_name}` });
        } else {
          this.msg.add({ severity: 'warn', summary: 'Sin resultados',
            detail: 'No se encontraron coordenadas para esta dirección' });
        }
        this.geocodificando.set(false);
      },
      error: () => {
        this.msg.add({ severity: 'error', summary: 'Error', detail: 'No se pudo conectar a Nominatim' });
        this.geocodificando.set(false);
      },
    });
  }

  // ── Contactos ────────────────────────────────────────────────────────────

  abrirNuevoContacto(): void {
    this.contactoEdit = {
      medio: 'CELULAR', tipo: 'PERSONAL',
      valor: '', etiqueta: '',
      es_principal: this.contactos().length === 0, // auto-principal si es el primero
      notas: '',
    };
    this.editandoContacto.set(true);
  }

  editarContacto(c: PersonaContacto): void {
    this.contactoEdit = { ...c };
    this.editandoContacto.set(true);
  }

  cancelarContacto(): void {
    this.editandoContacto.set(false);
    this.contactoEdit = {};
  }

  guardarContacto(): void {
    if (!this.personaId) return;

    const valor = (this.contactoEdit.valor ?? '').trim();
    const medio = this.contactoEdit.medio ?? '';

    if (!valor) {
      this.msg.add({ severity: 'warn', summary: 'Campo requerido', detail: 'Ingresa el valor del medio de contacto' });
      return;
    }

    if (medio === 'EMAIL') {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;
      if (!emailRegex.test(valor)) {
        this.msg.add({ severity: 'warn', summary: 'Email inválido', detail: 'Ingresa un correo electrónico válido (ej: nombre@dominio.com)' });
        return;
      }
    } else if (['CELULAR', 'FIJO', 'WHATSAPP'].includes(medio)) {
      const digitosRegex = /^\d{10}$/;
      const soloDigitos = valor.replace(/[\s\-\(\)]/g, '');
      if (!digitosRegex.test(soloDigitos)) {
        this.msg.add({ severity: 'warn', summary: 'Teléfono inválido', detail: 'El número debe tener exactamente 10 dígitos' });
        return;
      }
      this.contactoEdit.valor = soloDigitos; // normalizar
    }

    // Auto-principal si es el único registro
    if (this.contactos().length === 0) {
      this.contactoEdit.es_principal = true;
    }

    this.savingContacto.set(true);
    const isNew = !this.contactoEdit.id;
    const payload = { ...this.contactoEdit, persona_id: this.personaId };
    const req = isNew
      ? this.api.post('/persona-contactos', payload)
      : this.api.patch(`/persona-contactos/${this.contactoEdit.id}`, payload);
    req.subscribe({
      next: () => {
        this.msg.add({ severity: 'success', summary: 'Guardado', detail: 'Contacto actualizado' });
        this.cancelarContacto();
        this.cargarContactos();
      },
      error: e => {
        this.msg.add({ severity: 'error', summary: 'Error', detail: e.error?.detail ?? 'Error' });
        this.savingContacto.set(false);
      },
    });
  }

  eliminarContacto(id: string): void {
    this.api.delete(`/persona-contactos/${id}`).subscribe({
      next: () => this.cargarContactos(),
      error: () => {},
    });
  }

  // ── helpers ──────────────────────────────────────────────────────────────

  iconMedio(medio: string): string {
    const map: Record<string, string> = {
      CELULAR: 'pi pi-mobile', FIJO: 'pi pi-phone',
      WHATSAPP: 'pi pi-whatsapp', EMAIL: 'pi pi-envelope',
      TELEGRAM: 'pi pi-send', FAX: 'pi pi-print', OTRO: 'pi pi-ellipsis-h',
    };
    return map[medio] ?? 'pi pi-ellipsis-h';
  }

  formatDireccion(d: Direccion): string {
    const partes: string[] = [];
    if (d.tipo_via) partes.push(d.tipo_via);
    if (d.calle) partes.push(d.calle);
    if (d.numero_exterior) partes.push(`#${d.numero_exterior}`);
    if (d.numero_interior) partes.push(`Int. ${d.numero_interior}`);
    if (d.entre_calle_1 && d.entre_calle_2) {
      partes.push(`(entre ${d.entre_calle_1} y ${d.entre_calle_2})`);
    }
    if (d.referencia) partes.push(`— ${d.referencia}`);
    return partes.join(' ') || 'Sin detalle de calle';
  }

  urlMapa(lat: number | null, lng: number | null): string {
    if (!lat || !lng) return '#';
    return `https://www.openstreetmap.org/?mlat=${lat}&mlon=${lng}&zoom=17`;
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DragDropModule, CdkDragDrop } from '@angular/cdk/drag-drop';
import { TooltipModule } from 'primeng/tooltip';

export interface HorarioGridEntry {
  id: string;
  dia_semana: number;
  hora_inicio: string;
  hora_fin: string;
  fijado?: boolean;
  nombre_materia: string | null;
  materia_id: string | null;
  nombre_grupo: string | null;
  grupo_id: string | null;
  nombre_profesor: string | null;
  profesor_id: string | null;
  nombre_aula: string | null;
  aula_id: string | null;
}

@Component({
  selector: 'app-horario-grid',
  standalone: true,
  imports: [CommonModule, DragDropModule, TooltipModule],
  template: `
    @if (entradas.length === 0) {
      <div class="empty-state">
        <i class="pi pi-calendar-plus" style="font-size: 3rem"></i>
        <p>No hay entradas de horario para mostrar.</p>
      </div>
    } @else {
      <div class="horario-grid" cdkDropListGroup>
        <!-- Cabecera días -->
        <div class="grid-header">
          <div class="hora-header">Hora</div>
          @for (dia of dias; track dia.num) {
            <div class="dia-header">{{ dia.label }}</div>
          }
        </div>

        <!-- Franjas horarias -->
        @for (franja of franjas; track franja) {
          <div class="grid-row">
            <div class="hora-col">{{ franja }}</div>
            @for (dia of dias; track dia.num) {
              <div class="dia-cell" cdkDropList [cdkDropListData]="{dia: dia.num, franja: franja}" (cdkDropListDropped)="onDrop($event)">
                @for (e of entradasPor(dia.num, franja); track e.id) {
                  <div class="clase-chip" cdkDrag [cdkDragData]="e" [style.background]="colorMateria(e.nombre_materia)"
                       (click)="claseClick.emit(e)" pTooltip="Click para editar" style="cursor:pointer">
                    <strong>{{ e.nombre_materia }}</strong>
                    @if (modo === 'grupo') {
                      <span>{{ e.nombre_profesor }}</span>
                    } @else {
                      <span>{{ e.nombre_grupo }}</span>
                    }
                    @if (e.nombre_aula) { <span class="aula-tag">{{ e.nombre_aula }}</span> }
                    <span class="hora-tag">{{ e.hora_inicio | slice:0:5 }}–{{ e.hora_fin | slice:0:5 }}</span>
                    @if (e.fijado) { <i class="pi pi-lock" style="font-size: 0.7rem; color: #b91c1c" pTooltip="Fijada"></i> }
                  </div>
                }
              </div>
            }
          </div>
        }
      </div>
    }
  `,
  styles: [`
    .empty-state { display: flex; flex-direction: column; align-items: center; gap: 0.75rem; padding: 4rem; color: #94A3B8; }

    .horario-grid { overflow-x: auto; }
    .grid-header, .grid-row {
      display: grid;
      grid-template-columns: 70px repeat(5, 1fr);
      gap: 2px;
    }
    .grid-header { margin-bottom: 2px; }
    .dia-header {
      background: var(--nevadi-red);
      color: #fff;
      text-align: center;
      padding: 0.4rem;
      font-family: var(--font-display);
      font-weight: 700;
      font-size: 0.82rem;
      border-radius: 4px;
    }
    .hora-header, .hora-col {
      background: var(--surface-200);
      text-align: center;
      padding: 0.4rem;
      font-size: 0.8rem;
      font-weight: 600;
      border-radius: 4px;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    .dia-cell {
      background: var(--surface-100);
      border-radius: 4px;
      min-height: 70px;
      padding: 2px;
      display: flex;
      flex-direction: column;
      gap: 2px;
    }
    .clase-chip {
      border-radius: 4px;
      padding: 0.3rem 0.5rem;
      font-size: 0.78rem;
      display: flex; flex-direction: column;
      border-left: 3px solid var(--nevadi-red);
    }
    .clase-chip:hover { filter: brightness(.95); }
    .clase-chip strong { font-family: var(--font-display); font-size: 0.8rem; }
    .clase-chip span { color: var(--text-secondary); font-size: 0.72rem; }
    .aula-tag { font-weight: 600; color: var(--nevadi-red-dark) !important; }
    .hora-tag { font-size: 0.68rem !important; color: var(--text-muted) !important; }
    .grid-row { margin-bottom: 2px; }

    .cdk-drag-preview {
      box-sizing: border-box;
      border-radius: 4px;
      box-shadow: 0 5px 5px -3px rgba(0, 0, 0, 0.2),
                  0 8px 10px 1px rgba(0, 0, 0, 0.14),
                  0 3px 14px 2px rgba(0, 0, 0, 0.12);
    }
    .cdk-drag-placeholder {
      opacity: 0.3;
    }
    .cdk-drag-animating {
      transition: transform 250ms cubic-bezier(0, 0, 0.2, 1);
    }
  `]
})
export class HorarioGridComponent {
  @Input() dias: { num: number, label: string }[] = [];
  @Input() franjas: string[] = [];
  @Input() entradas: HorarioGridEntry[] = [];
  @Input() modo: 'grupo' | 'profesor' = 'grupo';

  @Output() claseDrop = new EventEmitter<CdkDragDrop<any>>();
  @Output() claseClick = new EventEmitter<HorarioGridEntry>();

  entradasPor(dia: number, franja: string): HorarioGridEntry[] {
    return this.entradas.filter(e => e.dia_semana === dia && e.hora_inicio.startsWith(franja));
  }

  colorMateria(nombre: string | null): string {
    if (!nombre) return 'var(--surface-hover)';
    const colorHash = nombre.split('').reduce((acc, char) => char.charCodeAt(0) + ((acc << 5) - acc), 0);
    const h = Math.abs(colorHash) % 360;
    return `hsl(${h}, 60%, 90%)`;
  }

  onDrop(event: CdkDragDrop<any>) {
    this.claseDrop.emit(event);
  }
}

import {
  Component, input, inject, signal, computed,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { ApiService } from '../../../core/services/api.service';
import { ButtonModule }    from 'primeng/button';
import { DialogModule }    from 'primeng/dialog';
import { TableModule }     from 'primeng/table';
import { TagModule }       from 'primeng/tag';
import { TooltipModule }   from 'primeng/tooltip';
import { ProgressBarModule } from 'primeng/progressbar';
import { environment }    from '../../../../environments/environment';
import { ContextService } from '../../../core/services/context.service';

export interface ImportResult {
  entidad: string;
  total: number;
  exitosos: number;
  errores: number;
  detalle_errores: Array<{ fila: number; dato: string; error: string }>;
}

@Component({
  selector: 'app-import-button',
  standalone: true,
  imports: [
    CommonModule, ButtonModule, DialogModule,
    TableModule, TagModule, TooltipModule, ProgressBarModule,
  ],
  template: `
    <!-- Botones de acción — solo visible para coordinador y superiores (nivel_acceso <= 3) -->
    @if (puedeImportar()) {
    <div class="import-actions">
      <p-button
        icon="pi pi-upload"
        label="Importar CSV/Excel"
        [outlined]="true"
        size="small"
        severity="secondary"
        (onClick)="fileInput.click()"
        [loading]="subiendo()"
        pTooltip="Importar registros desde archivo CSV o Excel (.xlsx)"
        tooltipPosition="top"
      />
      <p-button
        icon="pi pi-download"
        label="Plantilla"
        [text]="true"
        size="small"
        severity="secondary"
        (onClick)="descargarPlantilla()"
        pTooltip="Descargar plantilla CSV de ejemplo"
        tooltipPosition="top"
      />
    </div>
    }

    <!-- Input oculto -->
    <input
      #fileInput
      type="file"
      [accept]="accept"
      style="display:none"
      (change)="onFileSelected($event)"
    />

    <!-- Dialog de resultado -->
    <p-dialog
      [(visible)]="showResult"
      [header]="headerDialog()"
      [modal]="true"
      [style]="{width:'620px'}"
      [closeOnEscape]="true"
    >
      @if (resultado()) {
        <div class="result-summary">
          <div class="stat-card stat-total">
            <span class="stat-num">{{ resultado()!.total }}</span>
            <span class="stat-label">Total filas</span>
          </div>
          <div class="stat-card stat-ok">
            <span class="stat-num">{{ resultado()!.exitosos }}</span>
            <span class="stat-label">Importados</span>
          </div>
          <div class="stat-card" [class.stat-error]="resultado()!.errores > 0" [class.stat-zero]="resultado()!.errores === 0">
            <span class="stat-num">{{ resultado()!.errores }}</span>
            <span class="stat-label">Errores</span>
          </div>
        </div>

        @if (resultado()!.detalle_errores.length > 0) {
          <p class="error-title">Detalle de errores:</p>
          <p-table
            [value]="resultado()!.detalle_errores"
            [scrollable]="true" scrollHeight="260px"
            styleClass="p-datatable-sm p-datatable-striped"
          >
            <ng-template pTemplate="header">
              <tr>
                <th style="width:60px">Fila</th>
                <th style="width:180px">Identificador</th>
                <th>Error</th>
              </tr>
            </ng-template>
            <ng-template pTemplate="body" let-e>
              <tr>
                <td class="text-center">{{ e.fila }}</td>
                <td class="monospace">{{ e.dato }}</td>
                <td class="error-msg">{{ e.error }}</td>
              </tr>
            </ng-template>
          </p-table>
        }
      }

      <ng-template pTemplate="footer">
        <p-button label="Cerrar" icon="pi pi-times" [text]="true" (onClick)="showResult = false" />
        @if (resultado()?.exitosos ?? 0 > 0) {
          <p-button label="Actualizar lista" icon="pi pi-refresh" (onClick)="onRefresh()" />
        }
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .import-actions { display: flex; gap: .25rem; align-items: center; }

    .result-summary {
      display: flex; gap: 1rem; margin-bottom: 1.25rem;
    }
    .stat-card {
      flex: 1; text-align: center; padding: .75rem 1rem;
      border-radius: 8px; border: 1px solid var(--surface-border);
      display: flex; flex-direction: column; gap: .15rem;
    }
    .stat-num   { font-size: 1.8rem; font-weight: 700; line-height: 1; }
    .stat-label { font-size: .75rem; color: var(--text-color-secondary); }
    .stat-total { background: var(--surface-100); }
    .stat-ok    { background: #ecfdf5; border-color: #6ee7b7; }
    .stat-ok .stat-num { color: #059669; }
    .stat-error { background: #fef2f2; border-color: #fca5a5; }
    .stat-error .stat-num { color: #dc2626; }
    .stat-zero  { background: var(--surface-100); }
    .stat-zero .stat-num { color: var(--text-color-secondary); }

    .error-title { font-weight: 600; font-size: .85rem; margin: 0 0 .5rem; color: #dc2626; }
    .error-msg   { font-size: .8rem; color: #dc2626; }
    .monospace   { font-family: monospace; font-size: .8rem; }
  `],
})
export class ImportButtonComponent {
  private readonly api = inject(ApiService);
  private readonly ctx  = inject(ContextService);

  /** Entidad a importar: 'alumnos' | 'profesores' | 'materias' | 'grupos' */
  entidad = input.required<string>();

  /** Callback invocado cuando hay registros exitosos, para refrescar la lista padre */
  onSuccess = input<() => void>(() => {});

  /** Solo coordinador (nivel 3) o superior puede importar */
  readonly puedeImportar = computed(() => this.ctx.nivelAcceso() <= 3);

  accept = '.csv,.xlsx,.xls';

  subiendo  = signal(false);
  resultado = signal<ImportResult | null>(null);
  showResult = false;

  headerDialog = computed(() => {
    const r = this.resultado();
    if (!r) return 'Resultado de importación';
    const ok = r.exitosos === r.total;
    return ok
      ? `✓ Importación completa — ${r.exitosos} registros`
      : `Importación finalizada — ${r.exitosos} de ${r.total} registros`;
  });

  onFileSelected(event: Event): void {
    const input = event.target as HTMLInputElement;
    const file  = input.files?.[0];
    if (!file) return;
    input.value = '';  // reset para permitir re-subir el mismo archivo
    this.upload(file);
  }

  private upload(file: File): void {
    const form = new FormData();
    form.append('file', file);

    this.subiendo.set(true);
    this.api.postForm<ImportResult>(
      `/imports/${this.entidad()}`,
      form,
    ).subscribe({
      next: (res) => {
        this.subiendo.set(false);
        this.resultado.set(res);
        this.showResult = true;
      },
      error: (err) => {
        this.subiendo.set(false);
        const msg = err?.error?.detail ?? 'Error desconocido al importar';
        this.resultado.set({
          entidad: this.entidad(),
          total: 0, exitosos: 0, errores: 1,
          detalle_errores: [{ fila: 0, dato: '—', error: String(msg) }],
        });
        this.showResult = true;
      },
    });
  }

  descargarPlantilla(): void {
    this.api.getBlob(
      `/imports/plantillas/${this.entidad()}`
    ).subscribe(blob => {
      const url = URL.createObjectURL(blob);
      const a   = document.createElement('a');
      a.href    = url;
      a.download = `plantilla_${this.entidad()}.csv`;
      a.click();
      URL.revokeObjectURL(url);
    });
  }

  onRefresh(): void {
    this.showResult = false;
    this.onSuccess()();
  }
}

/**
 * Interactive Grid Component — APEX-style
 *
 * Comportamiento estilo Oracle APEX Interactive Grid:
 *   - Click en fila → rowSelected (abre drawer/detalle)
 *   - Filtro por columna: autocomplete LOV con valores únicos + texto libre
 *   - Sort nativo de PrimeNG (clic en cabecera)
 *   - Columna Acciones: botón eliminar (rowDeleted)
 *   - Column chooser, exportar CSV
 */
import {
  Component, Input, Output, EventEmitter, signal, computed, OnChanges, SimpleChanges
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { TableModule } from 'primeng/table';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { TooltipModule } from 'primeng/tooltip';
import { DialogModule } from 'primeng/dialog';
import { AutoCompleteModule } from 'primeng/autocomplete';

export interface ColumnConfig {
  field: string;
  header: string;
  sortable?: boolean;
  filterable?: boolean;
  editable?: boolean;
  width?: string;
  align?: 'left' | 'center' | 'right';
  type?: 'text' | 'number' | 'date' | 'boolean' | 'select';
  selectOptions?: Array<{ label: string; value: any }>;
  template?: (row: any) => string;
}

@Component({
  selector: 'app-interactive-grid',
  standalone: true,
  imports: [
    CommonModule, FormsModule,
    TableModule, ButtonModule, InputTextModule, TooltipModule,
    DialogModule, AutoCompleteModule,
  ],
  template: `
    <div class="grid-container">
      <!-- TOOLBAR -->
      <div class="grid-toolbar">
        <div class="toolbar-left">
          <p-button icon="pi pi-th-large" [text]="true" severity="secondary"
            ariaLabel="Mostrar u ocultar columnas de la tabla"
            pTooltip="Mostrar/ocultar columnas"
            (onClick)="mostrarColumnChooser.set(true)" />
          <p-button icon="pi pi-download" [text]="true" severity="secondary"
            ariaLabel="Descargar datos como archivo CSV"
            pTooltip="Descargar CSV"
            (onClick)="exportToCSV()" />
          @if (filtrosActivos.size > 0) {
            <p-button icon="pi pi-filter-slash" [text]="true" severity="secondary"
              ariaLabel="Limpiar todos los filtros activos"
              pTooltip="Limpiar filtros"
              (onClick)="limpiarFiltros()" />
          }
        </div>
        <div class="toolbar-right">
          <span class="grid-count">{{ totalFilas() }} registro(s)</span>
        </div>
      </div>

      <!-- TABLA -->
      <p-table
        [value]="datosActuales"
        [loading]="loading"
        [columns]="columnasVisibles()"
        [paginator]="true"
        [rows]="20"
        [rowsPerPageOptions]="[10,20,50,100]"
        [sortMode]="'single'"
        styleClass="p-datatable-sm p-datatable-striped p-datatable-gridlines apex-grid">

        <!-- CABECERA -->
        <ng-template pTemplate="header" let-columns>
          <tr class="header-row">
            @for (col of columns; track col.field) {
              <th [pSortableColumn]="col.sortable !== false ? col.field : undefined"
                  [style.width]="col.width || 'auto'"
                  [class.sortable]="col.sortable !== false">
                <div class="col-header-inner">
                  <span class="col-title">{{ col.header }}</span>
                  @if (col.sortable !== false) {
                    <p-sortIcon [field]="col.field" />
                  }
                </div>
                @if (col.filterable !== false) {
                  <div class="col-filter" (click)="$event.stopPropagation()">
                    <p-autoComplete
                      [suggestions]="getFilterSuggestions(col.field)"
                      (completeMethod)="buscarSugerencias(col.field, $event.query)"
                      (onSelect)="onFilterSelect(col.field, $event.value)"
                      (onClear)="clearFilter(col.field)"
                      [(ngModel)]="filterModels[col.field]"
                      [dropdown]="true"
                      [minLength]="0"
                      placeholder="Filtrar..."
                      styleClass="filter-autocomplete"
                      [inputStyle]="{'font-size': '.78rem', 'padding': '.25rem .4rem', 'width': '100%'}"
                      (onKeyUp)="onFilterKeyUp(col.field, $any($event).target?.value ?? '')"
                    />
                  </div>
                }
              </th>
            }
            <th class="col-acciones"><strong>Acciones</strong></th>
          </tr>
        </ng-template>

        <!-- CUERPO -->
        <ng-template pTemplate="body" let-rowData let-columns="columns">
          <tr class="data-row" (click)="rowSelected.emit(rowData)" title="Clic para ver/editar">
            @for (col of columns; track col.field) {
              <td>{{ rowData[col.field] }}</td>
            }
            <td class="acciones-cell" (click)="$event.stopPropagation()">
              <p-button icon="pi pi-pencil" severity="secondary" [text]="true" size="small"
                ariaLabel="Editar este registro"
                pTooltip="Editar" tooltipPosition="top"
                (onClick)="rowSelected.emit(rowData)" />
              @if (showDelete) {
                <p-button icon="pi pi-trash" severity="danger" [text]="true" size="small"
                  ariaLabel="Eliminar este registro"
                  pTooltip="Eliminar" tooltipPosition="top"
                  (onClick)="rowDeleted.emit(rowData)" />
              }
            </td>
          </tr>
        </ng-template>

        <ng-template pTemplate="emptymessage" let-columns>
          <tr>
            <td [colSpan]="columns.length + 1" class="empty-msg">
              {{ loading ? 'Cargando...' : 'Sin registros' }}
            </td>
          </tr>
        </ng-template>
      </p-table>
    </div>

    <!-- COLUMN CHOOSER -->
    <p-dialog
      [visible]="mostrarColumnChooser()"
      (visibleChange)="mostrarColumnChooser.set($event)"
      header="Columnas visibles"
      [modal]="true"
      [style]="{width:'380px'}">
      <ul class="col-chooser-list">
        @for (col of columns; track col.field) {
          <li class="col-chooser-item">
            <input type="checkbox"
              [id]="'chk-' + col.field"
              [checked]="columnasVisibles().some(c => c.field === col.field)"
              (change)="toggleColumna(col.field)" />
            <label [for]="'chk-' + col.field">{{ col.header }}</label>
          </li>
        }
      </ul>
      <ng-template pTemplate="footer">
        <p-button label="Cerrar" icon="pi pi-check"
          ariaLabel="Cerrar el selector de columnas"
          (onClick)="mostrarColumnChooser.set(false)" />
      </ng-template>
    </p-dialog>
  `,
  styles: [`
    .grid-container { background: var(--surface-0); border-radius: 8px; padding: 0; overflow: hidden; }

    .grid-toolbar {
      display: flex; justify-content: space-between; align-items: center;
      padding: .4rem .75rem; border-bottom: 1px solid var(--surface-200);
      background: var(--surface-50);
    }
    .toolbar-left, .toolbar-right { display: flex; gap: .25rem; align-items: center; }
    .grid-count { font-size: .82rem; color: var(--text-color-secondary); }

    /* Cabecera */
    .header-row th { vertical-align: top; padding: .4rem .5rem !important; }
    .col-header-inner {
      display: flex; align-items: center; justify-content: space-between; gap: .25rem;
      margin-bottom: .3rem;
    }
    .col-title { font-size: .82rem; font-weight: 600; white-space: nowrap; }

    /* Filtro LOV */
    .col-filter { width: 100%; }
    :host ::ng-deep .filter-autocomplete { width: 100%; }
    :host ::ng-deep .filter-autocomplete .p-autocomplete-input { width: 100%; font-size: .78rem; }
    :host ::ng-deep .filter-autocomplete .p-autocomplete-dropdown { padding: .2rem .4rem; }

    /* Fila clickeable */
    .data-row { cursor: pointer; transition: background .1s; }
    .data-row:hover { background: var(--primary-50, #fef2f3) !important; }
    .data-row td { font-size: .87rem; }

    /* Acciones */
    .col-acciones { width: 90px; text-align: center; }
    .acciones-cell { text-align: center; white-space: nowrap; }

    /* Misc */
    .empty-msg { text-align: center; padding: 2rem; color: var(--text-color-secondary); }

    /* Column chooser */
    .col-chooser-list { list-style: none; margin: 0; padding: 0; display: flex; flex-direction: column; gap: .65rem; }
    .col-chooser-item { display: flex; align-items: center; gap: .5rem; cursor: pointer; }
    .col-chooser-item label { flex: 1; font-size: .9rem; cursor: pointer; }

    /* Override PrimeNG table spacing */
    :host ::ng-deep .apex-grid .p-datatable-thead > tr > th { padding: .4rem .5rem; }
    :host ::ng-deep .apex-grid .p-datatable-tbody > tr > td { padding: .45rem .5rem; }
  `],
})
export class InteractiveGridComponent implements OnChanges {
  @Input() data: any[] = [];
  @Input() columns: ColumnConfig[] = [];
  @Input() loading = false;
  @Input() showDelete = false;
  @Input() searchable = true;
  /** Labels impuestos por el contexto global — se muestran en el filtro de esas columnas. */
  @Input() externalFilters: Record<string, string> = {};
  /** LOV externo por columna (catálogo completo de la cascada) en vez del índice local. */
  @Input() externalSuggestions: Record<string, string[]> = {};
  /** Columnas filtradas por el servidor/contexto — NO se filtran client-side aquí. */
  @Input() serverFilteredFields: string[] = [];
  @Output() rowSelected = new EventEmitter<any>();
  @Output() rowDeleted  = new EventEmitter<any>();
  /** Camino grid → contexto: el usuario cambió el filtro de una columna de rol cascada. */
  @Output() filterChange = new EventEmitter<{ field: string; value: string | null }>();

  columnasVisibles = signal<ColumnConfig[]>([]);
  mostrarColumnChooser = signal(false);
  totalFilas = signal(0);

  filtrosActivos = new Map<string, string>();
  datosOriginales: any[] = [];
  datosActuales:   any[] = [];

  // LOV suggestions per column
  filterSuggestions: Record<string, string[]> = {};
  filterModels:      Record<string, string>   = {};

  // Índice precalculado de valores únicos por campo — se reconstruye en ngOnChanges
  private _suggestionsIndex: Record<string, string[]> = {};

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['columns']) {
      this.columnasVisibles.set(this.columns);
    }
    if (changes['data']) {
      this.datosOriginales = [...this.data];
      this.datosActuales   = [...this.data];
      this._rebuildSuggestionsIndex();
      this.aplicarFiltros();
    }
    if (changes['externalFilters']) {
      this._seedExternalFilters();
    }
  }

  /** Vuelca los labels del contexto en los modelos de filtro de sus columnas. */
  private _seedExternalFilters(): void {
    for (const field of Object.keys(this.externalFilters)) {
      const label = this.externalFilters[field] ?? '';
      this.filterModels[field] = label;
    }
  }

  private _isServerFiltered(field: string): boolean {
    return this.serverFilteredFields.includes(field);
  }

  // ── LOV filter ───────────────────────────────────────────────────────────────

  private _rebuildSuggestionsIndex(): void {
    this._suggestionsIndex = {};
    for (const col of this.columns) {
      this._suggestionsIndex[col.field] = [...new Set(
        this.datosOriginales.map(r => String(r[col.field] ?? '')).filter(Boolean)
      )].sort();
    }
  }

  getFilterSuggestions(field: string): string[] {
    return this.filterSuggestions[field] ?? [];
  }

  buscarSugerencias(field: string, query: string): void {
    // Columnas de rol cascada: LOV proviene del catálogo completo del contexto.
    const all = this.externalSuggestions[field] ?? this._suggestionsIndex[field] ?? [];
    const q = query.toLowerCase();
    this.filterSuggestions[field] = q
      ? all.filter(v => v.toLowerCase().includes(q))
      : all;
  }

  onFilterSelect(field: string, value: string): void {
    this.filterModels[field] = value;
    if (this._isServerFiltered(field)) {
      this.filterChange.emit({ field, value });
      return;
    }
    this.filtrosActivos.set(field, value.toLowerCase());
    this.aplicarFiltros();
  }

  onFilterKeyUp(field: string, value: string): void {
    if (this._isServerFiltered(field)) return; // estas columnas solo cambian vía LOV/clear
    if (value.trim()) {
      this.filtrosActivos.set(field, value.toLowerCase());
    } else {
      this.filtrosActivos.delete(field);
      this.filterModels[field] = '';
    }
    this.aplicarFiltros();
  }

  clearFilter(field: string): void {
    this.filterModels[field] = '';
    if (this._isServerFiltered(field)) {
      this.filterChange.emit({ field, value: null });
      return;
    }
    this.filtrosActivos.delete(field);
    this.aplicarFiltros();
  }

  limpiarFiltros(): void {
    this.filtrosActivos.clear();
    this.filterModels = {};
    this._seedExternalFilters(); // conserva el reflejo del contexto en columnas cascada
    this.datosActuales = [...this.datosOriginales];
    this.totalFilas.set(this.datosActuales.length);
  }

  // ── Sort / filter ─────────────────────────────────────────────────────────────

  private aplicarFiltros(): void {
    let res = [...this.datosOriginales];
    for (const [field, filtro] of this.filtrosActivos.entries()) {
      res = res.filter(r => String(r[field] ?? '').toLowerCase().includes(filtro));
    }
    this.datosActuales = res;
    this.totalFilas.set(res.length);
  }

  // ── Column chooser ────────────────────────────────────────────────────────────

  toggleColumna(field: string): void {
    const actual = this.columnasVisibles();
    const existe = actual.some(c => c.field === field);
    if (existe) {
      this.columnasVisibles.set(actual.filter(c => c.field !== field));
    } else {
      const col = this.columns.find(c => c.field === field);
      if (col) this.columnasVisibles.set([...actual, col]);
    }
  }

  // ── Export ────────────────────────────────────────────────────────────────────

  exportToCSV(): void {
    const cols = this.columnasVisibles();
    const headers = cols.map(c => c.header).join(',');
    const rows = this.datosActuales.map(r =>
      cols.map(c => `"${String(r[c.field] ?? '').replace(/"/g, '""')}"`).join(',')
    );
    const csv = [headers, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = `export-${new Date().toISOString().slice(0,10)}.csv`;
    a.click();
  }
}

